INSERT INTO flashcard
    (id, desk_id, word, cefr, pos_json, all_levels_json, ipa, audio_url,
     definition, example, topic, vietnamese, vi_definition, vi_example)
VALUES
    ('7ea83347-b30b-54c3-8107-90a48d202a78', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'absolute', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈæb.səˌljuːt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/absolute-uk.mp3', 'That which is independent of context-dependent interpretation, inviolate, fundamental.', 'moral absolutes', 'Society & Culture', 'tuyệt đối', 'Điều độc lập với cách diễn giải phụ thuộc ngữ cảnh, không thể xâm phạm, cơ bản.', 'những giá trị tuyệt đối về đạo đức'),
    ('7446e6d5-15e9-511a-b25d-4f8041aed00b', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'acceptable', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/æk.ˈsɛp.tə.bəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/acceptable-us.mp3', 'Worthy, decent, sure of being accepted or received with at least moderate pleasure', 'We need to find an acceptable present for Jeff.', 'Society & Culture', 'có thể chấp nhận', 'Đáng giá, tử tế, chắc chắn được chấp nhận hoặc nhận được với ít nhất niềm vui vừa phải', 'Chúng ta cần tìm một món quà có thể chấp nhận được cho Jeff.'),
    ('705119fd-50f4-5588-9047-f7cec2e11add', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'affair', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/əˈfɛə/', 'audio/affair.mp3', '(often in the plural) Something which is done or is to be done; business of any kind, commercial, professional, or public.', 'a difficult affair to manage', 'Society & Culture', 'việc, sự việc', '(thường ở số nhiều) Điều gì đó được làm hoặc sẽ được làm; công việc thuộc bất kỳ loại nào, thương mại, chuyên nghiệp, hoặc công cộng.', 'một việc khó quản lý'),
    ('25126fa8-963b-5eb4-920e-7a9d3809a885', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'anniversary', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˌænɪˈvɜːs(ə)ɹi/', 'https://api.dictionaryapi.dev/media/pronunciations/en/anniversary-uk.mp3', 'A day that is an exact number of years (to the day) since a given significant event occurred. Often preceded by an ordinal number indicating the number of years.', 'Today is the fiftieth anniversary of the end of the war.', 'Society & Culture', 'ngày kỷ niệm', 'Một ngày chính xác bằng số năm (tính theo ngày) kể từ khi một sự kiện quan trọng xảy ra. Thường được đứng trước bởi một số thứ tự chỉ số năm.', 'Hôm nay là kỷ niệm năm mươi năm ngày kết thúc chiến tranh.'),
    ('f51d9df2-2ff8-5115-b930-f6409a2dc227', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'beg', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/bɛɡ/', 'audio/beg.mp3', 'The act of begging; an imploring request.', 'He begged on the street corner from passers-by.', 'Society & Culture', 'ăn xin', 'Hành động ăn xin; một lời cầu xin khẩn thiết.', 'Anh ta ăn xin ở góc phố từ những người qua đường.'),
    ('e33df6ab-a909-5c26-91ef-fbb53fbd76bf', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'citizen', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈsɪtɪzən/', 'audio/citizen.mp3', 'A resident of a city or town, especially one with legally-recognized rights or duties.', 'Diogenes reckoned himself a citizen of the world.', 'Society & Culture', 'công dân', 'Một cư dân của một thành phố hoặc thị trấn, đặc biệt là người có quyền hoặc nghĩa vụ được công nhận hợp pháp.', 'Diogenes coi mình là một công dân của thế giới.'),
    ('e35425c8-feeb-5915-b8e6-1caea773da97', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'conflict', 'B2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "v", "level": "B2"}]'::jsonb, '/kənˈflɪkt/', 'audio/conflict.mp3', 'A clash or disagreement, often violent, between two or more opposing groups or individuals.', 'The conflict between the government and the rebels began three years ago.', 'Society & Culture', 'xung đột', 'Một sự va chạm hoặc bất đồng, thường là bạo lực, giữa hai hoặc nhiều nhóm hoặc cá nhân đối lập.', 'Xung đột giữa chính phủ và phiến quân bắt đầu từ ba năm trước.'),
    ('42723ce4-fb84-5b12-8715-33ebe0b61258', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'contemporary', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/kənˈtɛm.p(ə).ɹi/', 'audio/contemporary.mp3', 'Someone or something living at the same time, or of roughly the same age as another.', 'Cervantes was a contemporary of Shakespeare.', 'Society & Culture', 'đương thời', 'Ai đó hoặc thứ gì đó sống cùng thời, hoặc có độ tuổi tương đương với người khác.', 'Cervantes là người đương thời với Shakespeare.'),
    ('b1b03065-c30a-52df-8347-6e7492313f7d', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'contribute', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/kənˈt(ʃ)ɹɪb.juːt/', 'audio/contribute.mp3', 'To give something that is or becomes part of a larger whole.', 'to contribute articles to a journal', 'Society & Culture', 'đóng góp', 'Cho đi thứ gì đó là hoặc trở thành một phần của tổng thể lớn hơn.', 'đóng góp bài viết cho một tạp chí'),
    ('93e8ba07-f9d2-5b1e-9d9a-152af7c5246d', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'convert', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/ˈkɒn.vəːt/', 'audio/convert.mp3', 'A person who has converted to a religion.', 'They were all converts to Islam.', 'Society & Culture', 'cải đạo', 'Một người đã cải sang một tôn giáo.', 'Tất cả họ đều là những người cải đạo sang Hồi giáo.'),
    ('9bad5aa2-f230-5a6b-b0c4-299a144d7bf5', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'county', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈkaʊnti/', 'audio/county.mp3', 'The land ruled by a count or a countess.', 'He can''t come; he''s up in the county for agg assault.', 'Society & Culture', 'hạt', 'Vùng đất được cai quản bởi một bá tước hoặc nữ bá tước.', 'Anh ấy không thể đến; anh ấy đang ở trên hạt vì tội hành hung.'),
