    ('0066b216-2f36-58dc-9405-8ec35a092e86', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'dominate', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/ˈdɒməˌneɪt/', 'audio/dominate.mp3', 'Ruling; governing; prevailing', 'The dominant party controlled the government.', 'Society & Culture', 'thống trị', 'Cai trị; chi phối; chiếm ưu thế', 'Đảng chiếm ưu thế đã kiểm soát chính phủ.'),
    ('423e50ea-88ba-5f42-aa81-473c2271390c', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'ethical', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈɛθɪkəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/ethical-us.mp3', 'An ethical drug, one only dispensed on the prescription of a physician.', 'The philosopher Kant is particularly known for his ethical writings.', 'Society & Culture', 'đạo đức', 'Một loại thuốc đạo đức, chỉ được cấp phát theo đơn của bác sĩ.', 'Triết gia Kant đặc biệt nổi tiếng với các tác phẩm đạo đức của ông.'),
    ('3b4bddbd-b2ac-5a10-be42-fae0b3a037fb', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'fault', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/fɒlt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/fault-uk.mp3', 'A defect; something that detracts from perfection.', 'No! This is my fault, not yours.', 'Society & Culture', 'lỗi, sai sót', 'Một khuyết điểm; điều gì đó làm giảm sự hoàn hảo.', 'Không! Đây là lỗi của tôi, không phải của bạn.'),
    ('6ebbd027-c5bb-5b68-8f26-ee9a8d57ea68', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'freedom', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈfɹiːdəm/', 'https://api.dictionaryapi.dev/media/pronunciations/en/freedom-uk.mp3', 'The state of being free, of not being imprisoned or enslaved.', 'Having recently been released from prison, he didn''t know what to do with his newfound freedom.', 'Society & Culture', 'tự do', 'Trạng thái tự do, không bị giam cầm hoặc nô lệ.', 'Vừa mới được ra tù, anh ấy không biết phải làm gì với sự tự do mới tìm thấy của mình.'),
    ('32c6274e-0347-5987-804c-83ee566aef7e', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'holy', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈhəʊli/', 'audio/holy.mp3', 'A thing that is extremely holy; used almost exclusively in Holy of Holies.', 'I''m planning to visit the holy city of Jerusalem this Christmas.', 'Society & Culture', 'linh thiêng', 'Một thứ cực kỳ linh thiêng; được sử dụng hầu như độc quyền trong Nơi Chí Thánh.', 'Tôi đang lên kế hoạch thăm thành phố linh thiêng Jerusalem vào Giáng sinh này.'),
    ('937ad683-e618-540a-9c0a-b5e3405eefce', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'honour', 'B2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "v", "level": "B2"}]'::jsonb, '/ˈɒnə(ɹ)/', 'https://api.dictionaryapi.dev/media/pronunciations/en/honour-uk.mp3', 'Recognition of importance or value; respect; veneration (of someone, usually for being morally upright or successful)', 'The crowds gave the returning general much honor and praise.', 'Society & Culture', 'danh dự', 'Sự công nhận tầm quan trọng hoặc giá trị; sự tôn trọng; sự tôn kính (của ai đó, thường vì đạo đức ngay thẳng hoặc thành công).', 'Đám đông đã dành nhiều danh dự và lời khen ngợi cho vị tướng trở về.'),
    ('dde74925-fd0f-5cc6-b9f9-a3b644e9b0e5', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'incident', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈɪn.sɪ.dənt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/incident-us.mp3', 'An event or occurrence.', 'It was an incident that he hoped to forget.', 'Society & Culture', 'sự việc', 'Một sự kiện hoặc sự xảy ra.', 'Đó là một sự việc mà anh ấy hy vọng sẽ quên đi.'),
    ('9526d8d9-2952-504c-94ae-98cba1c88999', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'institution', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˌɪnstɪˈtjuːʃən/', 'audio/institution.mp3', 'A custom or practice of a society or community.', 'He''s been in an institution since the crash.', 'Society & Culture', 'tổ chức', 'Một phong tục hoặc thông lệ của một xã hội hoặc cộng đồng.', 'Anh ấy đã ở trong một tổ chức từ sau vụ tai nạn.'),
    ('54d83078-1276-5a3b-9c75-bfaf1aaf865d', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'majority', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/məˈd͡ʒɒɹɪti/', 'audio/majority.mp3', 'More than half (50%) of some group.', 'The majority agreed that the new proposal was the best.', 'Society & Culture', 'đa số', 'Hơn một nửa (50%) của một nhóm nào đó.', 'Đa số đồng ý rằng đề xuất mới là tốt nhất.'),
    ('0034636a-2c8d-53db-81f3-07c7c5e5458a', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'minority', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/maɪˈnɒɹ.ɪ.ti/', 'audio/minority.mp3', 'The state of being a minor; youth, the period of a person''s life prior to reaching adulthood.', 'Most people agreed, but a sizable minority were upset by the decision.', 'Society & Culture', 'thiểu số', 'Tình trạng là một người vị thành niên; tuổi trẻ, giai đoạn cuộc đời trước khi trưởng thành.', 'Hầu hết mọi người đồng ý, nhưng một nhóm thiểu số đáng kể đã khó chịu với quyết định đó.'),
    ('dd7dd3a1-7d14-523c-9ad4-d5d2572c7238', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'moral', 'B2', '["adj", "n"]'::jsonb, '[{"pos": "adj", "level": "B2"}, {"pos": "n", "level": "B2"}]'::jsonb, '/ˈmɒɹəl/', 'audio/moral.mp3', '(of a narrative) The ethical significance or practical lesson.', 'a candidate with strong morals', 'Society & Culture', 'đạo đức, bài học', '(của một câu chuyện) Ý nghĩa đạo đức hoặc bài học thực tiễn.', 'một ứng viên có đạo đức mạnh mẽ'),
    ('0d8a0604-4f93-5483-a4f5-6e86dee10f18', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'participant', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/pɑːˈtɪsɪpənt/', 'audio/participant.mp3', 'One who participates.', 'All participants must adhere to the rules of the competition.', 'Society & Culture', 'người tham gia', 'Người tham gia.', 'Tất cả người tham gia phải tuân thủ các quy tắc của cuộc thi.'),
    ('69bc1884-e5b5-5fc8-a50e-28c2466906bf', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'popularity', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˌpɒp.jəˈlæɹ.ɪ.ti/', 'https://api.dictionaryapi.dev/media/pronunciations/en/popularity-us.mp3', 'The quality or state of being popular; especially, the state of being esteemed by, or of being in favor with, the people at large', 'Politicians are rarely known for their popularity.', 'Society & Culture', 'sự nổi tiếng', 'Chất lượng hoặc trạng thái được ưa chuộng; đặc biệt, trạng thái được quần chúng đánh giá cao hoặc ủng hộ.', 'Các chính trị gia hiếm khi được biết đến vì sự nổi tiếng của họ.'),
    ('270f33dd-afeb-5f57-9a89-a057a3247ac9', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'preserve', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/pɹəˈzɜːv/', 'audio/preserve.mp3', 'A sweet spread made of any of a variety of fruits.', 'Every people have the right to preserve its identity and culture.', 'Society & Culture', 'bảo tồn', 'Một loại mứt ngọt làm từ nhiều loại trái cây.', 'Mọi dân tộc đều có quyền bảo tồn bản sắc và văn hóa của mình.'),
    ('87511ca0-ccbf-5d1d-aa6c-901bc1cefb6b', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'privacy', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈpɹaɪv.ə.sɪ/', 'audio/privacy.mp3', 'The state of being secluded from the presence, sight, or knowledge of others.', 'I need my privacy, so please stay out of my room.', 'Society & Culture', 'sự riêng tư', 'Trạng thái được cách ly khỏi sự hiện diện, tầm nhìn hoặc kiến thức của người khác.', 'Tôi cần sự riêng tư, vì vậy hãy ở ngoài phòng tôi.'),
    ('cb6970ff-bf6a-536c-9baa-0b39b70110e1', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'reward', 'B2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "v", "level": "B2"}]'::jsonb, '/ɹəˈwɔːd/', 'audio/reward.mp3', 'Something of value given in return for an act.', 'For catching the thief, you''ll get a nice reward.', 'Society & Culture', 'phần thưởng', 'Thứ có giá trị được trao để đổi lấy một hành động.', 'Để bắt được tên trộm, bạn sẽ nhận được một phần thưởng tốt đẹp.'),
    ('59094e94-c7ad-5e2e-a5e9-5c9d9f743b9d', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'senior', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈsiːnjə(r)/', 'audio/senior.mp3', 'An old person.', 'He was four years her senior.', 'Society & Culture', 'cao cấp', 'Một người già.', 'Anh ấy hơn cô ấy bốn tuổi.'),
    ('d969ee5d-83f1-52bc-a7b7-c346a271ed11', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'slave', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/sleɪv/', 'https://api.dictionaryapi.dev/media/pronunciations/en/slave-us.mp3', 'A person who is held in servitude as the property of another person, and whose labor (and often also whose body and life) is subject to the owner''s volition and control.', 'a slave to passion, to strong drink, or to ambition', 'Society & Culture', 'nô lệ', 'Một người bị giữ trong cảnh nô lệ như tài sản của người khác, và lao động của họ (và thường cả cơ thể và cuộc sống của họ) phụ thuộc vào ý chí và sự kiểm soát của chủ sở hữu.', 'nô lệ cho đam mê, cho rượu mạnh, hoặc cho tham vọng'),
    ('9f45a69c-56e5-5e8c-8e65-609b138d7f6f', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'soul', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/səʊl/', 'audio/soul.mp3', 'The spirit or essence of a person usually thought to consist of one''s thoughts and personality. Often believed to live on after the person''s death.', 'Fifty souls were lost when the ship sank.', 'Society & Culture', 'linh hồn', 'Tinh thần hoặc bản chất của một người, thường được cho là bao gồm suy nghĩ và tính cách của người đó. Thường được tin là sẽ sống tiếp sau khi người đó chết.', 'Năm mươi sinh mạng đã mất khi con tàu chìm.'),
    ('799f40ff-e667-56ec-8224-1ab874d93eeb', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'spiritual', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈspɪɹɪtjʊəl/', 'audio/spiritual.mp3', 'A Christian religious song, especially one in an African-American style, or a similar non-religious song.', 'He assigns supremacy to the pope in spirituals, and to the emperor in temporals. — Lowell.', 'Society & Culture', 'tâm linh', 'Một bài hát tôn giáo của Cơ đốc giáo, đặc biệt là theo phong cách người Mỹ gốc Phi, hoặc một bài hát tương tự không mang tính tôn giáo.', 'Ông ấy giao quyền tối cao cho giáo hoàng trong các vấn đề tâm linh, và cho hoàng đế trong các vấn đề thế tục. — Lowell.'),
    ('965e58ab-6a41-5ee2-9feb-81b330cd3a4f', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'status', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈstæt.əs/', 'audio/status.mp3', 'A person’s condition, position or standing relative to that of others.', 'Superstition is highly correlated with economic status.', 'Society & Culture', 'địa vị', 'Điều kiện, vị trí hoặc địa vị của một người so với người khác.', 'Mê tín dị đoan có tương quan cao với địa vị kinh tế.'),
    ('73416e3b-4c5b-5a6e-84b6-af727977ad53', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'stiff', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/stɪf/', 'https://api.dictionaryapi.dev/media/pronunciations/en/stiff-us.mp3', 'An average person, usually male, of no particular distinction, skill, or education, often a working stiff or lucky stiff.', 'A Working Stiff''s Manifesto: A Memoir of Thirty Jobs I Quit, Nine That Fired Me, and Three I Can''t Remember was published in 2003.', 'Society & Culture', 'người bình thường', 'Một người bình thường, thường là nam, không có sự khác biệt, kỹ năng hoặc học vấn đặc biệt nào, thường là một người lao động bình thường hoặc một kẻ may mắn.', '''Tuyên ngôn của một người lao động bình thường: Hồi ký về ba mươi công việc tôi bỏ, chín việc sa thải tôi và ba việc tôi không thể nhớ'' được xuất bản năm 2003.'),
    ('c1ab9e55-204b-55e8-bbce-4cf8692e9636', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'struggle', 'B2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B2"}, {"pos": "n", "level": "B2"}]'::jsonb, '/ˈstrʌɡəl/', 'audio/struggle.mp3', 'A contortion of the body in an attempt to escape or to perform a difficult task.', 'During the centuries, the people of Ireland struggled constantly to assert their right to govern themselves.', 'Society & Culture', 'đấu tranh', 'Một sự vặn vẹo của cơ thể trong nỗ lực trốn thoát hoặc thực hiện một nhiệm vụ khó khăn.', 'Qua nhiều thế kỷ, người dân Ireland liên tục đấu tranh để khẳng định quyền tự quản của họ.'),
    ('8ef4c505-df55-5240-a66a-7989dc33d96f', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'transition', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/tɹænˈzɪʃən/', 'audio/transition.mp3', 'The process of change from one form, state, style or place to another.', 'The soldier was transitioned from a combat role to a strategic role.', 'Society & Culture', 'chuyển tiếp, quá độ', 'Quá trình thay đổi từ một hình thức, trạng thái, phong cách hoặc địa điểm này sang một cái khác.', 'Người lính đã được chuyển đổi từ vai trò chiến đấu sang vai trò chiến lược.'),
    ('80b8f285-506f-5b32-ba88-c289dd62991b', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'violence', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈvaɪləns/', 'https://api.dictionaryapi.dev/media/pronunciations/en/violence-us.mp3', 'Extreme force.', 'The violence of the storm, fortunately, was more awesome than destructive.', 'Society & Culture', 'bạo lực', 'Lực lượng cực đoan.', 'May mắn thay, sức mạnh của cơn bão đáng kinh ngạc hơn là phá hủy.'),
    ('a0e4839d-746f-566d-aa61-b2784fa21621', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'alien', 'B2', '["n", "adj"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "adj", "level": "C1"}]'::jsonb, '/ˈeɪ.li.ən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/alien-us.mp3', 'Any life form of extraterrestrial or extradimensional origin.', 'alien subjects, enemies, property, or shores', 'Society & Culture', 'người ngoài hành tinh', 'Bất kỳ dạng sống có nguồn gốc ngoài Trái đất hoặc ngoại chiều.', 'chủ thể, kẻ thù, tài sản, hoặc bờ biển nước ngoài'),
    ('03657d46-6a20-51cf-a725-80c4cc6fd7d4', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'badge', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/bædʒ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/badge-uk.mp3', 'A distinctive mark, token, sign, emblem or cognizance, worn on one''s clothing, as an insignia of some rank, or of the membership of an organization.', 'the badge of a society; the badge of a policeman', 'Society & Culture', 'huy hiệu', 'Dấu hiệu, biểu tượng, ký hiệu hoặc phù hiệu đặc biệt, đeo trên quần áo, như một dấu hiệu của cấp bậc nào đó, hoặc của thành viên trong một tổ chức.', 'huy hiệu của một hội; huy hiệu của cảnh sát'),
    ('b5fb614c-eb5a-5ea0-91e4-365c0b56b32a', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'civilization', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '[ˌsɪv.ə.lɑeˈzæɪ.ʃən]', 'audio/civilization.mp3', 'An organized culture encompassing many communities, often on the scale of a nation or a people; a stage or system of social, political or technical development.', 'Modern civilization is a product of industrialization and globalization.', 'Society & Culture', 'nền văn minh', 'Một nền văn hóa có tổ chức bao trùm nhiều cộng đồng, thường ở quy mô một quốc gia hoặc một dân tộc; một giai đoạn hoặc hệ thống phát triển xã hội, chính trị hoặc kỹ thuật.', 'Nền văn minh hiện đại là sản phẩm của công nghiệp hóa và toàn cầu hóa.'),
    ('f0b35bf7-3ac1-5609-b8ed-58d78876312a', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'colony', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈkɒl.əni/', 'audio/colony.mp3', 'A governmental unit created on land of another country owned by colonists from a country.', 'Bermuda is a crown colony of Great Britain.', 'Society & Culture', 'thuộc địa', 'Một đơn vị hành chính được tạo ra trên đất của một quốc gia khác thuộc sở hữu của những người thực dân từ một quốc gia.', 'Bermuda là một thuộc địa hoàng gia của Anh Quốc.'),
    ('21da301d-578c-5f1d-8473-079420007550', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'convention', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/kənˈvɛn.ʃən/', 'audio/convention.mp3', 'A meeting or gathering.', 'The convention was held in Geneva.', 'Society & Culture', 'hội nghị, quy ước', 'Một cuộc họp hoặc tụ họp.', 'Hội nghị được tổ chức tại Geneva.'),
    ('e581c111-4ef9-54fa-b953-f6c4db2378a3', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'conventional', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/kənˈvɛnʃənl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/conventional-us.mp3', 'A conventional gilt-edged security, a kind of bond paying the holder a fixed cash payment (or coupon) every six months until maturity, at which point the holder receives the final payment and the return of the principal.', 'They wear conventional clothes, eat conventional food, and keep conventional hours.', 'Society & Culture', 'thông thường, truyền thống', 'Một chứng khoán viền vàng thông thường, một loại trái phiếu trả cho người nắm giữ một khoản thanh toán tiền mặt cố định (hoặc phiếu lãi) mỗi sáu tháng cho đến khi đáo hạn, tại thời điểm đó người nắm giữ nhận được khoản thanh toán cuối cùng và lợi nhuận.', 'Họ mặc quần áo thông thường, ăn thức ăn thông thường và giữ giờ giấc thông thường.'),
    ('88e453bf-0b84-5eb2-af52-be8a2cc888e2', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'destruction', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˌdɪsˈtɹʌkʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/destruction-us.mp3', 'The act of destroying.', 'The destruction of the condemned building will take place at noon.', 'Society & Culture', 'sự phá hủy', 'Hành động phá hủy.', 'Việc phá hủy tòa nhà bị lên án sẽ diễn ra vào buổi trưa.'),
    ('50c02735-70d6-55cf-bbf9-126f165c0122', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'disagreement', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/dɪsəˈɡɹiːmənt/', 'audio/disagreement.mp3', 'An argument or debate.', 'They had a bit of a disagreement about what color to paint the bedroom, but they have reached a compromise.', 'Society & Culture', 'sự bất đồng', 'Một cuộc tranh luận hoặc tranh cãi.', 'Họ đã có một chút bất đồng về việc sơn phòng ngủ màu gì, nhưng họ đã đạt được thỏa hiệp.'),
    ('d214ccc1-b5b4-5351-b6bc-0085048ddbb8', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'disturb', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/dɪsˈtɜːb/', 'audio/disturb.mp3', 'Disturbance', 'A school of fish disturbed the water.', 'Society & Culture', 'làm phiền, quấy rầy', 'Sự quấy rầy', 'Một đàn cá làm xáo động mặt nước.'),
    ('f8783fad-33b0-55d0-aa74-7550670911b1', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'diverse', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/daɪˈvɜːs/', 'audio/diverse.mp3', 'Consisting of many different elements; various.', 'Idris Elba was a diverse hire for the franchise', 'Society & Culture', 'đa dạng', 'Bao gồm nhiều yếu tố khác nhau; đa dạng.', 'Idris Elba là một tuyển dụng đa dạng cho nhượng quyền thương mại'),
    ('e2ba0e7e-4d06-5d6a-80f5-93217bf9b9c4', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'dominant', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈdɒmɪnənt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/dominant-uk.mp3', 'The fifth major tone of a musical scale (five major steps above the note in question); thus G is the dominant of C, A of D, and so on.', 'The dominant party controlled the government.', 'Society & Culture', 'thống trị, trội', 'Nốt chính thứ năm của một âm giai (năm bước chính trên nốt được đề cập); do đó G là âm át của C, A của D, v.v.', 'Đảng thống trị kiểm soát chính phủ.'),
    ('8db81f39-b76d-54ba-87e0-affd34d48066', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'donation', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/dəʊˈneɪʃən/', 'audio/donation.mp3', 'A voluntary gift or contribution for a specific cause.', 'They were collecting donations for the elderly at Christmas.', 'Society & Culture', 'sự quyên góp', 'Một món quà hoặc đóng góp tự nguyện cho một mục đích cụ thể.', 'Họ đang quyên góp cho người già vào Giáng sinh.'),
    ('96fe571c-9a9a-52a3-b4a9-c5aa338c1f19', 'b7e00f04-6746-5930-9092-7c16152cb9c1', 'dynamic', 'B2', '["adj", "n"]'::jsonb, '[{"pos": "adj", "level": "B2"}, {"pos": "n", "level": "C1"}]'::jsonb, '/daɪˈnæ.mɪk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/dynamic-au.mp3', 'A characteristic or manner of an interaction; a behavior.', 'Watch the dynamic between the husband and wife when they disagree.', 'Society & Culture', 'năng động', 'Một đặc điểm hoặc cách thức tương tác; một hành vi.', 'Hãy quan sát sự tương tác giữa vợ và chồng khi họ bất đồng.')
ON CONFLICT (desk_id, word) DO NOTHING;

