INSERT INTO flashcard
    (id, desk_id, word, cefr, pos_json, all_levels_json, ipa, audio_url,
     definition, example, topic, vietnamese, vi_definition, vi_example)
VALUES
    ('7cc02e3b-3222-5e59-839d-c4cdf251758b', '8a257431-b668-5df8-84f3-49d544fbf6eb', 'acquire', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/əˈkwaɪə/', 'audio/acquire.mp3', 'To get.', 'He acquired a title.', 'Business & Economy', 'thu được', 'Nhận được.', 'Ông ấy đã thu được một danh hiệu.'),
    ('f74749c1-9792-5db4-b5f4-48e9c7b050ff', '8a257431-b668-5df8-84f3-49d544fbf6eb', 'approval', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/əˈpɹuːvəl/', 'audio/approval.mp3', 'An expression granting permission; an indication of agreement with a proposal; an acknowledgement that a person, thing or event meets requirements.', 'I need to get an approval on this purchase order.', 'Business & Economy', 'sự chấp thuận', 'Một biểu hiện cho phép; một dấu hiệu đồng ý với một đề xuất; một sự thừa nhận rằng một người, sự vật hoặc sự kiện đáp ứng các yêu cầu.', 'Tôi cần được chấp thuận đơn đặt hàng này.'),
    ('89f0321d-742e-5c5e-95dd-90670e78e568', '8a257431-b668-5df8-84f3-49d544fbf6eb', 'approve', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/əˈpɹuːv/', 'https://api.dictionaryapi.dev/media/pronunciations/en/approve-uk.mp3', 'To sanction officially; to ratify; to confirm; to set as satisfactory.', 'Although we may disagree with it, we must nevertheless approve the sentence handed down by the court-martial.', 'Business & Economy', 'phê duyệt', 'Chính thức phê chuẩn; phê chuẩn; xác nhận; đặt là hài lòng.', 'Mặc dù chúng ta có thể không đồng ý, nhưng chúng ta vẫn phải phê duyệt bản án do tòa án quân sự đưa ra.'),
    ('eb53d746-6532-5856-b192-9121ffb8a3ca', '8a257431-b668-5df8-84f3-49d544fbf6eb', 'bond', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/bɒnd/', 'audio/bond.mp3', 'Evidence of a long-term debt, by which the bond issuer (the borrower) is obliged to pay interest when due, and repay the principal at maturity, as specified on the face of the bond certificate. The rights of the holder are specified in the bond indenture, which contains the legal terms and conditions under which the bond was issued. Bonds are available in two forms: registered bonds, and bearer bonds.', 'Investors face a quandary. Cash offers a return of virtually zero in many developed countries; government-bond yields may have risen in recent weeks but they are still unattractive. Equities have suffered two big bear markets since 2000 and are wobbling again. It is hardly surprising that pension funds, insurers and endowments are searching for new sources of return.', 'Business & Economy', 'trái phiếu', 'Bằng chứng về một khoản nợ dài hạn, theo đó tổ chức phát hành trái phiếu (người vay) có nghĩa vụ trả lãi khi đến hạn và hoàn trả số tiền gốc khi đáo hạn, như được quy định trên mặt chứng chỉ trái phiếu. Các quyền...', 'Các nhà đầu tư đối mặt với một tình thế khó xử. Tiền mặt mang lại lợi nhuận gần như bằng không ở nhiều nước phát triển; lợi suất trái phiếu chính phủ có thể đã tăng trong những tuần gần đây nhưng chúng vẫn không hấp dẫn. Cổ phiếu đã chịu...'),
    ('2f720a75-2e6c-5f82-acfe-1f417afcf9b2', '8a257431-b668-5df8-84f3-49d544fbf6eb', 'budget', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈbʌdʒ.ɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/budget-us.mp3', 'The amount of money or resources earmarked for a particular institution, activity or time-frame.', 'Budgeting is even harder in times of recession', 'Business & Economy', 'ngân sách', 'Số tiền hoặc nguồn lực được dành riêng cho một tổ chức, hoạt động hoặc khung thời gian cụ thể.', 'Lập ngân sách thậm chí còn khó hơn trong thời kỳ suy thoái'),
    ('af8392a5-5758-5293-aa8e-10304dd5c238', '8a257431-b668-5df8-84f3-49d544fbf6eb', 'cancel', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/ˈkænsl̩/', 'https://api.dictionaryapi.dev/media/pronunciations/en/cancel-au.mp3', 'A cancellation (US); (nonstandard in some kinds of English).', 'He cancelled his order on their website.', 'Business & Economy', 'hủy', 'Sự hủy bỏ (Mỹ); (không chuẩn trong một số loại tiếng Anh).', 'Anh ấy đã hủy đơn hàng trên trang web của họ.'),
    ('aa1fb848-db89-51cf-9908-ff50d5ff9f48', '8a257431-b668-5df8-84f3-49d544fbf6eb', 'commission', 'B2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "v", "level": "B2"}]'::jsonb, '/kəˈmɪʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/commission.mp3', 'A sending or mission (to do or accomplish something).', 'David received his commission after graduating from West Point.', 'Business & Economy', 'ủy ban', 'Một sự phái đi hoặc sứ mệnh (để làm hoặc hoàn thành điều gì đó).', 'David nhận được ủy nhiệm của mình sau khi tốt nghiệp từ West Point.'),
    ('b6708a1c-4ada-561f-9257-43516a9f3ef5', '8a257431-b668-5df8-84f3-49d544fbf6eb', 'corporate', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈkɔːp(ə)ɹət/', 'https://api.dictionaryapi.dev/media/pronunciations/en/corporate-uk.mp3', 'A bond issued by a corporation.', 'McDonald''s corporate issued a new policy today.', 'Business & Economy', 'thuộc công ty', 'Trái phiếu do một tập đoàn phát hành.', 'Tập đoàn McDonald''s đã ban hành một chính sách mới ngày hôm nay.'),
    ('a397c9df-4b3d-5bce-a857-5e6afcda4e4a', '8a257431-b668-5df8-84f3-49d544fbf6eb', 'crucial', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈkɹuː.ʃəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/crucial-au.mp3', 'Essential or decisive for determining the outcome or future of something; extremely important.', 'A secure supply of crude oil is crucial for any modern nation, let alone a superpower.', 'Business & Economy', 'quan trọng', 'Thiết yếu hoặc quyết định để xác định kết quả hoặc tương lai của điều gì đó; cực kỳ quan trọng.', 'Nguồn cung dầu thô an toàn là rất quan trọng đối với bất kỳ quốc gia hiện đại nào, chứ đừng nói đến một siêu cường.'),
    ('1ee4dba2-57ac-5ad8-89cc-c5be51a6eae4', '8a257431-b668-5df8-84f3-49d544fbf6eb', 'decline', 'B2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B2"}, {"pos": "n", "level": "B2"}]'::jsonb, '/dɪˈklaɪn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/decline-us.mp3', 'Downward movement, fall.', 'The dollar has declined rapidly since 2001.', 'Business & Economy', 'suy giảm', 'Chuyển động đi xuống, sự sụt giảm.', 'Đồng đô la đã suy giảm nhanh chóng kể từ năm 2001.'),
    ('f12445dc-6570-5453-af35-3bc704209083', '8a257431-b668-5df8-84f3-49d544fbf6eb', 'demand', 'B2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "v", "level": "B2"}]'::jsonb, '/dɪˈmɑːnd/', 'audio/demand.mp3', 'The desire to purchase goods and services.', 'Prices usually go up when demand exceeds supply.', 'Business & Economy', 'nhu cầu', 'Mong muốn mua hàng hóa và dịch vụ.', 'Giá cả thường tăng khi nhu cầu vượt quá cung cấp.'),
    ('fab75bad-0d58-5dbc-9a6f-69379263b83a', '8a257431-b668-5df8-84f3-49d544fbf6eb', 'distribute', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/dɨˈstɹɪbjuːt/', 'audio/distribute.mp3', 'To divide into portions and dispense.', 'He distributed the bread amongst his followers.', 'Business & Economy', 'phân phối', 'Chia thành các phần và phân phát.', 'Ông ấy phân phát bánh mì cho những người theo ông.'),
