    (id, desk_id, word, cefr, pos_json, all_levels_json, ipa, audio_url,
     definition, example, topic, vietnamese, vi_definition, vi_example)
VALUES
    ('77c2c86b-3985-5ba6-b930-4de8cc5317e9', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'apparently', 'B2', '["adv"]'::jsonb, '[{"pos": "adv", "level": "B2"}]'::jsonb, '/əˈpaɹəntli/', 'audio/apparently.mp3', 'Plainly; clearly; manifestly; evidently.', 'A man may be apparently friendly, yet malicious in heart.', 'Appearance & Description', 'rõ ràng là', 'Một cách rõ ràng; hiển nhiên.', 'Một người có vẻ bề ngoài thân thiện, nhưng trong lòng lại độc ác.'),
    ('ab154b8f-e5a4-5916-849e-562dbed29f0b', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'arise', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/əˈɹaɪz/', 'https://api.dictionaryapi.dev/media/pronunciations/en/arise-us.mp3', 'To come up from a lower to a higher position.', 'to arise from a kneeling posture', 'Appearance & Description', 'phát sinh', 'Đi lên từ vị trí thấp hơn đến vị trí cao hơn.', 'đứng dậy từ tư thế quỳ'),
    ('837b6434-b6b4-5e2c-acf6-5081c46bb756', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'bent', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/bɛnt/', 'audio/bent.mp3', 'To cause (something) to change its shape into a curve, by physical force, chemical action, or any other means.', 'Don’t bend your knees.', 'Appearance & Description', 'cong', 'Làm cho (thứ gì đó) thay đổi hình dạng thành một đường cong, bằng lực vật lý, tác động hóa học, hoặc bất kỳ phương tiện nào khác.', 'Đừng cong đầu gối của bạn.'),
    ('2c49ec57-3d7a-597b-b100-4e5110bf32fb', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'broad', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/bɹɑd/', 'audio/broad.mp3', 'A shallow lake, one of a number of bodies of water in eastern Norfolk and Suffolk.', 'the broad expanse of ocean', 'Appearance & Description', 'rộng', 'Một hồ nước nông, một trong số các vùng nước ở phía đông Norfolk và Suffolk.', 'vùng biển rộng lớn mênh mông'),
    ('41be5f8d-044f-5a3a-80c0-a816449524b1', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'capable', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈkeɪpəbl̩/', 'https://api.dictionaryapi.dev/media/pronunciations/en/capable-us.mp3', 'Able and efficient; having the ability needed for a specific task; having the disposition to do something; permitting or being susceptible to something.', 'As everyone knew, he was capable of violence when roused.', 'Appearance & Description', 'có khả năng', 'Có năng lực và hiệu quả; có khả năng cần thiết cho một nhiệm vụ cụ thể; có khuynh hướng làm điều gì đó; cho phép hoặc dễ bị ảnh hưởng bởi điều gì đó.', 'Như mọi người đều biết, anh ta có khả năng bạo lực khi bị kích động.'),
    ('fb6e4877-6cad-5389-9f30-d2ccbbac1e7f', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'characteristic', 'B2', '["n", "adj"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "adj", "level": "B2"}]'::jsonb, '/ˌkæɹəktəˈɹɪstɪk/', 'audio/characteristic.mp3', 'A distinguishing feature of a person or thing.', 'The characteristic of a field, if non-zero, must be a prime number.', 'Appearance & Description', 'đặc trưng', 'Một đặc điểm phân biệt của một người hoặc vật.', 'Đặc trưng của một trường, nếu khác không, phải là một số nguyên tố.'),
    ('6f7cef28-bf9a-51d0-ac1c-55e2997697b1', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'curved', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/kɜːvd/', 'audio/curved.mp3', 'To bend; to crook.', 'to curve a line', 'Appearance & Description', 'cong', 'Uốn cong; làm cho cong.', 'uốn cong một đường thẳng'),
    ('be3f60e4-2e50-5642-b9c3-019cf2c300c9', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'decent', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈdiːsənt/', 'audio/decent.mp3', 'Appropriate; suitable for the circumstances.', 'Are you decent? May I come in?', 'Appearance & Description', 'tử tế', 'Phù hợp; thích hợp với hoàn cảnh.', 'Anh đã mặc đồ chỉnh tề chưa? Tôi có thể vào không?'),
    ('e6bcb53f-f86a-5415-9722-708c7b105e92', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'entire', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ənˈtaɪə/', 'audio/entire.mp3', 'The whole of something; the entirety.', 'We had the entire building to ourselves for the evening.', 'Appearance & Description', 'toàn bộ', 'Toàn bộ của một thứ gì đó; tính toàn thể.', 'Chúng tôi có toàn bộ tòa nhà cho riêng mình vào buổi tối.'),
    ('43560a87-e6a4-56f7-955b-1f4c9710f318', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'external', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/əksˈtɜːnəl/', 'audio/external.mp3', '(chiefly in the plural) The exterior; outward features or appearances.', 'This building has some external pipework.', 'Appearance & Description', 'bên ngoài', '(chủ yếu ở số nhiều) Bề ngoài; các đặc điểm hoặc vẻ ngoài bên ngoài.', 'Tòa nhà này có một số đường ống bên ngoài.'),
    ('464705af-56d9-5697-b962-ce0a1a4fd375', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'extraordinary', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ɪksˈtɹɔː(ɹ)dɪnəɹi/', 'audio/extraordinary.mp3', 'Anything that goes beyond what is ordinary.', 'an extraordinary poet', 'Appearance & Description', 'phi thường', 'Bất cứ điều gì vượt ra ngoài những gì bình thường.', 'một nhà thơ phi thường'),
    ('84d81dc7-a07d-54d6-bfd3-ffa5aa3b61fb', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'flexible', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈflɛk.sə.bəl/', 'audio/flexible.mp3', 'Something that is flexible.', 'This was a principle more flexible to their purpose. -Rogers.', 'Appearance & Description', 'linh hoạt', 'Thứ gì đó linh hoạt.', 'Đây là một nguyên tắc linh hoạt hơn cho mục đích của họ. -Rogers.'),
    ('0174700d-1485-544f-87bb-3f7133d43593', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'grab', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/ɡɹæb/', 'https://api.dictionaryapi.dev/media/pronunciations/en/grab-us.mp3', 'A sudden snatch at something.', 'I grabbed her hand to pull her back from the cliff edge.', 'Appearance & Description', 'chộp lấy', 'Một cái chộp đột ngột vào thứ gì đó.', 'Tôi chộp lấy tay cô ấy để kéo cô ấy trở lại từ mép vách đá.'),
    ('f295443d-515d-5ffb-a048-ba7399a2998c', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'inner', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈɪnə/', 'audio/inner.mp3', 'An inner part.', 'inner door; inner room; inner sanctum; inner surface', 'Appearance & Description', 'bên trong', 'Một phần bên trong.', 'cửa bên trong; phòng bên trong; nơi linh thiêng bên trong; bề mặt bên trong'),
    ('c6f50a1b-595e-5554-83e8-d3cc06f6b521', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'internal', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ɪnˈtɝnəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/internal-us.mp3', 'Inside of something', 'We saw the internal compartments.', 'Appearance & Description', 'nội bộ', 'Bên trong của một cái gì đó', 'Chúng tôi đã thấy các ngăn bên trong.'),
    ('f9b7bafe-5e53-5ea9-b0a5-f0b848635a47', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'lean', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/liːn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/lean-us.mp3', '(of an object taller than its width and depth) An inclination away from the vertical.', 'The trees had various leans toward gaps in the canopy.', 'Appearance & Description', 'nghiêng, dựa', '(của một vật cao hơn chiều rộng và chiều sâu của nó) Độ nghiêng lệch khỏi phương thẳng đứng.', 'Những cái cây có các độ nghiêng khác nhau về phía những khoảng trống trong tán cây.'),
    ('97c18327-1555-564f-871d-46524f965156', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'loose', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/luːs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/loose-1-us.mp3', 'The release of an arrow.', 'This wheelbarrow has a loose wheel.', 'Appearance & Description', 'lỏng lẻo', 'Việc bắn một mũi tên.', 'Chiếc xe cút kít này có một bánh xe bị lỏng.'),
    ('38dddc2d-bb61-5b6e-9e5c-7e18fca7eb65', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'matching', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈmætʃɪŋ/', 'audio/matching.mp3', 'To agree; to be equal; to correspond.', 'Their interests didn''t match, so it took a long time to agree what to do together.', 'Appearance & Description', 'phù hợp, tương xứng', 'Đồng ý; bằng nhau; tương ứng.', 'Sở thích của họ không phù hợp, vì vậy phải mất nhiều thời gian để thống nhất việc sẽ làm cùng nhau.'),
    ('c6d1328c-45b6-5391-b386-3b505deb264a', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'neat', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/niːt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/neat-us.mp3', 'An artificial intelligence researcher who believes that solutions should be elegant, clear and provably correct. Compare scruffy.', 'My room is neat because I tidied it this morning. She has very neat hair.', 'Appearance & Description', 'gọn gàng', 'Một nhà nghiên cứu trí tuệ nhân tạo tin rằng các giải pháp nên thanh lịch, rõ ràng và có thể chứng minh được. So sánh với scruffy.', 'Phòng của tôi gọn gàng vì tôi đã dọn dẹp nó sáng nay. Cô ấy có mái tóc rất gọn gàng.'),
    ('f87a2b2e-9480-5c7b-95bd-1243d489c69d', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'permanent', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈpɜːmənənt/', 'audio/permanent.mp3', 'A chemical hair treatment imparting or removing curliness, whose effects typically last for a period of weeks; a perm.', 'Nothing in this world is truly permanent.', 'Appearance & Description', 'vĩnh viễn, lâu dài', 'Một phương pháp xử lý tóc bằng hóa chất tạo hoặc loại bỏ nếp xoăn, có tác dụng thường kéo dài trong vài tuần; một kiểu uốn tóc.', 'Không có gì trên thế giới này là thực sự vĩnh viễn.'),
    ('1f3cced8-1d81-5670-8a5e-b421dacf744a', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'plain', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/pleɪn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/plain-us.mp3', 'Flat, level.', 'Throughout high school she worried that she had a rather plain face.', 'Appearance & Description', 'đơn giản, bình thường', 'Phẳng, bằng phẳng.', 'Suốt thời trung học, cô ấy lo lắng rằng mình có khuôn mặt khá bình thường.'),
    ('91079c28-3e06-5b7b-b853-3ee91f7e8de6', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'presence', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈpɹɛzəns/', 'https://api.dictionaryapi.dev/media/pronunciations/en/presence-us.mp3', 'The fact or condition of being present, or of being within sight or call, or at hand.', 'Any painter can benefit from the presence of a live model from which to draw.', 'Appearance & Description', 'sự hiện diện', 'Thực tế hoặc điều kiện là đang có mặt, hoặc đang trong tầm nhìn hoặc gọi, hoặc sẵn sàng.', 'Bất kỳ họa sĩ nào cũng có thể hưởng lợi từ sự hiện diện của một người mẫu thật để vẽ.'),
    ('94c3f2b9-cd92-50ca-92d8-bf4132e08791', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'pure', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈpjɔː/', 'audio/pure.mp3', 'One who, or that which, is pure.', 'Tiger Woods pured his first drive straight down the middle of the fairway.', 'Appearance & Description', 'tinh khiết', 'Một người, hoặc thứ, là thuần khiết.', 'Tiger Woods đã đánh cú drive đầu tiên của mình một cách hoàn hảo thẳng xuống giữa đường bóng.'),
    ('8dcfc134-7735-5998-b803-d68ddd46dacf', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'rank', 'B2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "v", "level": "B2"}]'::jsonb, '/ɹæŋk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/rank-us.mp3', 'Strong of its kind or in character; unmitigated; virulent; thorough; utter (used of negative things).', 'rank nonsense', 'Appearance & Description', 'cấp bậc', 'Mạnh về loại hoặc tính chất; không giảm nhẹ; độc hại; triệt để; hoàn toàn (dùng cho những điều tiêu cực).', 'chuyện vô lý hoàn toàn'),
    ('b3811e23-b1e7-5377-a6d0-5e6d9024bd2c', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'rapid', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈɹæpɪd/', 'audio/rapid.mp3', '(often in the plural) a rough section of a river or stream which is difficult to navigate due to the swift and turbulent motion of the water.', 'a rapid stream', 'Appearance & Description', 'nhanh', '(thường ở số nhiều) một đoạn sông hoặc suối gồ ghề khó đi lại do dòng nước chảy xiết và hỗn loạn.', 'một dòng suối chảy xiết'),
    ('17c26c47-68a6-59d1-b532-ec12a56eab6a', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'realistic', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˌɹiːjəˈlɪstɪk/', 'audio/realistic.mp3', 'Expressed or represented as being accurate, practicable, or not idealistic.', 'A realistic appraisal of the situation.', 'Appearance & Description', 'thực tế', 'Được thể hiện hoặc đại diện là chính xác, khả thi, hoặc không lý tưởng hóa.', 'Một đánh giá thực tế về tình hình.'),
    ('46184a2d-a448-500a-a74e-100229e01492', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'reasonable', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈɹiː.zən.ə.bəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/reasonable-us.mp3', 'Having the faculty of reason; rational, reasoning.', 'a reasonable demand, amount, or price', 'Appearance & Description', 'hợp lý', 'Có khả năng lý trí; hợp lý, biết suy luận.', 'một yêu cầu, số lượng, hoặc giá cả hợp lý'),
    ('80b0beaf-20c9-5c8a-9362-11b1fdf5f813', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'silk', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/sɪlk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/silk-us.mp3', 'A fine fiber excreted by the silkworm or other arthropod (such as a spider).', 'The thread made of silk was barely visible.', 'Appearance & Description', 'lụa', 'Một sợi mịn do tằm hoặc động vật chân đốt khác (như nhện) tiết ra.', 'Sợi chỉ làm bằng lụa hầu như không thể nhìn thấy.'),
    ('49bd0c8b-b925-5e5c-ba63-3a9d7512a68a', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'slight', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '[sl̥l͡ɐɪʔ̚]', 'https://api.dictionaryapi.dev/media/pronunciations/en/slight-us.mp3', 'The act of slighting; a deliberate act of neglect or discourtesy.', 'a slight but graceful woman', 'Appearance & Description', 'mảnh mai/nhẹ', 'Hành động coi thường; một hành động cố ý của sự lơ là hoặc bất lịch sự.', 'một người phụ nữ mảnh mai nhưng duyên dáng'),
    ('901b6e21-6a83-5969-afc9-85f41f826a2a', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'split', 'B2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B2"}, {"pos": "n", "level": "B2"}]'::jsonb, '/splɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/split-uk.mp3', 'A crack or longitudinal fissure.', 'He’s got a nasty split.', 'Appearance & Description', 'vết nứt', 'Một vết nứt hoặc khe dọc.', 'Anh ấy có một vết nứt khó chịu.'),
    ('4e0e7f22-6522-5c17-bc3f-40a8fb12d26e', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'steady', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈstɛdi/', 'https://api.dictionaryapi.dev/media/pronunciations/en/steady-us.mp3', 'A rest or support, as for the hand, a tool, or a piece of work.', 'Hold the ladder steady while I go up.', 'Appearance & Description', 'vững chắc', 'Một điểm tựa hoặc giá đỡ, dành cho tay, một công cụ, hoặc một món đồ.', 'Giữ thang vững trong khi tôi leo lên.'),
    ('5eed28f7-e8fd-5187-bba6-964d6330eef9', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'tough', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/tʌf/', 'https://api.dictionaryapi.dev/media/pronunciations/en/tough-us.mp3', 'A person who obtains things by force; a thug or bully.', 'They were doing fine until they encountered a bunch of toughs from the opposition.', 'Appearance & Description', 'cứng, dai', 'Một người lấy đồ vật bằng vũ lực; một kẻ côn đồ hoặc bắt nạt.', 'Họ vẫn ổn cho đến khi gặp một nhóm côn đồ từ phe đối lập.'),
    ('a2bb2134-0e2e-5b3d-8ed5-9f5d0a64849c', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'unique', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/juːˈniːk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/unique-us.mp3', 'A thing without a like; something unequalled or unparallelled.', 'Every person has a unique life, therefore every person has a unique journey. ― Gary Cook', 'Appearance & Description', 'độc nhất', 'Một thứ không có cái giống như vậy; thứ gì đó không ai sánh bằng hoặc vô song.', 'Mỗi người có một cuộc đời độc nhất, do đó mỗi người có một hành trình độc nhất. ― Gary Cook'),
    ('71a3f49c-2575-579d-bfe8-2c5774bcedab', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'vast', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/vɑːst/', 'audio/vast.mp3', 'A vast space.', 'The Sahara desert is vast.', 'Appearance & Description', 'bao la, rộng lớn', 'Một không gian rộng lớn.', 'Sa mạc Sahara rất rộng lớn.'),
    ('d5d89e7c-6abf-51f1-b42c-24783cf8fda2', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'awkward', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈɑkwɚd/', 'audio/awkward.mp3', 'Someone or something that is awkward.', 'John was awkward at performing the trick. He''ll have to practice to improve.', 'Appearance & Description', 'vụng về', 'Ai đó hoặc cái gì đó vụng về.', 'John đã vụng về khi thực hiện thủ thuật. Anh ấy sẽ phải luyện tập để cải thiện.'),
    ('1317aefb-4426-57ca-9773-e7c646f163ce', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'charming', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈtʃɑː(ɹ).mɪŋ/', 'audio/charming.mp3', 'To seduce, persuade or fascinate someone or something.', 'He charmed her with his dashing tales of his days as a sailor.', 'Appearance & Description', 'duyên dáng, quyến rũ', 'Quyến rũ, thuyết phục hoặc mê hoặc ai đó hoặc điều gì đó.', 'Anh ấy quyến rũ cô bằng những câu chuyện hào hứng về những ngày làm thủy thủ của mình.'),
    ('95d70363-0160-5804-865f-0f561c7d5f9e', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'cute', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/kjuːt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/cute-us.mp3', 'Possessing physical features, behaviors, personality traits or other properties that are mainly attributed to infants and small or cuddly animals; e.g. fair, dainty, round, and soft physical features, disproportionately large eyes and head, playfulness, fragility, helplessness, curiosity or shyness, innocence, affectionate behavior.', 'Our reaction to cute attributes is understood as the way nature ensures mammals care for their young.', 'Appearance & Description', 'dễ thương', 'Sở hữu các đặc điểm thể chất, hành vi, tính cách hoặc các thuộc tính khác chủ yếu được quy cho trẻ sơ sinh và động vật nhỏ hoặc đáng ôm ấp; ví dụ: các đặc điểm thể chất công bằng, thanh nhã, tròn trịa và mềm mại,', 'Phản ứng của chúng ta với các thuộc tính dễ thương được hiểu là cách tự nhiên đảm bảo động vật có vú chăm sóc con non của chúng.'),
    ('a3263d03-b6d9-507d-b52c-205ac9c6b820', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'distant', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈdɪstənt/', 'audio/distant.mp3', 'Far off (physically, logically or mentally).', 'We heard a distant rumbling but didn''t pay any more attention to it. She was surprised to find that her fiancé was a distant relative of hers. His distant look showed that he was not listening to me.', 'Appearance & Description', 'xa xôi, xa cách', 'Xa xôi (về thể chất, logic hoặc tinh thần).', 'Chúng tôi nghe thấy tiếng ầm ầm từ xa nhưng không chú ý thêm nữa. Cô ấy ngạc nhiên khi phát hiện ra vị hôn phu của mình là một người họ hàng xa. Ánh mắt xa xăm của anh ấy cho thấy anh ấy không đang lắng nghe'),
    ('bccae148-f9c8-5acd-a5cb-57517c394b25', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'distinct', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/dɪsˈtɪŋkt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/distinct-us.mp3', 'Capable of being perceived very clearly.', 'Her voice was distinct despite the heavy traffic.', 'Appearance & Description', 'rõ ràng, riêng biệt', 'Có thể được nhận thức rất rõ ràng.', 'Giọng cô ấy vẫn rõ ràng mặc dù giao thông đông đúc.'),
    ('8d2f0aec-c481-5e36-a608-4bd27f067c3f', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'dot', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/dɒt/', 'audio/dot.mp3', 'A small, round spot.', 'a dot of colour', 'Appearance & Description', 'chấm', 'Một đốm tròn nhỏ.', 'một chấm màu'),
    ('d7239cae-e4d3-552e-9a78-58b15a9d9724', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'dull', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/dəl/', 'audio/dull.mp3', 'To render dull; to remove or blunt an edge or something that was sharp.', 'Years of misuse have dulled the tools.', 'Appearance & Description', 'cùn, đần độn', 'Làm cho cùn đi; loại bỏ hoặc làm mòn lưỡi sắc của thứ gì đó.', 'Nhiều năm sử dụng sai cách đã làm cùn các công cụ.'),
    ('eaad1020-aa9b-51b4-a1ad-f5022c70eb4c', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'elegant', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈɛl.ə.ɡənt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/elegant-uk.mp3', 'Characterised by or exhibiting elegance.', 'an elegant solution', 'Appearance & Description', 'thanh lịch', 'Được đặc trưng bởi hoặc thể hiện sự thanh lịch, tinh tế.', 'một giải pháp tinh tế'),
    ('e6cc37d8-97a3-542d-95bb-436dcfc59414', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'evident', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈɛ.vɪ.dənt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/evident-us.mp3', 'Obviously true by simple observation.', 'It was evident she was angry, after she slammed the door.', 'Appearance & Description', 'rõ ràng', 'Hiển nhiên đúng qua quan sát đơn giản.', 'Rõ ràng là cô ấy đang tức giận, sau khi cô ấy đóng sầm cửa.'),
    ('47d50dff-4fa6-554f-82ea-acc0a0afa5ca', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'excessive', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ɪkˈsɛsɪv/', 'audio/excessive.mp3', 'Exceeding the usual bounds of something; extravagant; immoderate.', 'Putting a wide vibrato on a single 16th triplet note at 160 beats per minute seems rather excessive.', 'Appearance & Description', 'quá mức', 'Vượt quá giới hạn thông thường của thứ gì đó; quá mức; không điều độ.', 'Đặt độ rung rộng trên một nốt triplet 1/16 đơn lẻ ở 160 nhịp mỗi phút có vẻ khá quá mức.'),
    ('c0289fee-7ae5-5299-8411-f1fa06af8617', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'fake', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/feɪk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/fake-us.mp3', 'Something which is not genuine, or is presented fraudulently.', 'to fake a marriage', 'Appearance & Description', 'giả mạo, giả', 'Thứ gì đó không chính hãng, hoặc được trình bày một cách gian lận.', 'giả một cuộc hôn nhân'),
    ('f087cead-c620-542b-a60e-3eab2a055287', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'fragment', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈfɹæɡmənt/', 'audio/fragment.mp3', 'A part broken off; a small, detached portion; an imperfect part, either physically or not', 'I heard a small fragment of the conversation.', 'Appearance & Description', 'mảnh vỡ', 'Một phần bị vỡ ra; một phần nhỏ, tách rời; một phần không hoàn hảo, về mặt vật lý hoặc không', 'Tôi nghe thấy một mảnh nhỏ của cuộc trò chuyện.'),
    ('90112b69-c82a-5bf0-855e-cfc572d25338', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'genuine', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈdʒɛnjuːˌaɪn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/genuine-us.mp3', 'Belonging to, or proceeding from the original stock; native', 'a genuine text; a genuine production; genuine materials; genuine friendship', 'Appearance & Description', 'chân thật, thật', 'Thuộc về, hoặc xuất phát từ nguồn gốc ban đầu; bản địa.', 'một văn bản chính gốc; một sản phẩm chính hãng; vật liệu thật; tình bạn chân thành'),
    ('ec549121-532b-5613-824c-d60e143af6ad', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'golden', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈɡəʊl.dən/', 'audio/golden.mp3', 'Kyphosus vaigiensis, a fish found in southeast Asia.', 'She wore a golden crown.', 'Appearance & Description', 'màu vàng, vàng', 'Cá Kyphosus vaigiensis, một loài cá được tìm thấy ở Đông Nam Á.', 'Cô ấy đội một vương miện vàng.'),
    ('19f3a1e6-97a7-5c03-8ba0-a053d293376a', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'gorgeous', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈɡɔːdʒəs/', 'audio/gorgeous.mp3', '(of a person or place) Very beautiful.', 'All the contest judges agreed that Brigitt was absolutely gorgeous.', 'Appearance & Description', 'lộng lẫy, tuyệt đẹp', '(về một người hoặc địa điểm) Rất đẹp.', 'Tất cả các giám khảo cuộc thi đều đồng ý rằng Brigitt hoàn toàn tuyệt đẹp.'),
    ('20b00782-88c3-5c03-9cd7-7ca0f25b1b00', '15ef8d19-0c44-553e-9a35-0a72f3c6fb6b', 'hidden', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈhɪd(ə)n/', 'https://api.dictionaryapi.dev/media/pronunciations/en/hidden-us.mp3', 'Located or positioned out of sight; not visually apparent.', 'hidden treasure; hidden talents', 'Appearance & Description', 'ẩn giấu', 'Nằm hoặc được đặt ngoài tầm nhìn; không rõ ràng về mặt hình ảnh.', 'kho báu ẩn giấu; tài năng ẩn giấu')
ON CONFLICT (desk_id, word) DO NOTHING;

-- ── B2 · Học tập & Trường lớp (50 từ) ─────────────────────────────
