INSERT INTO flashcard
    (id, desk_id, word, cefr, pos_json, all_levels_json, ipa, audio_url,
     definition, example, topic, vietnamese, vi_definition, vi_example)
VALUES
    ('32c3e327-17e6-574b-bdce-d815221430df', 'a6546351-d35f-5799-8078-c15f01fdfde8', 'aid', 'B2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "v", "level": "B2"}]'::jsonb, '/eɪd/', 'audio/aid.mp3', 'Help; assistance; succor, relief.', 'He came to my aid when I was foundering.', 'Health & Body', 'sự trợ giúp', 'Sự giúp đỡ; sự hỗ trợ; sự cứu trợ, sự giải cứu.', 'Anh ấy đã đến giúp tôi khi tôi đang gặp khó khăn.'),
    ('1c751df9-7311-5138-afa1-91b3bdcaa4c3', 'a6546351-d35f-5799-8078-c15f01fdfde8', 'breast', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/bɹɛst/', 'https://api.dictionaryapi.dev/media/pronunciations/en/breast-us.mp3', 'Either of the two organs on the front of a female human''s chest, which contain the mammary glands; also the analogous organs in males.', 'Tanya''s breasts grew remarkably during pregnancy.', 'Health & Body', 'ngực', 'Một trong hai cơ quan ở phía trước ngực của người phụ nữ, chứa tuyến vú; cũng là các cơ quan tương tự ở nam giới.', 'Ngực của Tanya phát triển đáng kể trong thời kỳ mang thai.'),
    ('1880a276-2d2f-5dc5-a8d2-8cf14aaef1b9', 'a6546351-d35f-5799-8078-c15f01fdfde8', 'collapse', 'B2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B2"}, {"pos": "n", "level": "B2"}]'::jsonb, '/kəˈlæps/', 'https://api.dictionaryapi.dev/media/pronunciations/en/collapse-au.mp3', 'The act of collapsing.', 'She suffered a terrible collapse after slipping on the wet floor.', 'Health & Body', 'sụp đổ', 'Hành động sụp đổ.', 'Cô ấy bị một cơn suy sụp khủng khiếp sau khi trượt chân trên sàn ướt.'),
    ('30ae42f2-8d1c-5a20-97e7-3e7329c43cb1', 'a6546351-d35f-5799-8078-c15f01fdfde8', 'conscious', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈkɒn.ʃəs/', 'audio/conscious.mp3', 'The part of the mind that is aware of itself; the consciousness.', 'The noise woke me, but it was another few minutes before I was fully conscious.', 'Health & Body', 'có ý thức', 'Phần của tâm trí nhận thức được chính nó; ý thức.', 'Tiếng ồn đánh thức tôi, nhưng phải mất thêm vài phút nữa tôi mới hoàn toàn tỉnh táo.'),
    ('54c49234-1759-51ab-be52-a6b83ff5a576', 'a6546351-d35f-5799-8078-c15f01fdfde8', 'harm', 'B2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "v", "level": "B2"}]'::jsonb, '/hɑːm/', 'audio/harm.mp3', 'Physical injury; hurt; damage', 'No harm came to my possessions.', 'Health & Body', 'tổn hại', 'Thương tích về thể chất; đau đớn; thiệt hại', 'Không có thiệt hại nào xảy đến với tài sản của tôi.'),
    ('2299289a-741e-564b-9ad7-1d1282ff6d1e', 'a6546351-d35f-5799-8078-c15f01fdfde8', 'harmful', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈhɑːmfl̩/', 'audio/harmful.mp3', 'Of a kind likely to be damaging; injurious', 'Wear a hat to protect your skin from harmful sunlight.', 'Health & Body', 'có hại', 'Thuộc loại có khả năng gây thiệt hại; gây tổn thương', 'Đội mũ để bảo vệ da bạn khỏi ánh nắng mặt trời có hại.'),
    ('18452f01-eda5-55df-81ae-8f509011fdf4', 'a6546351-d35f-5799-8078-c15f01fdfde8', 'hearing', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈhiːɹ.ɪŋ/', 'audio/hearing.mp3', '(stative) To perceive sounds through the ear.', 'I was deaf, and now I can hear.', 'Health & Body', 'thính giác', '(trạng thái) Nhận thức âm thanh qua tai.', 'Tôi đã bị điếc, và bây giờ tôi có thể nghe.'),
