    ('30e43ed9-a290-5a52-8c2f-9371bbcd0c8e', 'a6546351-d35f-5799-8078-c15f01fdfde8', 'immune', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ɪˈmjuːn/', 'audio/immune.mp3', 'A person who is not susceptible to infection by a particular disease', 'As a diplomat, you are immune from prosecution.', 'Health & Body', 'miễn dịch', 'Một người không dễ bị nhiễm bệnh bởi một bệnh cụ thể', 'Là một nhà ngoại giao, bạn được miễn truy tố.'),
    ('605872af-7809-5441-a498-6b199f0e13b2', 'a6546351-d35f-5799-8078-c15f01fdfde8', 'joint', 'B2', '["adj", "n"]'::jsonb, '[{"pos": "adj", "level": "B2"}, {"pos": "n", "level": "B2"}]'::jsonb, '/dʒɔɪnt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/joint-au.mp3', 'The point where two components of a structure join, but are still able to rotate.', 'This rod is free to swing at the joint with the platform.', 'Health & Body', 'khớp', 'Điểm mà hai bộ phận của một cấu trúc nối với nhau, nhưng vẫn có thể xoay.', 'Thanh này có thể tự do xoay tại khớp nối với bệ đỡ.'),
    ('1427a1fd-9286-570e-a882-077a3089f32a', 'a6546351-d35f-5799-8078-c15f01fdfde8', 'nursing', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈnɜːsɪŋ/', 'audio/nursing.mp3', 'To breastfeed: to feed (a baby) at the breast; to suckle.', 'She believes that nursing her baby will make him strong and healthy.', 'Health & Body', 'cho con bú, điều dưỡng', 'Cho con bú: cho (em bé) bú sữa mẹ; bú mẹ.', 'Cô ấy tin rằng cho con bú sẽ khiến con trai cô khỏe mạnh và mạnh mẽ.'),
    ('1712eadb-bdbe-52c5-988b-e38328eb7ae6', 'a6546351-d35f-5799-8078-c15f01fdfde8', 'pill', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/pɪl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/pill-uk.mp3', 'A small, usually round or cylindrical object designed for easy swallowing, usually containing some sort of medication.', 'Jane went on the pill when she left for college.', 'Health & Body', 'viên thuốc', 'Một vật thể nhỏ, thường tròn hoặc hình trụ được thiết kế để dễ nuốt, thường chứa một loại thuốc nào đó.', 'Jane bắt đầu uống thuốc tránh thai khi cô ấy lên đại học.'),
    ('00d26d90-651e-56ac-8966-ab3652dc048a', 'a6546351-d35f-5799-8078-c15f01fdfde8', 'psychological', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˌsaɪkəˈlɒdʒɪkl/', 'audio/psychological.mp3', 'Of or pertaining to psychology.', 'I''m concerned about their psychological well-being.', 'Health & Body', 'tâm lý', 'Thuộc về hoặc liên quan đến tâm lý học.', 'Tôi lo lắng về sức khỏe tâm lý của họ.'),
    ('0def4746-0e70-5802-9004-52a20a12fdfa', 'a6546351-d35f-5799-8078-c15f01fdfde8', 'scratch', 'B2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B2"}, {"pos": "n", "level": "B2"}]'::jsonb, '/skɹætʃ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/scratch-us.mp3', 'A disruption, mark or shallow cut on a surface made by scratching.', 'Her skin was covered with tiny scratches.', 'Health & Body', 'cào, vết xước', 'Một sự gián đoạn, vết hoặc vết cắt nông trên bề mặt được tạo ra bằng cách cào.', 'Da cô ấy phủ đầy những vết xước nhỏ.'),
    ('d47cd5c8-fc79-5cd3-9bf9-65f85c4ea1ac', 'a6546351-d35f-5799-8078-c15f01fdfde8', 'screening', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈskɹiːnɪŋ/', 'audio/screening.mp3', 'To filter by passing through a screen.', 'Mary screened the beans to remove the clumps of gravel.', 'Health & Body', 'sàng lọc, chiếu phim', 'Để lọc bằng cách đi qua một cái sàng.', 'Mary sàng đậu để loại bỏ những cục sỏi.'),
    ('b909a078-bbab-5879-a7e2-0581cd27ffec', 'a6546351-d35f-5799-8078-c15f01fdfde8', 'starve', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/stɑːv/', 'audio/starve.mp3', 'To die; in later use especially to die slowly, waste away.', 'Hey, ma, I''m starving! What''s for dinner?', 'Health & Body', 'chết đói', 'Chết; trong cách dùng sau này đặc biệt là chết dần, hao mòn.', 'Này mẹ, con đói quá! Tối nay ăn gì vậy?'),
    ('49296523-379e-546f-8888-605a5c599d57', 'a6546351-d35f-5799-8078-c15f01fdfde8', 'strengthen', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/ˈstɹɛŋ(k)θən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/strengthen-us.mp3', 'To make strong or stronger; to add strength to; to increase the strength of; to fortify.', 'strengthen a muscle', 'Health & Body', 'tăng cường', 'Làm cho mạnh hoặc mạnh hơn; thêm sức mạnh vào; tăng sức mạnh của; củng cố.', 'tăng cường cơ bắp'),
    ('3a49610c-e523-5b89-9c49-fb91711fd8e1', 'a6546351-d35f-5799-8078-c15f01fdfde8', 'stroke', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/stɹəʊk/', 'audio/stroke.mp3', 'An act of stroking (moving one''s hand over a surface).', 'She gave the cat a stroke.', 'Health & Body', 'đột quỵ', 'Một hành động vuốt ve (di chuyển tay trên bề mặt).', 'Cô ấy vuốt ve con mèo.'),
    ('97cbcd47-c5a4-5079-9406-40af2e40e469', 'a6546351-d35f-5799-8078-c15f01fdfde8', 'surgeon', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈsɜːdʒən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/surgeon-uk.mp3', 'One who performs surgery; a doctor who performs operations on people or animals.', 'The surgeon refused to operate because the patient was her son.', 'Health & Body', 'bác sĩ phẫu thuật', 'Người thực hiện phẫu thuật; một bác sĩ thực hiện các ca mổ trên người hoặc động vật.', 'Bác sĩ phẫu thuật từ chối mổ vì bệnh nhân là con trai bà.'),
    ('bc6b427c-98dd-5be4-a2d7-715799edbfd8', 'a6546351-d35f-5799-8078-c15f01fdfde8', 'survival', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/sɚˈvaɪvəl/', 'audio/survival.mp3', 'The fact or act of surviving; continued existence or life.', 'His survival in the open ocean was a miracle; he had fully expected to die.', 'Health & Body', 'sự sống sót', 'Thực tế hoặc hành động sống sót; sự tồn tại hoặc cuộc sống tiếp diễn.', 'Việc anh ấy sống sót trên biển khơi là một phép màu; anh đã hoàn toàn nghĩ rằng mình sẽ chết.'),
    ('e95258e7-e78c-5725-a3b3-4f4e4854bf10', 'a6546351-d35f-5799-8078-c15f01fdfde8', 'survivor', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/sɚˈvaɪvɚ/', 'audio/survivor.mp3', 'One who survives, especially one who survives a traumatic experience.', 'From this moment on, I choose to live not as a victim, but as a survivor.', 'Health & Body', 'người sống sót', 'Người sống sót, đặc biệt là người sống sót sau một trải nghiệm đau thương.', 'Từ giây phút này trở đi, tôi chọn sống không phải là nạn nhân, mà là người sống sót.'),
    ('9d4d51d1-d2ab-5d6f-b559-56af08049077', 'a6546351-d35f-5799-8078-c15f01fdfde8', 'swallow', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/ˈswɒləʊ/', 'audio/swallow.mp3', 'A deep chasm or abyss in the earth.', 'He took the aspirin with a single swallow of water.', 'Health & Body', 'nuốt', 'Một vực sâu hoặc vực thẳm trong lòng đất.', 'Anh ấy uống viên aspirin với một ngụm nước duy nhất.')
