    ('5821fa2a-19de-5c94-8613-d570acd88324', 'be9ff4eb-b3d9-560a-8b34-019d8277510f', 'declare', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/dɪˈkleə/', 'audio/declare.mp3', 'To make clear, explain, interpret.', 'He declared him innocent.', 'Law & Politics', 'tuyên bố', 'Làm cho rõ ràng, giải thích, diễn giải.', 'Ông ấy tuyên bố anh ta vô tội.'),
