    ('a615d1d7-6c70-5f36-8674-6f2ee08c9cee', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'critic', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈkɹɪt.ɪk/', 'audio/critic.mp3', 'A person who appraises the works of others.', 'Bob liked most of my presentation, but offered three minor critiques.', 'Arts & Entertainment', 'nhà phê bình', 'Một người đánh giá tác phẩm của người khác.', 'Bob thích hầu hết bài thuyết trình của tôi, nhưng đưa ra ba lời phê bình nhỏ.'),
