    ('e9fb9d49-d45e-5ca0-9a60-ef41cb7d5c54', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'reveal', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/ɹəˈviːl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/reveal-au.mp3', 'The outer side of a window or door frame; the jamb.', 'The comedian had been telling us about his sleep being disturbed by noise. Then came the reveal: he was sleeping on a bed in a department store.', 'Arts & Entertainment', 'tiết lộ', 'Mặt ngoài của khung cửa sổ hoặc cửa ra vào; thanh đứng.', 'Anh chàng hài kịch đã kể cho chúng tôi nghe về việc giấc ngủ của anh ấy bị quấy rầy bởi tiếng ồn. Sau đó là màn tiết lộ: anh ấy đang ngủ trên một chiếc giường trong cửa hàng bách hóa.'),
    ('7455d36f-f439-5809-80a6-7c120b5f48a8', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'rhythm', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈɹɪ.ð(ə)m/', 'https://api.dictionaryapi.dev/media/pronunciations/en/rhythm-us.mp3', 'The variation of strong and weak elements (such as duration, accent) of sounds, notably in speech or music, over time; a beat or meter.', 'Dance to the rhythm of the music.', 'Arts & Entertainment', 'nhịp điệu', 'Sự biến đổi của các yếu tố mạnh và yếu (chẳng hạn như độ dài, trọng âm) của âm thanh, đặc biệt trong lời nói hoặc âm nhạc, theo thời gian; một nhịp hoặc tiết tấu.', 'Nhảy theo nhịp điệu của âm nhạc.'),
    ('5c313a2c-0775-5702-805b-1dc5607a8e60', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'session', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈsɛʃən/', 'audio/session.mp3', 'An informal gathering of musicians to play music, especially improvised jazz or a similar genre.', '"Are we having a recording session?" / "Yes. We''ve even got some session musicians to provide some brass."', 'Arts & Entertainment', 'buổi diễn', 'Một cuộc tụ họp không chính thức của các nhạc sĩ để chơi nhạc, đặc biệt là nhạc jazz ngẫu hứng hoặc thể loại tương tự.', '"Chúng ta có buổi thu âm không?" / "Có. Chúng tôi thậm chí còn có một số nhạc sĩ tham gia để cung cấp kèn đồng."'),
    ('c8cc2f29-93b8-5d7d-a9e8-a440c1481110', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'tale', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈteɪl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/tale-au.mp3', 'An account of an asserted fact or circumstance; a rumour; a report, especially an idle or malicious story; a piece of gossip or slander; a lie.', 'Don''t tell tales!', 'Arts & Entertainment', 'câu chuyện', 'Một lời kể về một sự việc hoặc tình huống được khẳng định; một tin đồn; một báo cáo, đặc biệt là một câu chuyện vô căn cứ hoặc ác ý; một mẩu chuyện ngồi lê đôi mách hoặc vu khống; một lời nói dối.', 'Đừng có mách lẻo!'),
    ('802bbb86-8a1e-5cca-8bc2-b8e93c47904c', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'tone', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/təʊn/', 'audio/tone.mp3', 'A specific pitch.', 'Her rousing speech gave an upbeat tone to the rest of the evening.', 'Arts & Entertainment', 'giai điệu, âm sắc', 'Một cao độ cụ thể.', 'Bài phát biểu truyền cảm hứng của cô ấy đã mang lại một âm hưởng lạc quan cho phần còn lại của buổi tối.'),
