    ('3a1987a0-52bd-57f9-8e63-c8d6ef6ac272', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'artwork', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈɑːtˌwɜːk/', 'audio/artwork.mp3', 'A painting, drawing, sculpture or other piece of creative, visual art', 'The text has been reviewed, but the photographer hasn''t delivered some of the artwork.', 'Arts & Entertainment', 'tác phẩm nghệ thuật', 'Một bức tranh, bản vẽ, tác phẩm điêu khắc hoặc tác phẩm sáng tạo, nghệ thuật thị giác khác', 'Văn bản đã được xem xét, nhưng nhiếp ảnh gia chưa giao một số tác phẩm nghệ thuật.'),
    ('7a306012-e2ed-5af8-8f27-9bc795fa409e', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'balloon', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/bəˈluːn/', 'audio/balloon.mp3', 'An inflatable buoyant object, often (but not necessarily) round and flexible.', 'the balloon of St. Paul''s Cathedral in London', 'Arts & Entertainment', 'bóng bay', 'Một vật thể nổi có thể bơm hơi, thường (nhưng không nhất thiết) tròn và linh hoạt.', 'quả bóng bay của Nhà thờ St. Paul ở London'),
    ('ff52c250-4b68-534e-bd1e-498df7177499', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'choir', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/kwaɪə(ɹ)/', 'https://api.dictionaryapi.dev/media/pronunciations/en/choir-uk.mp3', 'Singing group; group of people who sing together; company of people who are trained to sing together.', 'The church choir practices Thursday nights.', 'Arts & Entertainment', 'dàn hợp xướng', 'Nhóm hát; một nhóm người hát cùng nhau; một nhóm người được đào tạo để hát cùng nhau.', 'Dàn hợp xướng nhà thờ tập luyện vào các tối thứ Năm.'),
    ('5d6eae89-d475-5ed7-aac2-8ae7359aa164', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'collector', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/kəˈlɛktə(ɹ)/', 'audio/collector.mp3', 'A person who or thing that collects, or which creates or manages a collection.', 'He is an avid collector of nineteenth-century postage stamps.', 'Arts & Entertainment', 'người sưu tập', 'Một người hoặc vật thu thập, hoặc tạo ra hoặc quản lý một bộ sưu tập.', 'Ông ấy là một nhà sưu tập nhiệt thành các con tem thế kỷ 19.'),
    ('e8675a18-eb79-5be7-99d2-e10a09ca1e37', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'comic', 'B2', '["adj", "n"]'::jsonb, '[{"pos": "adj", "level": "B2"}, {"pos": "n", "level": "B2"}]'::jsonb, '/ˈkɒmɪk/', 'audio/comic.mp3', 'A comedian.', 'a comic stereotype', 'Arts & Entertainment', 'hài hước, truyện tranh', 'Một diễn viên hài.', 'một khuôn mẫu hài'),
    ('08f58b56-66cd-5ec9-832c-126c63f5e50c', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'compose', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/kəmˈpəʊz/', 'audio/compose.mp3', 'To make something by merging parts.', 'The editor composed a historical journal from many individual letters.', 'Arts & Entertainment', 'soạn, sáng tác', 'Tạo ra thứ gì đó bằng cách hợp nhất các phần.', 'Biên tập viên đã biên soạn một tạp chí lịch sử từ nhiều bức thư cá nhân.'),
    ('2245262e-962b-5fcb-89d8-c853ee46daf3', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'craft', 'B2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "v", "level": "C1"}]'::jsonb, '/kɹɑːft/', 'audio/craft.mp3', 'Strength; power; might; force .', 'The craft of writing plays.', 'Arts & Entertainment', 'nghề thủ công / chế tác', 'Sức mạnh; quyền lực; sức mạnh; lực lượng.', 'Nghệ thuật viết kịch.'),
    ('675ba6ee-df1a-529d-9b05-32edbe2e900d', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'editorial', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˌɛdɪˈtɔːɹɪəl/', 'audio/editorial.mp3', 'An article in a publication giving the opinion of its editors on a given topic or current event.', 'editorial labours; editorial remarks', 'Arts & Entertainment', 'xã luận', 'Một bài báo trong ấn phẩm đưa ra quan điểm của biên tập viên về một chủ đề hoặc sự kiện hiện tại.', 'công việc biên tập; nhận xét của biên tập viên'),
    ('52d479ba-262e-53c6-8dcb-795124566067', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'exhibit', 'B2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B2"}, {"pos": "n", "level": "B2"}]'::jsonb, '/ɛɡ-/', 'audio/exhibit.mp3', 'An instance of exhibiting.', 'The museum''s new exhibit is drawing quite a crowd.', 'Arts & Entertainment', 'triển lãm', 'Một trường hợp triển lãm.', 'Triển lãm mới của bảo tàng đang thu hút khá đông người.'),
    ('da4d0de4-878a-56b5-b39b-5911cafb979c', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'gig', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ɡɪɡ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/gig-au.mp3', 'A performing engagement by a musical group; or, generally, any job or role, especially for a musician or performer.', 'Hey, when are we gonna get that hotel gig again?', 'Arts & Entertainment', 'buổi biểu diễn', 'Một hợp đồng biểu diễn của một nhóm nhạc; hoặc, nói chung, bất kỳ công việc hoặc vai trò nào, đặc biệt là cho một nhạc sĩ hoặc nghệ sĩ biểu diễn.', 'Này, khi nào chúng ta sẽ có lại buổi biểu diễn ở khách sạn đó?'),
    ('8c7c4f14-3238-5c7b-8b28-5568bbaefa75', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'icon', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈaɪ.kən/', 'audio/icon.mp3', 'An image, symbol, picture, or other representation usually as an object of religious devotion.', 'That man is an icon in the business; he personifies loyalty and good business sense.', 'Arts & Entertainment', 'biểu tượng', 'Một hình ảnh, biểu tượng, bức tranh, hoặc đại diện khác thường là một đối tượng của sự sùng bái tôn giáo.', 'Người đàn ông đó là một biểu tượng trong giới kinh doanh; ông ấy hiện thân cho lòng trung thành và tinh thần kinh doanh tốt.'),
    ('77ce863a-15e0-5470-a7bf-655b2cceeeac', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'illusion', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ɪˈl(j)uːʒ(ə)n/', 'audio/illusion.mp3', 'Anything that seems to be something that it is not.', 'Using artificial additives, scientists can create the illusion of fruit flavours in food.', 'Arts & Entertainment', 'ảo ảnh, ảo tưởng', 'Bất cứ thứ gì dường như là thứ mà nó không phải.', 'Sử dụng các chất phụ gia nhân tạo, các nhà khoa học có thể tạo ra ảo giác của hương vị trái cây trong thực phẩm.'),
    ('d10997cc-1ed0-5c9e-afa0-5bba35fe2766', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'ink', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ɪŋk/', 'audio/ink.mp3', 'A pigment (or dye)-based fluid used for writing, printing etc.', 'The TSA has been getting a lot of ink lately.', 'Arts & Entertainment', 'mực', 'Chất lỏng dựa trên sắc tố (hoặc thuốc nhuộm) dùng để viết, in ấn, v.v.', 'TSA gần đây nhận được rất nhiều sự chú ý của báo chí.'),
    ('5529f17a-728f-53b4-b497-272cfd29c562', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'interpretation', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ɪntəpɹəˈteɪʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/interpretation-uk.mp3', 'An act of interpreting or explaining what is obscure; a translation; a version; a construction.', 'the interpretation of a dream, or of an enigma.', 'Arts & Entertainment', 'sự diễn giải', 'Hành động diễn giải hoặc giải thích điều gì đó khó hiểu; một bản dịch; một phiên bản; một cách hiểu.', 'sự giải thích một giấc mơ, hoặc một điều bí ẩn.'),
    ('01986b77-3b8f-5e49-bdd2-08f5bb196dc0', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'legend', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈlɛdʒ.ənd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/legend-au.mp3', 'An unrealistic story depicting past events.', 'According to the legend on the map, that building is a school.', 'Arts & Entertainment', 'huyền thoại', 'Câu chuyện không thực tế mô tả các sự kiện trong quá khứ.', 'Theo chú giải trên bản đồ, tòa nhà đó là một trường học.'),
    ('998bf278-16f6-5e54-b210-7e188e0c4dae', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'literary', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈlɪt(ə)ɹi/', 'audio/literary.mp3', 'Relating to literature.', 'a literary history', 'Arts & Entertainment', 'thuộc văn học', 'Liên quan đến văn học.', 'một tác phẩm lịch sử văn học'),
    ('11941f68-d20a-5c80-8607-b53c6604362c', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'lyric', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈlɪɹ.ɪk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/lyric-uk.mp3', 'A lyric poem.', 'The lyric in line 3 doesn''t rhyme.', 'Arts & Entertainment', 'lời bài hát', 'Một bài thơ trữ tình.', 'Lời bài hát ở dòng 3 không gieo vần.'),
    ('7c2b068f-267c-5bf2-b78f-efe5f95d311e', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'metaphor', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈmɛt.ə.fɔː(ɹ)/', 'https://api.dictionaryapi.dev/media/pronunciations/en/metaphor-uk.mp3', 'The use of a word or phrase to refer to something that it is not, invoking a direct similarity between the word or phrase used and the thing described (but in the case of English without the words like or as, since use of those words would imply a simile); the word or phrase used in this way; an implied comparison.', 'desktop metaphor; wastebasket metaphor', 'Arts & Entertainment', 'phép ẩn dụ', 'Việc sử dụng một từ hoặc cụm từ để chỉ một thứ mà nó không phải, gợi lên sự tương đồng trực tiếp giữa từ hoặc cụm từ được dùng và thứ được mô tả (nhưng trong trường hợp tiếng Anh không có các từ như ''like'' hoặc ''as'').', 'ẩn dụ màn hình nền; ẩn dụ thùng rác'),
    ('6c7db9af-9684-5c86-b38a-8a807fe8d661', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'monster', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈmɒnstə(ɹ)/', 'audio/monster.mp3', 'A terrifying and dangerous creature.', 'The children decided Grover was a cuddly monster.', 'Arts & Entertainment', 'quái vật', 'Một sinh vật đáng sợ và nguy hiểm.', 'Bọn trẻ quyết định rằng Grover là một con quái vật đáng yêu.'),
    ('3fb56b9c-94ba-5a22-bf95-cf3474143103', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'monument', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈmɒnjʊmənt/', 'audio/monument.mp3', 'A structure built for commemorative or symbolic reasons, or as a memorial; a commemoration.', 'There is a monument on the town green to the soldiers who died in World War I.', 'Arts & Entertainment', 'đài tưởng niệm', 'Một công trình được xây dựng vì lý do tưởng niệm hoặc biểu tượng, hoặc như một đài kỷ niệm; một sự tưởng niệm.', 'Có một đài tưởng niệm trên bãi cỏ thị trấn cho những người lính đã chết trong Thế chiến thứ nhất.'),
    ('ed839163-ea01-5cc1-a3ce-72433594ff47', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'publishing', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈpʌblɪʃɪŋ/', 'audio/publishing.mp3', 'To issue (something, such as printed work) for distribution and/or sale.', 'Most of the sketches Faulkner published in 1925 appeared in the Sunday magazine section of the New Orleans Times-Picayune.', 'Arts & Entertainment', 'xuất bản', 'Phát hành (thứ gì đó, chẳng hạn như tác phẩm in) để phân phối và/hoặc bán.', 'Hầu hết các bản phác thảo Faulkner xuất bản năm 1925 xuất hiện trong phần tạp chí Chủ nhật của tờ New Orleans Times-Picayune.'),
    ('c73dfc77-db35-5b4c-b0ff-4d79ff9f90f5', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'punk', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/pʌŋk/', 'audio/punk.mp3', 'A person used for sex, particularly:', 'Ricky punked his new cell-mates.', 'Arts & Entertainment', 'punk', 'Một người được sử dụng cho tình dục, đặc biệt:', 'Ricky đã punk những bạn tù mới của anh ta.'),
    ('bdce5284-bd84-5d6a-b51f-1372bd6d33e7', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'romance', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ɹəˈmæns/', 'audio/romance.mp3', 'A story relating to chivalry; a story involving knights, heroes, adventures, quests, etc.', 'His life was a romance.', 'Arts & Entertainment', 'chuyện tình, tiểu thuyết lãng mạn', 'Một câu chuyện liên quan đến tinh thần hiệp sĩ; một câu chuyện liên quan đến các hiệp sĩ, anh hùng, cuộc phiêu lưu, nhiệm vụ, v.v.', 'Cuộc đời của anh ấy là một câu chuyện lãng mạn.'),
    ('cd92476f-696f-5c4d-a3f6-8de06d49e91d', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'spectacular', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/spɛkˈtæk.jʊ.lə/', 'audio/spectacular.mp3', 'A spectacular display.', 'The parachutists were spectacular.', 'Arts & Entertainment', 'ngoạn mục, đẹp mắt', 'Một màn trình diễn ngoạn mục.', 'Những người nhảy dù thật ngoạn mục.'),
    ('51f76481-c48e-5192-93b8-56603fb46789', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'tragic', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈtɹædʒɪk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/tragic-au.mp3', 'An obsessive fan, a superfan', '2008, Search for tragic Madeleine McCann over (in The Daily Telegraph of Australia, 14 February 2008) http//www.dailytelegraph.com.au/news/search-for-maddie-over/story-e6freuy9-1111115550129', 'Arts & Entertainment', 'bi thảm', 'Một người hâm mộ ám ảnh, một siêu fan', '2008, Cuộc tìm kiếm Madeleine McCann đáng buồn đã kết thúc (trong The Daily Telegraph của Úc, ngày 14 tháng 2 năm 2008) http//www.dailytelegraph.com.au/news/search-for-maddie-over/story-e6freuy9-1111115550129'),
    ('9a46f930-f706-56d0-84a4-d93d39dd88de', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'voluntary', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈvɒ.lən.tɹi/', 'audio/voluntary.mp3', 'A short piece of music, often having improvisation, played on a solo instrument.', 'If a man accidentally kills another by lopping a tree, it is not voluntary manslaughter.', 'Arts & Entertainment', 'tự nguyện', 'Một bản nhạc ngắn, thường có ngẫu hứng, được chơi trên một nhạc cụ độc tấu.', 'Nếu một người vô tình giết người khác bằng cách chặt cây, đó không phải là ngộ sát tự nguyện.'),
    ('70e7ea43-e664-571e-b749-df84e98666c7', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'entertaining', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, NULL, 'audio/entertaining.mp3', 'To amuse (someone); to engage the attention of agreeably.', 'The motivational speaker not only instructed but also entertained the audience.', 'Arts & Entertainment', 'giải trí, tiêu khiển', 'Làm cho (ai đó) vui; thu hút sự chú ý một cách dễ chịu.', 'Diễn giả truyền động lực không chỉ hướng dẫn mà còn giải trí cho khán giả.'),
    ('7accb01d-c9fa-5dc1-98c9-9c3d8b8f628b', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'firework', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, NULL, 'audio/firework.mp3', 'A device using gunpowder and other chemicals which, when lit, emits a combination of coloured flames, sparks, whistles or bangs, and sometimes made to rocket high into the sky before exploding, used for entertainment or celebration.', 'Commercial firework displays are commonly launched from boats or other vessels', 'Arts & Entertainment', 'pháo hoa', 'Một thiết bị sử dụng thuốc súng và các hóa chất khác, khi đốt lên, phát ra sự kết hợp của ngọn lửa màu sắc, tia lửa, tiếng huýt sáo hoặc tiếng nổ, và đôi khi được làm để bay cao lên trời trước khi nổ, được sử dụng cho mục đích giải trí.', 'Các màn bắn pháo hoa thương mại thường được phóng từ thuyền hoặc tàu thuyền khác'),
    ('2ad2b423-7123-5246-8ea9-412466611d71', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'alter', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/ˈɑl.tɚ/', 'audio/alter.mp3', 'To change the form or structure of.', NULL, 'Arts & Entertainment', 'thay đổi', 'Thay đổi hình thức hoặc cấu trúc của.', NULL),
    ('9840fb59-9ce1-5533-8a29-0622dd291a1b', '467c58e1-6a98-5a5d-a1ac-6d7d0fbcdbdb', 'artistic', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ɑːˈtɪstɪk/', 'audio/artistic.mp3', 'Having or revealing creative skill.', NULL, 'Arts & Entertainment', 'có tính nghệ thuật', NULL, NULL)
ON CONFLICT (desk_id, word) DO NOTHING;

