    ('159d55a3-5a51-57fb-9e48-52a52acae570', 'e264f34b-826e-549c-9089-8d3e371020f6', 'advance', 'B2', '["n", "v", "adj"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "v", "level": "B2"}, {"pos": "adj", "level": "B2"}]'::jsonb, '/ədˈvaːns/', 'audio/advance.mp3', 'A forward move; improvement or progression.', 'an advance in health or knowledge', 'Work & Career', 'tiến bộ, tiến lên', 'Một bước tiến về phía trước; sự cải thiện hoặc tiến triển.', 'một sự tiến bộ về sức khỏe hoặc kiến thức'),
    ('7910ad25-a847-57f8-84e8-bc25329ec9e8', 'e264f34b-826e-549c-9089-8d3e371020f6', 'agency', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈeɪ.dʒən.si/', 'https://api.dictionaryapi.dev/media/pronunciations/en/agency-us.mp3', 'The capacity, condition, or state of acting or of exerting power.', 'individual agency', 'Work & Career', 'cơ quan, đại lý', 'Khả năng, điều kiện, hoặc trạng thái hành động hoặc phát huy quyền lực.', 'quyền tự chủ cá nhân'),
    ('20e49038-a072-5532-982f-384c3dee96bc', 'e264f34b-826e-549c-9089-8d3e371020f6', 'associate', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/əˈsəʊsi.ət/', 'audio/associate.mp3', 'A person united with another or others in an act, enterprise, or business; a partner.', 'She associates with her coworkers on weekends.', 'Work & Career', 'liên kết, cộng tác', 'Một người hợp tác với người khác trong một hành động, công việc hoặc kinh doanh; một đối tác.', 'Cô ấy giao lưu với đồng nghiệp vào cuối tuần.'),
    ('b8fd970d-51ca-52ca-9be5-c9fc1cd2551d', 'e264f34b-826e-549c-9089-8d3e371020f6', 'associated', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/əˈsəʊsieɪtɪd/', 'audio/associated.mp3', 'To join in or form a league, union, or association.', 'She associates with her coworkers on weekends.', 'Work & Career', 'liên kết', 'Tham gia hoặc thành lập một liên đoàn, công đoàn hoặc hiệp hội.', 'Cô ấy giao lưu với đồng nghiệp vào cuối tuần.'),
    ('51504f7d-c8df-5b90-841e-7decc70a184b', 'e264f34b-826e-549c-9089-8d3e371020f6', 'chief', 'B2', '["adj", "n"]'::jsonb, '[{"pos": "adj", "level": "B2"}, {"pos": "n", "level": "B2"}]'::jsonb, '/tʃiːf/', 'https://api.dictionaryapi.dev/media/pronunciations/en/chief-us.mp3', 'A leader or head of a group of people, organisation, etc.', 'All firefighters report to the fire chief.', 'Work & Career', 'trưởng, chính', 'Một người lãnh đạo hoặc người đứng đầu một nhóm người, tổ chức, v.v.', 'Tất cả lính cứu hỏa đều báo cáo với trưởng phòng cứu hỏa.'),
    ('95723b06-82c9-566b-92c1-0559f4cc5ea9', 'e264f34b-826e-549c-9089-8d3e371020f6', 'command', 'B2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "v", "level": "B2"}]'::jsonb, '/kəˈmɑːnd/', 'audio/command.mp3', 'An order to do something.', 'I was given a command to cease shooting.', 'Work & Career', 'mệnh lệnh', 'Một lệnh để làm điều gì đó.', 'Tôi được lệnh ngừng bắn.'),
    ('493ba81e-b3b8-59cf-a0c4-838316d4e4e9', 'e264f34b-826e-549c-9089-8d3e371020f6', 'conduct', 'B2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B2"}, {"pos": "n", "level": "B2"}]'::jsonb, '/ˈkɒndʌkt/', 'audio/conduct.mp3', 'The act or method of controlling or directing', 'Good conduct will be rewarded and likewise poor conduct will be punished.', 'Work & Career', 'tiến hành', 'Hành động hoặc phương pháp kiểm soát hoặc chỉ đạo', 'Hành vi tốt sẽ được khen thưởng và tương tự, hành vi kém sẽ bị trừng phạt.'),
    ('bc63099f-9974-50b5-b5ab-41c7823a64e3', 'e264f34b-826e-549c-9089-8d3e371020f6', 'dismiss', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/dɪsˈmɪs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/dismiss-au.mp3', 'To discharge; to end the employment or service of.', 'The company dismissed me after less than a year.', 'Work & Career', 'sa thải', 'Cho thôi việc; chấm dứt việc làm hoặc dịch vụ của ai đó.', 'Công ty đã sa thải tôi sau chưa đầy một năm.'),
    ('021bfb9e-bfb4-516b-9d72-feaac6e9f2e2', 'e264f34b-826e-549c-9089-8d3e371020f6', 'executive', 'B2', '["n", "adj"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "adj", "level": "B2"}]'::jsonb, '/ɛɡˈzɛkjʊtɪv/', 'audio/executive.mp3', 'A chief officer or administrator, especially one who can make significant decisions on their own authority.', 'an executive officer', 'Work & Career', 'giám đốc điều hành', 'Một sĩ quan hoặc quản trị viên cấp cao, đặc biệt là người có thể đưa ra quyết định quan trọng bằng thẩm quyền của chính mình.', 'một sĩ quan điều hành'),
    ('ca9f4148-335b-5525-85f1-04bcfb41d11a', 'e264f34b-826e-549c-9089-8d3e371020f6', 'facility', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/fəˈsɪlɪti/', 'https://api.dictionaryapi.dev/media/pronunciations/en/facility-us.mp3', 'The fact of being easy, or easily done; absence of difficulty, simplicity.', 'The facility she shows in playing the violin is unrivalled.', 'Work & Career', 'cơ sở', 'Tính chất dễ dàng, hoặc được thực hiện dễ dàng; không có khó khăn, sự đơn giản.', 'Khả năng chơi violin mà cô ấy thể hiện là không ai sánh bằng.'),
    ('3bf28bc9-ed73-59f1-9f56-6e4c19278173', 'e264f34b-826e-549c-9089-8d3e371020f6', 'fellow', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈfɛləʊ/', 'audio/fellow.mp3', 'A colleague or partner.', 'Roger and his fellow workers are to go on strike.', 'Work & Career', 'đồng nghiệp', 'Một đồng nghiệp hoặc đối tác.', 'Roger và các đồng nghiệp của anh ấy sẽ đình công.'),
    ('bcb13e7c-791c-5b92-91a1-7692495fe3db', 'e264f34b-826e-549c-9089-8d3e371020f6', 'labour', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈleɪ.bə/', 'https://api.dictionaryapi.dev/media/pronunciations/en/labour-uk.mp3', 'Effort expended on a particular task; toil, work.', 'I think we''ve all got the idea. There''s no need to labour the point.', 'Work & Career', 'lao động', 'Nỗ lực bỏ ra cho một nhiệm vụ cụ thể; công sức, công việc.', 'Tôi nghĩ tất cả chúng ta đều đã hiểu ý rồi. Không cần phải nói đi nói lại vấn đề đó.'),
    ('01a24e3d-9505-5ccf-aa52-a72753ce3ab4', 'e264f34b-826e-549c-9089-8d3e371020f6', 'load', 'B2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "v", "level": "B2"}]'::jsonb, '/ləʊd/', 'audio/load.mp3', 'A burden; a weight to be carried.', 'I struggled up the hill with the heavy load in my rucksack.', 'Work & Career', 'tải trọng', 'Một gánh nặng; một trọng lượng phải mang theo.', 'Tôi vật lộn lên đồi với tải trọng nặng trong ba lô của mình.'),
    ('f328a94f-9d9f-5d1a-ad18-5d130c50ed73', 'e264f34b-826e-549c-9089-8d3e371020f6', 'mission', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈmɪʃn̩/', 'audio/mission.mp3', 'A set of tasks that fulfills a purpose or duty; an assignment set by an employer, or by oneself.', 'Many cities across the Americas grew from Spanish missions.', 'Work & Career', 'nhiệm vụ, sứ mệnh', 'Một tập hợp các nhiệm vụ nhằm hoàn thành một mục đích hoặc bổn phận; một nhiệm vụ được giao bởi người sử dụng lao động, hoặc bởi chính bản thân.', 'Nhiều thành phố trên khắp châu Mỹ đã phát triển từ các phái bộ truyền giáo của Tây Ban Nha.'),
    ('1a914ce0-0cdd-53f6-adc3-d2028125731d', 'e264f34b-826e-549c-9089-8d3e371020f6', 'priority', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/pɹaɪˈɒɹɨti/', 'audio/priority.mp3', 'An item''s relative importance.', 'He set his e-mail message''s priority to high.', 'Work & Career', 'ưu tiên', 'Tầm quan trọng tương đối của một mục.', 'Anh ấy đặt mức độ ưu tiên cho tin nhắn email của mình là cao.'),
    ('d9aff1b1-bd26-55d0-8220-4cc67cb4d9bf', 'e264f34b-826e-549c-9089-8d3e371020f6', 'procedure', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/pɹəˈsiːdʒə/', 'audio/procedure.mp3', 'A particular method for performing a task.', 'Ensure that you follow procedure when accessing customers'' personal information.', 'Work & Career', 'thủ tục', 'Một phương pháp cụ thể để thực hiện một nhiệm vụ.', 'Đảm bảo bạn tuân theo thủ tục khi truy cập thông tin cá nhân của khách hàng.'),
    ('f53a7dc8-9bde-522f-97ee-fd37e49d0178', 'e264f34b-826e-549c-9089-8d3e371020f6', 'pursue', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/pəˈʃu/', 'audio/pursue.mp3', 'To follow urgently, originally with intent to capture or harm; to chase.', 'Her rival pursued a quite different course.', 'Work & Career', 'theo đuổi', 'Theo đuổi một cách khẩn cấp, ban đầu với ý định bắt giữ hoặc gây hại; để đuổi theo.', 'Đối thủ của cô ấy đã theo đuổi một hướng đi hoàn toàn khác.'),
    ('7294e9a4-e631-5cc5-9615-75f4546ee6b1', 'e264f34b-826e-549c-9089-8d3e371020f6', 'specialist', 'B2', '["n", "adj"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "adj", "level": "B2"}]'::jsonb, '/ˈspɛʃəlɪst/', 'audio/specialist.mp3', 'Someone who is an expert in, or devoted to, some specific branch of study or research.', 'The tree Lepidothamnus laxifolius is a high alpine specialist found in high-altitude bog communities and in scrub.', 'Work & Career', 'chuyên gia', 'Một người là chuyên gia, hoặc tận tâm, trong một số lĩnh vực nghiên cứu hoặc nghiên cứu cụ thể.', 'Cây Lepidothamnus laxifolius là một loài chuyên biệt vùng cao núi cao, được tìm thấy trong các quần xã đầm lầy độ cao lớn và trong vùng cây bụi.'),
    ('e087b928-969b-5109-a9b5-5ea2ebe9a17f', 'e264f34b-826e-549c-9089-8d3e371020f6', 'wage', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/weɪd͡ʒ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/wage-us.mp3', '(often in plural) An amount of money paid to a worker for a specified quantity of work, usually calculated on an hourly basis and expressed in an amount of money per hour.', 'Before her promotion, her wages were 20% less.', 'Work & Career', 'tiền lương', '(thường ở dạng số nhiều) Một khoản tiền được trả cho người lao động cho một khối lượng công việc cụ thể, thường được tính theo giờ và biểu thị bằng một số tiền mỗi giờ.', 'Trước khi được thăng chức, tiền lương của cô ấy thấp hơn 20%.'),
    ('2aa853c1-2c71-57b7-b6b6-a9e054f44e42', 'e264f34b-826e-549c-9089-8d3e371020f6', 'accomplish', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/əˈkɐm.plɪʃ/', 'audio/accomplish.mp3', 'To finish successfully.', 'to accomplish a design, an object, a promise', 'Work & Career', 'hoàn thành, đạt được', 'Kết thúc một cách thành công.', 'để hoàn thành một thiết kế, một mục tiêu, một lời hứa'),
    ('46ec3283-9de4-56d1-ad90-075046d59294', 'e264f34b-826e-549c-9089-8d3e371020f6', 'adjust', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/əˈdʒʌst/', 'audio/adjust.mp3', 'To modify.', 'Morimoto''s recipes are adjusted to suit the American palate.', 'Work & Career', 'điều chỉnh', 'Sửa đổi.', 'Các công thức của Morimoto được điều chỉnh để phù hợp với khẩu vị người Mỹ.'),
    ('c23bf7c3-9926-5bbf-9b9e-fbb6b79a5940', 'e264f34b-826e-549c-9089-8d3e371020f6', 'applicant', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈæp.lə.kɪnt/', 'audio/applicant.mp3', 'One who applies for something; one who makes a request; a petitioner.', 'Our job advertisement attracted seven applicants.', 'Work & Career', 'người nộp đơn, ứng viên', 'Người nộp đơn xin điều gì đó; người đưa ra yêu cầu; một người thỉnh cầu.', 'Quảng cáo tuyển dụng của chúng tôi thu hút bảy ứng viên.'),
    ('35fb159e-a9d2-5a97-a905-a42776a5907c', 'e264f34b-826e-549c-9089-8d3e371020f6', 'assign', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/əˈsaɪn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/assign-us.mp3', 'An assignee.', 'to assign a day for trial', 'Work & Career', 'phân công', 'Một người được ủy quyền.', 'ấn định một ngày để xét xử'),
    ('cfb176ab-683a-5a2a-ab9f-9f437990a002', 'e264f34b-826e-549c-9089-8d3e371020f6', 'casual', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈkɛʒɘl/', 'audio/casual.mp3', 'A worker who is only working for a company occasionally, not as its permanent employee.', 'The devs dumbed the game down so the casuals could enjoy it.', 'Work & Career', 'thời vụ, bình thường', 'Một công nhân chỉ làm việc cho một công ty thỉnh thoảng, không phải là nhân viên chính thức của công ty đó.', 'Các nhà phát triển đã làm đơn giản hóa trò chơi để những người chơi bình thường có thể thưởng thức.'),
    ('8271d13b-526c-50d0-94c2-ec569427c142', 'e264f34b-826e-549c-9089-8d3e371020f6', 'clerk', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/klɐːk/', 'audio/clerk.mp3', 'One who occupationally works with records, accounts, letters, etc.; an office worker.', 'The law school graduate clerked for the supreme court judge for the summer.', 'Work & Career', 'nhân viên văn phòng', 'Người làm việc với hồ sơ, tài khoản, thư từ, v.v. như một nghề nghiệp; một nhân viên văn phòng.', 'Tốt nghiệp trường luật, anh ấy đã làm thư ký cho thẩm phán tòa án tối cao vào mùa hè.'),
    ('fc425bdf-35a8-5d60-b746-a816eb7a62e7', 'e264f34b-826e-549c-9089-8d3e371020f6', 'deadline', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈdɛdˌlaɪn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/deadline-uk.mp3', 'A time limit in the form of a date on or before which something must be completed.', 'I must make this deadline or my boss will kill me!', 'Work & Career', 'hạn chót', 'Một giới hạn thời gian dưới dạng một ngày mà vào hoặc trước đó một việc gì đó phải được hoàn thành.', 'Tôi phải hoàn thành đúng hạn chót này nếu không sếp sẽ giết tôi mất!'),
    ('c1e9ec53-c584-5bd8-aa77-50d9f281a4be', 'e264f34b-826e-549c-9089-8d3e371020f6', 'expertise', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˌɛkspɚˈtiːs/', 'audio/expertise.mp3', 'Great skill or knowledge in a particular field or hobby.', 'The scientist has expertise in the field of nuclear fusion.', 'Work & Career', 'chuyên môn', 'Kỹ năng hoặc kiến thức lớn trong một lĩnh vực hoặc sở thích cụ thể.', 'Nhà khoa học có chuyên môn trong lĩnh vực hợp hạch hạt nhân.'),
    ('8da5498d-3344-5823-b00f-52f30fc7e1e3', 'e264f34b-826e-549c-9089-8d3e371020f6', 'failed', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/feɪld/', 'https://api.dictionaryapi.dev/media/pronunciations/en/failed-us.mp3', 'To be unsuccessful.', 'Throughout my life, I have always failed.', 'Work & Career', 'thất bại', 'Không thành công.', 'Suốt cuộc đời mình, tôi luôn thất bại.'),
    ('8156f1ca-ad50-5ea4-a2fa-e7e128235261', 'e264f34b-826e-549c-9089-8d3e371020f6', 'mechanic', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/məˈkænɪk/', 'audio/mechanic.mp3', 'A manual worker; a labourer or artisan.', 'This game has a mechanic where if you run toward a ledge you automatically jump off rather than just falling.', 'Work & Career', 'thợ máy, cơ chế', 'Một công nhân thủ công; một lao động hoặc thợ thủ công.', 'Trò chơi này có một cơ chế mà nếu bạn chạy về phía rìa, bạn sẽ tự động nhảy xuống thay vì chỉ rơi.'),
    ('28acaf92-9dee-5f99-a663-9877450273cb', 'e264f34b-826e-549c-9089-8d3e371020f6', 'motivate', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/ˈməʊtɪveɪt/', 'audio/motivate.mp3', 'To provide someone with an incentive to do something; to encourage.', 'The weekly staff meeting was meant to motivate employees.', 'Work & Career', 'động viên', 'Cung cấp cho ai đó động lực để làm điều gì đó; khuyến khích.', 'Cuộc họp nhân viên hàng tuần nhằm mục đích động viên nhân viên.'),
    ('bcfebcdc-bca1-58a8-8561-4f09bb9c39ca', 'e264f34b-826e-549c-9089-8d3e371020f6', 'operator', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈɒpəˌɹeɪtə/', 'https://api.dictionaryapi.dev/media/pronunciations/en/operator-uk.mp3', 'One who operates.', 'In the sentence "What did Bill say he wants to buy?", "what" is an operator, binding a phonetically empty variable.', 'Work & Career', 'người vận hành', 'Người vận hành.', 'Trong câu "Bill nói anh ấy muốn mua gì?", "what" là một toán tử, ràng buộc một biến trống ngữ âm.'),
    ('0fc1846b-2f7b-5bb7-b17e-850a80fe5a5f', 'e264f34b-826e-549c-9089-8d3e371020f6', 'placement', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈpleɪsmənt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/placement-us.mp3', 'The act of placing or putting in place; the act of locating or positioning; the state of being placed.', 'It seems to me that the placement of that poster could be better.', 'Work & Career', 'sự sắp xếp', 'Hành động đặt hoặc đưa vào vị trí; hành động định vị hoặc xác định vị trí; trạng thái được đặt.', 'Đối với tôi, vị trí đặt tấm áp phích đó có thể tốt hơn.'),
    ('f1e8f9c6-acd6-5d5e-8cbc-10a9f1edd4d9', 'e264f34b-826e-549c-9089-8d3e371020f6', 'promotion', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/pɹəˈməʊʃən/', 'audio/promotion.mp3', 'An advancement in rank or position.', 'I''ll have to give myself a promotion!', 'Work & Career', 'thăng chức', 'Sự thăng tiến về cấp bậc hoặc vị trí.', 'Tôi sẽ phải tự thăng chức cho mình!'),
    ('2959b693-acc6-5224-a749-ae647869ac60', 'e264f34b-826e-549c-9089-8d3e371020f6', 'recruit', 'B2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B2"}, {"pos": "n", "level": "B2"}]'::jsonb, '/ɹɪˈkɹuːt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/recruit-uk.mp3', 'A supply of anything wasted or exhausted; a reinforcement.', 'These new recruits were hired after passing the interviews', 'Work & Career', 'tuyển dụng', 'Một nguồn cung cấp bất cứ thứ gì đã bị lãng phí hoặc cạn kiệt; một sự tăng cường.', 'Những tân binh mới này được tuyển dụng sau khi vượt qua các cuộc phỏng vấn'),
    ('e71242ae-9ae4-559b-8d09-aaefbd145d4c', 'e264f34b-826e-549c-9089-8d3e371020f6', 'resign', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/ɹɪˈzaɪn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/resign-1-uk.mp3', 'To give up; to relinquish ownership of.', 'He resigned the crown to follow his heart.', 'Work & Career', 'từ chức', 'Từ bỏ; từ bỏ quyền sở hữu.', 'Ông ấy từ bỏ ngai vàng để theo đuổi trái tim mình.'),
    ('dce3d9fb-77b3-5804-8ddd-a5cff6830117', 'e264f34b-826e-549c-9089-8d3e371020f6', 'suspend', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/səˈspɛnd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/suspend-uk.mp3', 'To halt something temporarily.', 'The meeting was suspended for lunch.', 'Work & Career', 'tạm ngừng', 'Tạm dừng một cái gì đó tạm thời.', 'Cuộc họp bị tạm ngừng để ăn trưa.'),
    ('b9a0524f-1c23-5773-b92d-ec66be7797cf', 'e264f34b-826e-549c-9089-8d3e371020f6', 'undertake', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/ʌndəˈteɪk/', 'audio/undertake.mp3', 'To take upon oneself; to start, to embark on (a specific task etc.).', 'He undertook to exercise more in future.', 'Work & Career', 'đảm nhận, thực hiện', 'Tự mình đảm đương; bắt đầu, dấn thân vào (một nhiệm vụ cụ thể, v.v.).', 'Anh ấy cam kết sẽ tập thể dục nhiều hơn trong tương lai.'),
    ('291adafe-48df-5aa3-a8b1-795dd07c71ce', 'e264f34b-826e-549c-9089-8d3e371020f6', 'fulfil', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, NULL, 'audio/fulfil.mp3', 'To satisfy, carry out, bring to completion (an obligation, a requirement, etc.).', 'You made a promise, son, and now you must fulfill it.', 'Work & Career', 'hoàn thành', 'Thỏa mãn, thực hiện, đưa đến sự hoàn thành (một nghĩa vụ, yêu cầu, v.v.).', 'Con đã hứa, con trai, và giờ con phải thực hiện nó.'),
    ('8b55494e-d472-525a-8c78-5d3df6afd8f4', 'e264f34b-826e-549c-9089-8d3e371020f6', 'full-time', 'B2', '["adj", "adv"]'::jsonb, '[{"pos": "adj", "level": "B2"}, {"pos": "adv", "level": "B2"}]'::jsonb, NULL, 'audio/full-time.mp3', 'Involving a full amount of time spent on some activity, especially a job.', 'Bringing up a child is a full-time activity.', 'Work & Career', 'toàn thời gian', 'Liên quan đến toàn bộ thời gian dành cho một hoạt động nào đó, đặc biệt là một công việc.', 'Nuôi dạy một đứa trẻ là một hoạt động toàn thời gian.'),
    ('8fe6ea0f-f8a2-53b2-861a-6b2041231e3e', 'e264f34b-826e-549c-9089-8d3e371020f6', 'motivation', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, NULL, 'audio/motivation.mp3', 'Willingness of action especially in behavior.', 'The motivation scores showed that 65% of people wanted to visit our website to learn more about the offer after watching the commercial.', 'Work & Career', 'động lực', 'Sự sẵn lòng hành động đặc biệt trong hành vi.', 'Điểm động lực cho thấy 65% mọi người muốn truy cập trang web của chúng tôi để tìm hiểu thêm về ưu đãi sau khi xem quảng cáo.'),
    ('7324c433-37c8-5985-90f7-cbbf0a055550', 'e264f34b-826e-549c-9089-8d3e371020f6', 'agenda', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/əˈdʒɛn.də/', 'https://api.dictionaryapi.dev/media/pronunciations/en/agenda-us.mp3', 'A temporally organized plan for matters to be attended to.', NULL, 'Work & Career', 'chương trình nghị sự', 'Một kế hoạch được tổ chức theo thời gian cho những vấn đề cần được giải quyết.', NULL),
    ('aa6b3c31-7ecc-5ecf-9be8-4da04c6c90a7', 'e264f34b-826e-549c-9089-8d3e371020f6', 'chairman', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈtʃɛːmən/', 'audio/chairman.mp3', 'A person presiding over a meeting.', NULL, 'Work & Career', 'chủ tịch', 'Một người chủ trì một cuộc họp.', NULL),
    ('2f7f6d22-ac9c-5c9d-834d-9a8f54dab36d', 'e264f34b-826e-549c-9089-8d3e371020f6', 'failure', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈfeɪl.jɚ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/failure-ca.mp3', 'State or condition of not meeting a desirable or intended objective, opposite of success.', NULL, 'Work & Career', 'sự thất bại', 'Trạng thái hoặc điều kiện không đạt được mục tiêu mong muốn hoặc dự định, trái ngược với thành công.', NULL),
    ('30150d64-01b4-575b-a54f-3c7545a225f7', 'e264f34b-826e-549c-9089-8d3e371020f6', 'initiative', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ɪˈnɪʃətɪv/', 'https://api.dictionaryapi.dev/media/pronunciations/en/initiative-us.mp3', 'A beginning; a first move.', NULL, 'Work & Career', 'sáng kiến', 'Một sự bắt đầu; một hành động đầu tiên.', NULL),
    ('f1a022da-8ccc-5622-b3c6-e84a9950c106', 'e264f34b-826e-549c-9089-8d3e371020f6', 'leadership', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈliːdəʃɪp/', 'audio/leadership.mp3', 'The capacity of someone to lead others.', NULL, 'Work & Career', 'khả năng lãnh đạo', 'Khả năng của một người để dẫn dắt người khác.', NULL),
    ('06d917eb-dd1f-5f2e-b2cd-43d01eb64034', 'e264f34b-826e-549c-9089-8d3e371020f6', 'maintain', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/meɪnˈteɪn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/maintain-us.mp3', 'To support (someone), to back up or assist (someone) in an action.', NULL, 'Work & Career', 'duy trì', 'Hỗ trợ (ai đó), ủng hộ hoặc giúp đỡ (ai đó) trong một hành động.', NULL),
    ('ef805856-8fe9-5f00-9f3c-e0637367a3a3', 'e264f34b-826e-549c-9089-8d3e371020f6', 'temporary', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈtɛmpəɹi/', 'audio/temporary.mp3', 'One serving for a limited time; short-term employee.', NULL, 'Work & Career', 'tạm thời', 'Người phục vụ trong một thời gian giới hạn; nhân viên ngắn hạn.', NULL),
    ('d0ce74f9-f772-5ab1-a528-4d0ee08efcc0', 'e264f34b-826e-549c-9089-8d3e371020f6', 'analyst', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈænəlɪst/', 'https://api.dictionaryapi.dev/media/pronunciations/en/analyst-us.mp3', 'Someone who analyzes.', NULL, 'Work & Career', 'nhà phân tích', 'Người phân tích.', NULL),
