    ('e126da10-8353-5ab7-a4f8-124b2cf1b6ec', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'angle', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈæŋ.ɡəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/angle-us.mp3', 'A figure formed by two rays which start from a common point (a plane angle) or by three planes that intersect (a solid angle).', 'the angle between lines A and B', 'Science & Research', 'góc', 'Một hình được tạo bởi hai tia bắt đầu từ một điểm chung (góc phẳng) hoặc bởi ba mặt phẳng cắt nhau (góc khối).', 'góc giữa đường A và B'),
    ('562b6065-a3ad-509c-b471-01e69d16e97f', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'artificial', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ɑː(ɹ)təˈfɪʃəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/artificial-us.mp3', 'Man-made; of artifice.', 'The flowers were artificial, and he thought them rather tacky.', 'Science & Research', 'nhân tạo', 'Do con người tạo ra; thuộc về sự khéo léo nhân tạo.', 'Những bông hoa là nhân tạo, và anh ấy nghĩ chúng khá rẻ tiền.'),
    ('9749868b-4dae-52e9-9071-503e5e63206e', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'complicated', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈkɒmplɪkeɪtɪd/', 'audio/complicated.mp3', 'To make complex; to modify so as to make something intricate or difficult.', 'Don''t complicate yourself in issues that are beyond the scope of your understanding.', 'Science & Research', 'rắc rối', 'Làm cho phức tạp; sửa đổi để làm cho điều gì đó trở nên phức tạp hoặc khó khăn.', 'Đừng tự làm mình rắc rối vào những vấn đề vượt quá tầm hiểu biết của bạn.'),
    ('5ba1ce21-b481-56df-a143-c3e427132037', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'consistent', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/kənˈsɪstənt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/consistent-au.mp3', '(in the plural) Objects or facts that are coexistent, or in agreement with one another.', 'He is very consistent in his political choices: economy good or bad, he always votes Labour!', 'Science & Research', 'nhất quán', '(số nhiều) Các đối tượng hoặc sự kiện cùng tồn tại, hoặc thống nhất với nhau.', 'Anh ấy rất nhất quán trong các lựa chọn chính trị của mình: kinh tế tốt hay xấu, anh ấy luôn bỏ phiếu cho Đảng Lao động!'),
    ('e55fdc60-c554-5f30-81fc-6e0cc64c9caf', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'constant', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈkɒnstənt/', 'audio/constant.mp3', 'That which is permanent or invariable.', 'constant time constant space', 'Science & Research', 'không đổi', 'Điều gì đó là vĩnh viễn hoặc không thay đổi.', 'thời gian không đổi không gian không đổi'),
    ('43715bef-c076-5993-98c1-e6a456f17e49', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'construct', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/ˈkɒn.stɹʌkt/', 'audio/construct.mp3', 'Something constructed from parts.', 'Loops and conditional statements are constructs in computer programming.', 'Science & Research', 'xây dựng', 'Thứ gì đó được xây dựng từ các bộ phận.', 'Vòng lặp và câu lệnh điều kiện là các cấu trúc trong lập trình máy tính.'),
    ('3b42ff40-7c93-5455-94a4-8e581ea319c0', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'construction', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/kənˈstɹʌkʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/construction-us.mp3', 'The process of constructing.', 'Construction is underway on the new bridge.', 'Science & Research', 'sự xây dựng', 'Quá trình xây dựng.', 'Việc xây dựng cây cầu mới đang được tiến hành.'),
    ('5710b4d1-0933-5403-b519-be090db69b28', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'core', 'B2', '["n", "adj"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "adj", "level": "B2"}]'::jsonb, '/kɔː/', 'audio/core.mp3', 'The central part of fruit, containing the kernels or seeds.', 'the core of an apple or quince', 'Science & Research', 'lõi / cốt lõi', 'Phần trung tâm của trái cây, chứa hạt hoặc hột.', 'lõi của quả táo hoặc quả mộc qua'),
    ('0be0e89d-f272-5a92-a03b-98e76c71486a', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'curve', 'B2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "v", "level": "B2"}]'::jsonb, '/kɜːv/', 'audio/curve.mp3', 'A gentle bend, such as in a road.', 'You should slow down when approaching a curve.', 'Science & Research', 'đường cong', 'Một khúc cua nhẹ, chẳng hạn như trên đường.', 'Bạn nên giảm tốc độ khi đến gần khúc cua.'),
    ('31bbd24d-536e-5430-a307-979ab0a96bb1', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'dig', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/dɪɡ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/dig-1-us.mp3', 'An archeological or paleontological investigation, or the site where such an investigation is taking place.', 'He guffawed and gave me a dig in the ribs after telling his latest joke.', 'Science & Research', 'đào', 'Một cuộc điều tra khảo cổ học hoặc cổ sinh vật học, hoặc địa điểm nơi cuộc điều tra như vậy đang diễn ra.', 'Anh ấy cười phá lên và thúc vào sườn tôi sau khi kể câu chuyện cười mới nhất của mình.'),
    ('aa312afd-7e35-5290-825b-50dc83806bc9', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'drag', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/dɹæɡ/', 'audio/drag.mp3', 'Resistance of the air (or some other fluid) to something moving through it.', 'When designing cars, manufacturers have to take drag into consideration.', 'Science & Research', 'lực cản', 'Sức cản của không khí (hoặc một chất lỏng khác) đối với thứ gì đó di chuyển qua nó.', 'Khi thiết kế ô tô, các nhà sản xuất phải tính đến lực cản.'),
    ('2e3ab379-1fce-5eff-8945-1dc24c024c30', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'existence', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ɛɡ.ˈzɪs.təns/', 'https://api.dictionaryapi.dev/media/pronunciations/en/existence-us.mp3', 'The state of being, existing, or occurring; beinghood.', 'In order to destroy evil, we must first acknowledge its existence.', 'Science & Research', 'sự tồn tại', 'Trạng thái hiện hữu, tồn tại, hoặc xảy ra; sự hiện hữu.', 'Để tiêu diệt cái ác, trước tiên chúng ta phải thừa nhận sự tồn tại của nó.'),
    ('0efea5a8-8efc-5434-8b84-678877e58ca6', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'exploration', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˌɛkspləˈɹeɪʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/exploration-us.mp3', 'The process of exploring.', 'The exploration of unknown areas was often the precursor to colonization.', 'Science & Research', 'sự thám hiểm', 'Quá trình khám phá.', 'Việc thám hiểm các khu vực chưa biết thường là tiền đề cho quá trình thuộc địa hóa.'),
    ('1e46794a-b515-54db-810e-63c2e2626e26', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'finding', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈfaɪndɪŋ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/finding-us.mp3', 'To encounter or discover by accident; to happen upon.', 'I found my car keys. They were under the couch.', 'Science & Research', 'phát hiện, kết quả tìm thấy', 'Tình cờ gặp hoặc khám phá; tình cờ xảy ra.', 'Tôi đã tìm thấy chìa khóa xe. Chúng ở dưới ghế sofa.'),
    ('a07bc87b-3608-5ce9-b31f-5d12e4afd066', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'frequency', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈfɹiːkwənsi/', 'audio/frequency.mp3', 'The rate of occurrence of anything; the relationship between incidence and time period.', 'The frequency of bus service has been improved from one every 15 to one every 12 minutes.', 'Science & Research', 'tần số', 'Tỷ lệ xảy ra của bất cứ điều gì; mối quan hệ giữa tỷ lệ mắc và khoảng thời gian.', 'Tần suất dịch vụ xe buýt đã được cải thiện từ 15 phút một chuyến lên 12 phút một chuyến.'),
    ('8ff01735-3dc9-5a2e-8e64-59df1caacb75', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'investigation', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ɪnˌvɛstəˈɡeɪʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/investigation-us.mp3', 'The act of investigating; the process of inquiring into or following up; research, especially patient or thorough inquiry or examination', 'Despite thorough investigation, the perpetrator of the attacks remains unknown.', 'Science & Research', 'cuộc điều tra', 'Hành động điều tra; quá trình tìm hiểu hoặc theo dõi; nghiên cứu, đặc biệt là sự tìm hiểu hoặc kiểm tra kỹ lưỡng, kiên nhẫn.', 'Mặc dù điều tra kỹ lưỡng, thủ phạm của các vụ tấn công vẫn chưa được xác định.'),
    ('ac9439d7-3839-5b94-80da-82eef9cd0fc8', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'mass', 'B2', '["n", "adj"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "adj", "level": "B2"}]'::jsonb, '/mæs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/mass-1-us.mp3', '(physical) Matter, material.', 'I mass 70 kilograms.', 'Science & Research', 'khối lượng', '(vật lý) Vật chất, vật liệu.', 'Tôi nặng 70 kilôgam.'),
    ('cf0318fe-4236-5e97-a164-c2510f6a329e', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'observe', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/əbˈzɝv/', 'audio/observe.mp3', 'To notice or view, especially carefully or with attention to detail.', 'From this vantage point we can observe the behavior of the animals in their natural habitat.', 'Science & Research', 'quan sát', 'Để nhận thấy hoặc xem xét, đặc biệt là một cách cẩn thận hoặc với sự chú ý đến chi tiết.', 'Từ vị trí thuận lợi này, chúng ta có thể quan sát hành vi của các loài động vật trong môi trường sống tự nhiên của chúng.'),
    ('78556b76-16bc-5791-aaa6-fcd969b5afd4', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'phenomenon', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/fɪˈnɒmənɒn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/phenomenon-uk.mp3', 'A thing or being, event or process, perceptible through senses; or a fact or occurrence thereof.', 'An electromagnetic phenomenon.', 'Science & Research', 'hiện tượng', 'Một sự vật hoặc sinh thể, sự kiện hoặc quá trình, có thể nhận thức được qua các giác quan; hoặc một sự thật hoặc sự xuất hiện của nó.', 'Một hiện tượng điện từ.'),
    ('e3106f86-05d2-5723-abd9-5e3dfcff075d', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'proof', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/pɹʉːf/', 'audio/proof.mp3', 'An effort, process, or operation designed to establish or discover a fact or truth; an act of testing; a test; a trial.', 'a proof load; a proof charge', 'Science & Research', 'bằng chứng', 'Một nỗ lực, quá trình hoặc thao tác được thiết kế để thiết lập hoặc khám phá một sự thật hoặc chân lý; một hành động kiểm tra; một bài kiểm tra; một thử nghiệm.', 'tải trọng thử nghiệm; lượng thuốc nạp thử'),
    ('8114c6c7-6813-5be6-a586-96e217319311', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'species', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈspiːsiːz/', 'https://api.dictionaryapi.dev/media/pronunciations/en/species-us.mp3', 'Type or kind. (Compare race.)', 'the male species', 'Science & Research', 'loài', 'Loại hoặc kiểu. (So sánh với chủng tộc.)', 'giống đực'),
    ('ee1cc038-f848-5ad8-861f-d440721909d7', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'transform', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/tɹænzˈfɔːm/', 'https://api.dictionaryapi.dev/media/pronunciations/en/transform-uk.mp3', 'An operation (often an integration) that converts one function into another.', 'The alchemists sought to transform lead into gold.', 'Science & Research', 'biến đổi, chuyển hóa', 'Một phép toán (thường là tích phân) chuyển đổi một hàm số này thành một hàm số khác.', 'Các nhà giả kim thuật tìm cách biến chì thành vàng.'),
    ('094074a2-89d2-5fd0-8d05-d6cd14cc48b2', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'universe', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈjuːnɪˌvɜːs/', 'audio/universe.mp3', 'Our universe, the sum of everything that exists in the cosmos, including time and space itself.', 'Powerful telescopes look far back into the distant reaches of the Universe.', 'Science & Research', 'vũ trụ', 'Vũ trụ của chúng ta, tổng của mọi thứ tồn tại trong vũ trụ, bao gồm cả thời gian và không gian.', 'Những kính thiên văn mạnh mẽ nhìn xa vào những vùng xa xôi của Vũ trụ.'),
    ('ba3062e3-9112-5964-abcd-75aeded23f25', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'absorb', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/əbˈsɔːb/', 'audio/absorb.mp3', 'To include so that it no longer has separate existence; to overwhelm; to cause to disappear as if by swallowing up; to incorporate; to assimilate; to take in and use up.', 'Heat, light, and electricity are absorbed in the substances into which they pass.', 'Science & Research', 'hấp thụ, thu hút', 'Bao gồm để nó không còn tồn tại riêng biệt; lấn át; làm biến mất như thể bị nuốt chửng; hợp nhất; đồng hóa; tiếp nhận và sử dụng hết.', 'Nhiệt, ánh sáng và điện được hấp thụ trong các chất mà chúng đi qua.'),
    ('a26e91a6-6d90-5d5d-8ed0-aedcc3aa10e4', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'accuracy', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '[ˈækjʊrəsɪ]', 'audio/accuracy.mp3', 'The state of being accurate; being free from mistakes, this exemption arising from carefulness; exactness; correctness', 'The value of testimony depends on its accuracy.', 'Science & Research', 'độ chính xác', 'Trạng thái chính xác; không có sai sót, sự miễn trừ này xuất phát từ sự cẩn thận; sự chính xác; tính đúng đắn', 'Giá trị của lời khai phụ thuộc vào độ chính xác của nó.'),
    ('2645b201-adb4-5142-878f-4cd6b8a055dc', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'acid', 'B2', '["n", "adj"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "adj", "level": "C1"}]'::jsonb, '/ˈæs.ɪd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/acid-us.mp3', 'A sour substance.', 'acid fruits or liquors', 'Science & Research', 'axit', 'Một chất có vị chua.', 'trái cây hoặc rượu có vị chua'),
    ('26ad1b90-581d-518d-93c2-4ca52614dc9e', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'bias', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈbaɪəs/', 'audio/bias.mp3', 'Inclination towards something; predisposition, partiality, prejudice, preference, predilection.', 'Our prejudices bias our views.', 'Science & Research', 'thiên vị', 'Xu hướng về một cái gì đó; định kiến, thành kiến, sự ưu tiên, sở thích.', 'Định kiến của chúng ta làm thiên vị quan điểm của chúng ta.'),
    ('fa144d99-01ea-5452-96a2-17c9d021fa0d', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'carbon', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈkɑɹbən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/carbon-us.mp3', 'The chemical element (symbol C) with an atomic number of 6. It can be found in pure form for example as graphite, a black, shiny and very soft material, or diamond, a colourless, transparent, crystalline solid and the hardest known material.', 'A methane molecule is made up of a single carbon with four hydrogens.', 'Science & Research', 'cacbon', 'Nguyên tố hóa học (ký hiệu C) với số nguyên tử là 6. Nó có thể được tìm thấy ở dạng tinh khiết, ví dụ như than chì, một vật liệu màu đen, bóng và rất mềm, hoặc kim cương, một tinh thể trong suốt, không màu.', 'Một phân tử metan được tạo thành từ một nguyên tử cacbon với bốn nguyên tử hydro.'),
    ('28959b01-c73d-5644-8edd-badd47c46e10', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'circuit', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '[ˈsəɾ.kɪʈ]', 'audio/circuit.mp3', 'The act of moving or revolving around, or as in a circle or orbit; a revolution', 'Having circuited the air.', 'Science & Research', 'mạch, vòng', 'Hành động di chuyển hoặc quay quanh, hoặc như trong một vòng tròn hoặc quỹ đạo; một vòng quay.', 'Đã bay vòng quanh bầu không khí.'),
    ('2e5968c1-e8b7-5de2-883e-adf7a6b56731', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'classify', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/ˈklæsɪfaɪ/', 'audio/classify.mp3', 'To identify by or divide into classes; to categorize', 'Should we classify "make up" as an idiom or as a phrasal verb?', 'Science & Research', 'phân loại', 'Xác định bằng hoặc chia thành các lớp; phân loại.', 'Chúng ta nên phân loại "make up" là một thành ngữ hay một cụm động từ?'),
    ('3e04d1e5-0a0e-5c07-87ee-44929bf42f3a', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'evolve', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/ɪˈvɒlv/', 'https://api.dictionaryapi.dev/media/pronunciations/en/evolve-uk.mp3', 'To move in regular procession through a system.', 'to evolve odours', 'Science & Research', 'tiến hóa', 'Di chuyển theo một quá trình có hệ thống.', 'tiến hóa mùi hương'),
    ('4b2de02d-26d8-5763-9988-6c1d7580307e', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'framework', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈfɹeɪm.wɜːk/', 'audio/framework.mp3', 'A support structure comprising joined parts or conglomerated particles and intervening open spaces of similar or larger size.', 'These ‘three principles of connexion’ compose the framework of principles in Hume''s account of the association of ideas.', 'Science & Research', 'khung', 'Một cấu trúc hỗ trợ bao gồm các phần được nối hoặc các hạt kết tụ và các khoảng trống xen kẽ có kích thước tương tự hoặc lớn hơn.', 'Ba ''nguyên tắc kết nối'' này tạo thành khung nguyên tắc trong giải thích của Hume về sự liên tưởng ý tưởng.'),
    ('dd1f6eaf-3f56-52d8-8953-139aad2078de', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'gene', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/dʒiːn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/gene-us.mp3', 'A theoretical unit of heredity of living organisms; a gene may take several values and in principle predetermines a precise trait of an organism''s form (phenotype), such as hair color.', 'A change in a gene is reflected in the protein or RNA molecule that it codes for.', 'Science & Research', 'gen', 'Một đơn vị lý thuyết về di truyền của các sinh vật sống; một gen có thể có nhiều giá trị và về nguyên tắc định trước một đặc điểm chính xác của dạng hình thái (kiểu hình) của một sinh vật, chẳng hạn như màu tóc.', 'Một sự thay đổi trong gen được phản ánh trong phân tử protein hoặc RNA mà nó mã hóa.'),
    ('e3bb4de3-3bfc-593b-b46d-05cd7327add9', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'genetic', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '[d͡ʒəˈnɛtɪk]', 'audio/genetic.mp3', 'Relating to genetics or genes.', 'Chinese has borrowed several words from English, but it does not have a genetic relationship to English.', 'Science & Research', 'di truyền', 'Liên quan đến di truyền học hoặc gen.', 'Tiếng Trung đã mượn một số từ tiếng Anh, nhưng nó không có mối quan hệ di truyền với tiếng Anh.'),
    ('66edf532-f098-5a62-8cd9-9c2b29bda6cb', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'mechanical', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/mɪˈkanɪk(ə)l/', 'https://api.dictionaryapi.dev/media/pronunciations/en/mechanical-us.mp3', 'Manually created layout of artwork that is camera ready for photographic reproduction.', 'mechanical engineering', 'Science & Research', 'cơ khí, máy móc', 'Bố cục thủ công của tác phẩm nghệ thuật đã sẵn sàng để chụp ảnh sao chép.', 'kỹ thuật cơ khí'),
    ('b69931b0-870e-5935-8125-20806583cb08', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'mechanism', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈmɛkənɪzm/', 'https://api.dictionaryapi.dev/media/pronunciations/en/mechanism-us.mp3', '(within a machine or machinery) Any mechanical means for the conversion or control of motion, or the transmission or control of power.', 'political machine', 'Science & Research', 'cơ chế', '(trong một máy hoặc máy móc) Bất kỳ phương tiện cơ học nào để chuyển đổi hoặc kiểm soát chuyển động, hoặc truyền tải hoặc kiểm soát năng lượng.', 'cỗ máy chính trị'),
    ('5f6f3f75-a30f-5af9-be9d-ed8377819466', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'motion', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈməʊʃən/', 'audio/motion.mp3', 'A state of progression from one place to another.', 'The motion to amend is now open for discussion.', 'Science & Research', 'chuyển động', 'Trạng thái di chuyển từ nơi này sang nơi khác.', 'Đề xuất sửa đổi hiện đang mở để thảo luận.'),
    ('29951da7-deaa-5b27-a658-7e89635364c1', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'observer', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ɒb-/', 'audio/observer.mp3', 'One who makes observations, monitors or takes notice', 'Most impartial observers agreed that Sampras had not served well.', 'Science & Research', 'người quan sát', 'Người thực hiện quan sát, giám sát hoặc chú ý', 'Hầu hết các nhà quan sát khách quan đều đồng ý rằng Sampras đã không giao bóng tốt.'),
    ('9a093070-59fa-553b-950d-9f8caa99a624', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'organic', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ɔːˈɡænɪk/', 'audio/organic.mp3', 'An organic compound.', 'The writing of the script was an organic process.', 'Science & Research', 'hữu cơ', 'Một hợp chất hữu cơ.', 'Việc viết kịch bản là một quá trình hữu cơ.'),
    ('1e6fd983-4aa7-501a-8a1e-a443f93b1100', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'parallel', 'B2', '["adj", "n"]'::jsonb, '[{"pos": "adj", "level": "B2"}, {"pos": "n", "level": "B2"}]'::jsonb, '/ˈpæɹəˌlɛl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/parallel-us.mp3', 'One of a set of parallel lines.', 'The 31st parallel passes through the center of my town.', 'Science & Research', 'song song', 'Một trong một tập hợp các đường thẳng song song.', 'Vĩ tuyến 31 đi qua trung tâm thị trấn của tôi.'),
    ('2e37f1a6-baf4-5386-b92c-57cf4663a8b1', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'probability', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/pɹɒbəˈbɪlɪti/', 'audio/probability.mp3', 'The state of being probable; likelihood.', 'The probability of an event A occurring is denoted P(A).', 'Science & Research', 'xác suất', 'Trạng thái có khả năng xảy ra; khả năng.', 'Xác suất của một sự kiện A xảy ra được ký hiệu là P(A).'),
    ('d7d1c0c4-7c33-590b-8359-1a7d79e9aea2', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'radiation', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ɹaɪ.di.ˈaɪ.ʃən/', 'audio/radiation.mp3', 'The shooting forth of anything from a point or surface, like diverging rays of light.', 'heat radiation', 'Science & Research', 'bức xạ', 'Sự phát ra của bất cứ thứ gì từ một điểm hoặc bề mặt, giống như các tia sáng phân kỳ.', 'bức xạ nhiệt'),
    ('33b97776-6337-55ea-bfe6-186212871360', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'steam', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/stiːm/', 'https://api.dictionaryapi.dev/media/pronunciations/en/steam-us.mp3', 'The vapor formed when water changes from liquid phase to gas phase.', 'After three weeks in bed he was finally able to sit up under his own steam.', 'Science & Research', 'hơi nước', 'Hơi được hình thành khi nước chuyển từ pha lỏng sang pha khí.', 'Sau ba tuần trên giường, cuối cùng anh ấy đã có thể tự ngồi dậy bằng sức lực của chính mình.'),
    ('52e80e2f-c89e-5476-b70f-53bb442b16b2', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'trace', 'B2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B2"}, {"pos": "n", "level": "C1"}]'::jsonb, '/tɹeɪs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/trace-us.mp3', 'An act of tracing.', 'Your cell phone company can put a trace on your line.', 'Science & Research', 'truy tìm, dấu vết', 'Hành động truy tìm.', 'Công ty điện thoại di động của bạn có thể đặt lệnh truy tìm trên đường dây của bạn.'),
    ('ee82e0ee-83ad-5cb5-ac18-9f9f8068a357', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'variation', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˌvɛəɹɪˈeɪʃn̩/', 'audio/variation.mp3', 'The act of varying; a partial change in the form, position, state, or qualities of a thing.', 'All of his soups are variations on a single recipe.', 'Science & Research', 'sự biến đổi, khác biệt', 'Hành động thay đổi; một sự thay đổi một phần về hình thức, vị trí, trạng thái hoặc phẩm chất của một thứ.', 'Tất cả các món súp của anh ấy đều là những biến thể của một công thức duy nhất.'),
    ('57dcaf9a-5f86-5177-b3f6-c14ebfd964df', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'extract', 'B2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "v", "level": "C1"}]'::jsonb, NULL, 'audio/extract.mp3', 'Something that is extracted or drawn out.', 'I used an extract of Hemingway''s book to demonstrate culture shock.', 'Science & Research', 'chiết xuất, trích xuất', 'Thứ gì đó được chiết xuất hoặc rút ra.', 'Tôi đã sử dụng một đoạn trích từ sách của Hemingway để minh họa cú sốc văn hóa.'),
    ('02fe6f70-c97f-5d0d-be21-6bcacd65bec8', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'bacteria', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/bækˈtɪəɹ.ɪ.ə/', 'audio/bacteria.mp3', 'A type, species, or strain of bacterium.', NULL, 'Science & Research', 'vi khuẩn', 'Một loại, loài, hoặc chủng của vi khuẩn.', NULL),
    ('72628d9c-0e8c-5a4b-92b7-48d62d3795a7', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'being', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈbiːɪŋ/', 'audio/being.mp3', 'A living creature.', NULL, 'Science & Research', 'sinh vật', 'Một sinh vật sống.', NULL),
    ('85c21905-f8cd-56fe-b8aa-f91c2bb6c671', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'combination', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/kɒmbɪˈneɪʃən/', 'audio/combination.mp3', 'The act of combining, the state of being combined or the result of combining.', NULL, 'Science & Research', 'sự kết hợp', 'Hành động kết hợp, trạng thái được kết hợp hoặc kết quả của việc kết hợp.', NULL),
    ('4ad638d0-e9e5-51ba-9f08-f6bbf474c1d3', '64aad4e1-7999-51a4-98d3-290fab58c3b2', 'detect', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/dɪˈtɛkt/', 'audio/detect.mp3', 'To discover or find by careful search, examination, or probing', NULL, 'Science & Research', 'phát hiện', 'Khám phá hoặc tìm thấy bằng cách tìm kiếm, kiểm tra hoặc thăm dò cẩn thận', NULL)
ON CONFLICT (desk_id, word) DO NOTHING;

