INSERT INTO flashcard
    (id, desk_id, word, cefr, pos_json, all_levels_json, ipa, audio_url,
     definition, example, topic, vietnamese, vi_definition, vi_example)
VALUES
    ('390ce3d7-561d-5acd-9104-89959b72b82a', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'blind', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/blaɪnd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/blind-us.mp3', 'A covering for a window to keep out light. The covering may be made of cloth or of narrow slats that can block light or allow it to pass.', 'a duck blind', 'Home & Living', 'rèm che', 'Vật che cửa sổ để ngăn ánh sáng. Vật che có thể làm bằng vải hoặc các thanh hẹp có thể chặn ánh sáng hoặc cho phép nó đi qua.', 'chỗ ẩn nấp săn vịt'),
    ('0ff41325-aa1d-5af3-a439-d4811e6f6e0a', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'cell', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/sɛl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/cell-us.mp3', 'A single-room dwelling for a hermit.', 'Gregor Mendel must have spent a good amount of time outside of his cell.', 'Home & Living', 'phòng nhỏ', 'Nơi ở một phòng cho một ẩn sĩ.', 'Gregor Mendel hẳn đã dành nhiều thời gian bên ngoài căn phòng nhỏ của mình.'),
    ('30b6ba92-5a73-5d0a-bd68-3b3be321dc37', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'domestic', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/dəˈmɛstɪk/', 'audio/domestic.mp3', 'A house servant; a maid; a household worker.', '2005: Bellingham-Whatcom County Commission Against Domestic Violence, Domestic Violence in Whatcom County (read on the Whatcom County website athttps//web.archive.org/web/20060618212243/http://www.co.whatcom.wa.us/boards/dv_whatcom042505.pdf on 20 May 2006) - The number of “verbal domestics” (where law enforcement determines that no assault has occurred and where no arrest is made), decreased significantly.', 'Home & Living', 'nội địa, gia đình', 'Người giúp việc nhà; một người hầu; một công nhân gia đình.', '2005: Ủy ban Chống Bạo lực Gia đình Hạt Bellingham-Whatcom, Bạo lực Gia đình ở Hạt Whatcom (đọc trên trang web của Hạt Whatcom tại https//web.archive.org/web/20060618212243/http://www.co.'),
    ('73fa4124-cbf2-5f05-920c-874ddaef0670', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'draft', 'B2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "v", "level": "B2"}]'::jsonb, '/dɹæft/', 'audio/draft.mp3', 'A current of air, usually coming into a room or vehicle.', 'She took a deep draft from the bottle of water.', 'Home & Living', 'gió lùa, bản nháp', 'Một luồng không khí, thường đi vào phòng hoặc phương tiện.', 'Cô ấy uống một ngụm lớn từ chai nước.'),
    ('ed79bab5-16cc-56c9-b61c-a69c27ae4103', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'folding', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈfəʊldɪŋ/', 'audio/folding.mp3', 'To bend (any thin material, such as paper) over so that it comes in contact with itself.', 'If you fold the sheets, they''ll fit more easily in the drawer.', 'Home & Living', 'có thể gấp', 'Để uốn cong (bất kỳ vật liệu mỏng nào, chẳng hạn như giấy) lại để nó tiếp xúc với chính nó.', 'Nếu bạn gấp các tấm ga, chúng sẽ dễ dàng vừa vào ngăn kéo hơn.'),
    ('2cf72456-1bc6-517a-80d6-bae431d77333', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'handle', 'B2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B2"}, {"pos": "n", "level": "B2"}]'::jsonb, '/ˈhæn.dl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/handle-us.mp3', 'The part of an object which is (designed to be) held in the hand when used or moved.', 'The daily handle of a Las Vegas casino is typically millions of dollars.', 'Home & Living', 'tay cầm', 'Phần của một vật được (thiết kế để) cầm trong tay khi sử dụng hoặc di chuyển.', 'Doanh thu hàng ngày của một sòng bạc Las Vegas thường là hàng triệu đô la.'),
    ('d9bb5cba-09ff-5404-9ede-7a83f8639081', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'household', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈhaʊshəʊld/', 'audio/household.mp3', 'Collectively, all the persons who live in a given house; a family including attendants, servants etc.; a domestic or family establishment.', 'a household word; a household name', 'Home & Living', 'hộ gia đình', 'Tập hợp tất cả những người sống trong một ngôi nhà; một gia đình bao gồm cả người hầu, người giúp việc; một tổ chức gia đình hoặc nội trợ.', 'một từ phổ biến trong mọi gia đình; một cái tên quen thuộc'),
    ('70d73a4a-bc67-5575-b11f-8e852bb60731', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'housing', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈhaʊzɪŋ/', 'audio/housing.mp3', 'To keep within a structure or container.', 'The car is housed in the garage.', 'Home & Living', 'nhà ở, vỏ bọc', 'Để giữ bên trong một công trình hoặc vật chứa.', 'Chiếc xe được để trong nhà để xe.'),
    ('9aaeca9c-aa8a-5e2d-85b2-3c6db01df361', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'opening', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈəʊ.pənɪŋ/', 'audio/opening.mp3', 'To make something accessible or allow for passage by moving from a shut position.', 'Turn the doorknob to open the door.', 'Home & Living', 'sự mở', 'Làm cho thứ gì đó có thể tiếp cận hoặc cho phép đi qua bằng cách di chuyển từ vị trí đóng.', 'Vặn tay nắm cửa để mở cửa.'),
    ('67721f17-00ad-5111-9545-b42821d73d0f', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'panel', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈpænəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/panel-us.mp3', 'A (usually) rectangular section of a surface, or of a covering or of a wall, fence etc.', 'Behind the picture was a panel on the wall.', 'Home & Living', 'tấm, bảng', 'Một phần (thường là) hình chữ nhật của một bề mặt, hoặc của một lớp phủ hoặc của một bức tường, hàng rào, v.v.', 'Đằng sau bức tranh là một tấm bảng trên tường.'),
    ('2409e492-9cbe-5bef-a940-d3b24d0b3310', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'pile', 'B2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "v", "level": "B2"}]'::jsonb, '/paɪl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/pile-us.mp3', 'A mass of things heaped together; a heap.', 'When we were looking for a new housemate, we put the nice woman on the "maybe" pile, and the annoying guy on the "no" pile', 'Home & Living', 'đống', 'Một khối lượng các vật chất chất đống lên nhau; một đống.', 'Khi chúng tôi đang tìm bạn cùng phòng mới, chúng tôi xếp người phụ nữ tử tế vào đống "có thể", và anh chàng phiền phức vào đống "không".'),
    ('062a3aa5-f60f-5666-986f-c781fccbbc99', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'possess', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/pəˈzɛs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/possess-us.mp3', 'To have; to have ownership of.', 'He does not even possess a working telephone.', 'Home & Living', 'sở hữu', 'Có; có quyền sở hữu.', 'Anh ấy thậm chí còn không sở hữu một chiếc điện thoại hoạt động được.'),
    ('851dbcd9-1ca3-534e-add6-fd4ea7730e46', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'resident', 'B2', '["n", "adj"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "adj", "level": "B2"}]'::jsonb, '/ˈɹɛzɪd(ə)nt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/resident-uk.mp3', 'A person, animal or plant living at a certain location or in a certain area.', 'The tiger lily is a resident of Asia.', 'Home & Living', 'cư dân', 'Một người, động vật hoặc thực vật sống ở một địa điểm hoặc khu vực nhất định.', 'Hoa huệ tây là một loài cư trú ở châu Á.'),
    ('aead12ec-37bd-52ba-9dd3-9c4080c2603f', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'shelter', 'B2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "v", "level": "B2"}]'::jsonb, '/ˈʃɛltə/', 'audio/shelter.mp3', 'A refuge, haven or other cover or protection from something.', 'During the rainstorm, we sheltered under a tree.', 'Home & Living', 'nơi trú ẩn', 'Nơi ẩn náu, nơi trú ẩn hoặc sự che chở, bảo vệ khỏi điều gì đó.', 'Trong cơn mưa giông, chúng tôi trú dưới một gốc cây.'),
    ('12a2a9b5-ed2c-5b12-ad67-e60f538f3a2d', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'stable', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈsteɪ.bəɫ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/stable-uk.mp3', 'A building, wing or dependency set apart and adapted for lodging and feeding (and training) animals with hoofs, especially horses.', 'There were stalls for fourteen horses in the squire''s stables.', 'Home & Living', 'ổn định', 'Một tòa nhà, cánh hoặc công trình phụ được tách riêng và điều chỉnh để làm chỗ ở và cho ăn (cũng như huấn luyện) động vật có móng, đặc biệt là ngựa.', 'Có những chuồng cho mười bốn con ngựa trong chuồng ngựa của điền chủ.'),
    ('62bae411-29b4-5125-80bc-a02ffc494684', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'surround', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/səˈɹaʊnd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/surround-us.mp3', 'Anything, such as a fence or border, that surrounds something.', 'to surround the world', 'Home & Living', 'bao quanh', 'Bất cứ thứ gì, chẳng hạn như hàng rào hoặc đường biên, bao quanh thứ gì đó.', 'bao quanh thế giới'),
    ('331f5ddb-6e1a-5d04-87a4-b2bd09ccc007', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'surrounding', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/səˈɹaʊndɪŋ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/surrounding-us.mp3', 'To encircle something or simultaneously extend in all directions.', 'to surround the world', 'Home & Living', 'xung quanh', 'Để bao quanh thứ gì đó hoặc đồng thời mở rộng theo mọi hướng.', 'bao quanh thế giới'),
    ('34d8cc6b-f407-5485-b9ff-a2ea62e83382', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'sweep', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/swiːp/', 'https://api.dictionaryapi.dev/media/pronunciations/en/sweep-au.mp3', 'A single action of sweeping.', 'Give the front steps a quick sweep to get rid of those fallen leaves.', 'Home & Living', 'quét', 'Một hành động quét duy nhất.', 'Hãy quét nhanh các bậc thềm trước để loại bỏ những chiếc lá rụng đó.'),
    ('468b58ea-de29-59fe-b50f-f4ea2bec729d', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'accommodate', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/əˈkɒməˌdeɪt/', 'audio/accommodate.mp3', 'To render fit, suitable, or correspondent; to adapt.', 'to accommodate ourselves to circumstances', 'Home & Living', 'cung cấp chỗ ở, điều chỉnh', 'Làm cho phù hợp, thích hợp, hoặc tương ứng; thích nghi.', 'để thích nghi bản thân chúng ta với hoàn cảnh'),
    ('167c1edd-28b2-5ec5-897c-d13c263b1b62', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'basket', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈbaːskət/', 'audio/basket.mp3', 'A lightweight container, generally round, open at the top, and tapering toward the bottom.', 'A basket of fake fruit adorned the table.', 'Home & Living', 'cái rổ', 'Một vật đựng nhẹ, thường tròn, mở ở phía trên và thon dần về phía đáy.', 'Một rổ trái cây giả trang trí bàn.'),
    ('f78f665c-f006-575e-aa2e-5f25559ae316', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'blanket', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈblæŋkɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/blanket-uk.mp3', 'A heavy, loosely woven fabric, usually large and woollen, used for warmth while sleeping or resting.', 'The baby was cold, so his mother put a blanket over him.', 'Home & Living', 'chăn', 'Một loại vải dày, dệt lỏng, thường lớn và bằng len, dùng để giữ ấm khi ngủ hoặc nghỉ ngơi.', 'Em bé bị lạnh, nên mẹ nó đắp một cái chăn cho nó.'),
    ('f5dc0ba8-7378-5790-af81-30849048fba1', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'brick', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/bɹɪk/', 'audio/brick.mp3', 'A hardened rectangular block of mud, clay etc., used for building.', 'This wall is made of bricks.', 'Home & Living', 'gạch', 'Một khối hình chữ nhật cứng bằng bùn, đất sét, v.v., dùng để xây dựng.', 'Bức tường này được làm bằng gạch.'),
    ('055e8ed8-2de0-51aa-ad14-51f64698c3ac', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'cabin', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈkæbɪn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/cabin-us.mp3', 'A small dwelling characteristic of the frontier, especially when built from logs with simple tools and not constructed by professional builders, but by those who meant to live in it.', 'Abraham Lincoln was born in a log cabin.', 'Home & Living', 'căn nhà gỗ nhỏ', 'Một ngôi nhà nhỏ đặc trưng của vùng biên giới, đặc biệt khi được xây từ gỗ bằng công cụ đơn giản và không do thợ xây chuyên nghiệp dựng lên, mà bởi những người định sống trong đó.', 'Abraham Lincoln được sinh ra trong một căn nhà gỗ.'),
    ('b85c0730-a2e6-5575-9059-484e4695b5e7', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'clip', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/klɪp/', 'https://api.dictionaryapi.dev/media/pronunciations/en/clip-us.mp3', 'Something which clips or grasps; a device for attaching one object to another.', 'Use this clip to attach the check to your tax form.', 'Home & Living', 'cái kẹp', 'Thứ gì đó kẹp hoặc giữ; một thiết bị để gắn vật này vào vật khác.', 'Dùng cái kẹp này để đính tờ séc vào mẫu đơn thuế của bạn.'),
    ('e0528773-ca3c-5bbf-92f8-ae50087b2a64', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'concrete', 'B2', '["adj", "n"]'::jsonb, '[{"pos": "adj", "level": "B2"}, {"pos": "n", "level": "B2"}]'::jsonb, '/kɵnˈkɹiːt/', 'audio/concrete.mp3', 'A solid mass formed by the coalescence of separate particles; a compound substance, a concretion.', 'The road was made of concrete that had been poured in large slabs.', 'Home & Living', 'bê tông', 'Một khối rắn được hình thành bởi sự kết hợp của các hạt riêng biệt; một chất hợp chất, một khối kết tụ.', 'Con đường được làm bằng bê tông đã được đổ thành những tấm lớn.'),
    ('844a2e9b-a211-5d41-b09c-0ec3c9c38e5a', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'convenience', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/kənˈviːnɪəns/', 'audio/convenience.mp3', 'The quality of being convenient.', 'Fast food is popular because of its cost and convenience.', 'Home & Living', 'sự tiện lợi', 'Chất lượng của sự tiện lợi.', 'Đồ ăn nhanh phổ biến vì chi phí và sự tiện lợi của nó.'),
    ('595f0f0b-67e2-52ae-b5e9-fccd860bb6dc', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'crack', 'B2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B2"}, {"pos": "n", "level": "B2"}]'::jsonb, '/kɹæk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/crack-us.mp3', 'A thin and usually jagged space opened in a previously solid material.', 'A large crack had formed in the roadway.', 'Home & Living', 'vết nứt / làm nứt', 'Một khoảng trống mỏng và thường có hình răng cưa mở ra trong một vật liệu trước đó là rắn chắc.', 'Một vết nứt lớn đã hình thành trên mặt đường.'),
    ('803c2856-a7cf-519c-a62d-1e2fee01755e', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'deck', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/dɛk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/deck-us.mp3', 'Any raised flat surface that can be walked on: a balcony; a porch; a raised patio; a flat rooftop.', 'to swab the deck', 'Home & Living', 'boong tàu, sàn', 'Bất kỳ bề mặt phẳng được nâng cao nào có thể đi lại được: ban công; hiên nhà; sân thượng lát nền; mái nhà bằng phẳng.', 'lau boong tàu'),
    ('8248f9fe-bfe6-547b-8b71-ee959f25b68f', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'fabric', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈfæb.ɹɪk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/fabric-us.mp3', 'An edifice or building.', 'cloth of a beautiful fabric', 'Home & Living', 'vải, chất liệu', 'Một tòa nhà hoặc công trình kiến trúc.', 'loại vải có chất liệu đẹp'),
    ('83b891f2-0e88-5387-8240-a4eff119b7bb', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'ladder', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈladə/', 'audio/ladder.mp3', 'A frame, usually portable, of wood, metal, or rope, used for ascent and descent, consisting of two side pieces to which are fastened rungs (cross strips or rounds acting as steps).', 'Oh damn it, I''ve laddered my tights!', 'Home & Living', 'cái thang', 'Một khung, thường di động, bằng gỗ, kim loại hoặc dây thừng, dùng để leo lên và xuống, bao gồm hai thanh bên được gắn các bậc thang (các thanh ngang hoặc vòng tròn hoạt động như bậc thang).', 'Ôi chết tiệt, tôi đã làm giãn tất của mình rồi!'),
    ('b5c6b8a5-0b1e-5974-85f1-c00249a98f54', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'lighting', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈlaɪtɪŋ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/lighting-us.mp3', 'To start (a fire).', 'We lit the fire to get some heat.', 'Home & Living', 'chiếu sáng', 'Để bắt đầu (một đám cháy).', 'Chúng tôi nhóm lửa để có chút hơi ấm.'),
    ('808f96ff-f076-5a33-a695-e04380e5971f', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'moving', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈmuːvɪŋ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/moving-us.mp3', 'To change place or posture; to go, in any manner, from one place or position to another.', 'A ship moves rapidly.', 'Home & Living', 'đang di chuyển', 'Thay đổi địa điểm hoặc tư thế; đi, bằng bất kỳ cách nào, từ nơi này hoặc vị trí này sang nơi hoặc vị trí khác.', 'Một con tàu di chuyển nhanh chóng.'),
    ('b878a633-2990-50f6-9150-70e1fb132f29', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'ruin', 'B2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B2"}, {"pos": "n", "level": "B2"}]'::jsonb, '/ˈɹuː.ɪn/', 'https://api.dictionaryapi.dev/media/pronunciations/en/ruin-us.mp3', '(sometimes in the plural) The remains of a destroyed or dilapidated construction, such as a house or castle.', 'The monastery has fallen into ruin.', 'Home & Living', 'tàn phá, phế tích', '(đôi khi ở dạng số nhiều) Phần còn lại của một công trình bị phá hủy hoặc đổ nát, chẳng hạn như một ngôi nhà hoặc lâu đài.', 'Tu viện đã rơi vào cảnh đổ nát.'),
    ('f460b201-6775-5369-a53d-d7ead825a815', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'spare', 'B2', '["adj", "v"]'::jsonb, '[{"pos": "adj", "level": "B2"}, {"pos": "v", "level": "C1"}]'::jsonb, '/ˈspɛə(ɹ)/', 'audio/spare.mp3', 'The act of sparing; moderation; restraint.', 'a spare diet', 'Home & Living', 'dự phòng, tha thứ', 'Hành động tha thứ; sự điều độ; sự kiềm chế.', 'một chế độ ăn kiêng kham khổ'),
    ('19de0c2a-0954-582d-aa79-ae9ef5063acd', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'spill', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/spɪl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/spill-au.mp3', 'A mess of something that has been dropped.', 'The bruise is from a bad spill he had last week.', 'Home & Living', 'làm đổ, tràn', 'Một mớ hỗn độn của thứ gì đó đã bị đổ.', 'Vết bầm tím là từ một cú ngã nặng mà anh ấy gặp tuần trước.'),
    ('1ada9aac-a06c-5a36-b516-90ce31083d41', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'stall', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/stɔːl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/stall-uk.mp3', 'A compartment for a single animal in a stable or cattle shed.', 'to stall an ox', 'Home & Living', 'chuồng', 'Một ngăn cho một con vật duy nhất trong chuồng hoặc nhà kho gia súc.', 'nhốt một con bò vào chuồng'),
    ('859bf4fd-75cd-56e6-9ef9-984ac8b3bf23', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'tap', 'B2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B2"}, {"pos": "n", "level": "B2"}]'::jsonb, '/tæp/', 'https://api.dictionaryapi.dev/media/pronunciations/en/tap-us.mp3', 'A tapering cylindrical pin or peg used to stop the vent in a cask.', 'We don''t have bottled water; you''ll have to get it from the tap.', 'Home & Living', 'vòi nước, gõ nhẹ', 'Một chốt hình trụ nhọn dần được sử dụng để bịt lỗ thông hơi trên thùng rượu.', 'Chúng tôi không có nước đóng chai; bạn sẽ phải lấy nó từ vòi.'),
    ('13db8581-4779-52b6-961c-acf9f6411510', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'trap', 'B2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B2"}, {"pos": "n", "level": "B2"}]'::jsonb, '/tɹæp/', 'https://api.dictionaryapi.dev/media/pronunciations/en/trap-au.mp3', 'A machine or other device designed to catch (and sometimes kill) animals, either by holding them in a container, or by catching hold of part of the body.', 'I put down some traps in my apartment to try and deal with the mouse problem.', 'Home & Living', 'bẫy', 'Một máy móc hoặc thiết bị khác được thiết kế để bắt (và đôi khi giết) động vật, bằng cách giữ chúng trong một thùng chứa, hoặc bằng cách giữ chặt một phần cơ thể.', 'Tôi đặt một vài cái bẫy trong căn hộ của mình để cố gắng xử lý vấn đề chuột.'),
    ('6b9e5d1c-2d24-5bb6-ba8d-778e1d3d4ff5', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'unfold', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/ʌnˈfəʊld/', 'https://api.dictionaryapi.dev/media/pronunciations/en/unfold-uk.mp3', 'In functional programming, a kind of higher-order function that is the opposite of a fold.', 'to unfold a map; to unfold a tablecloth; she unpacks the new dress and unfolds it carefully', 'Home & Living', 'mở ra, trải ra', 'Trong lập trình hàm, một loại hàm bậc cao ngược lại với hàm gấp.', 'mở một tấm bản đồ; trải một tấm khăn trải bàn; cô ấy mở gói chiếc váy mới và cẩn thận trải nó ra'),
    ('0189fd78-5ff8-539e-8e9f-13cb4d7f1041', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'downtown', 'B2', '["n", "adj", "adv"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "adj", "level": "B2"}, {"pos": "adv", "level": "B2"}]'::jsonb, NULL, 'audio/downtown.mp3', 'The main business part of a city or town, usually located at or near its center.', 'John walked every day to his downtown job.', 'Home & Living', 'trung tâm thành phố', 'Khu vực kinh doanh chính của một thành phố hoặc thị trấn, thường nằm ở hoặc gần trung tâm.', 'John đi bộ mỗi ngày đến công việc ở trung tâm thành phố.'),
    ('488492a8-89e0-5195-a23c-39cf68a516ea', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'decoration', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˌdɛkəˈɹeɪʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/decoration-us.mp3', 'The act of adorning, embellishing, or honoring; ornamentation.', NULL, 'Home & Living', 'đồ trang trí', 'Hành động tô điểm, làm đẹp, hoặc tôn vinh; sự trang trí.', NULL),
    ('37642daf-076b-5777-842b-a550dcb31237', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'basement', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈbeɪsmənt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/basement-us.mp3', 'A floor of a building below ground level.', NULL, 'Home & Living', 'tầng hầm', 'Một tầng của tòa nhà dưới mức mặt đất.', NULL),
    ('4e291d9c-9980-50f7-b5b4-f456120e27b6', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'candle', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈkændl̩/', 'audio/candle.mp3', 'A light source consisting of a wick embedded in a solid, flammable substance such as wax, tallow, or paraffin.', NULL, 'Home & Living', 'ngọn nến', 'Nguồn sáng bao gồm một bấc được gắn trong một chất rắn dễ cháy như sáp, mỡ hoặc paraffin.', NULL),
    ('042dbec6-5d0d-5a20-82e7-d7f1c8d9b748', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'compound', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈkɒmpaʊnd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/compound-1-uk.mp3', 'An enclosure within which workers, prisoners, or soldiers are confined', NULL, 'Home & Living', 'khuôn viên', 'Một khu vực khép kín nơi công nhân, tù nhân hoặc binh lính bị giam giữ', NULL),
    ('c9a32a8a-3c2b-5097-abaa-e3a1f53c5750', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'corridor', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈkɒɹɪˌdɔː(ɹ)/', 'audio/corridor.mp3', 'A narrow hall or passage with rooms leading off it, as in a building or in a railway carriage.', NULL, 'Home & Living', 'hành lang', 'Một sảnh hoặc lối đi hẹp với các phòng dẫn ra từ nó, như trong một tòa nhà hoặc trong toa xe lửa.', NULL),
    ('10a441db-32e9-5e96-8005-27cc9c2d85ef', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'envelope', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈɒn.və.ləʊp/', 'https://api.dictionaryapi.dev/media/pronunciations/en/envelope-1-uk.mp3', 'A paper or cardboard wrapper used to enclose small, flat items, especially letters, for mailing.', NULL, 'Home & Living', 'phong bì', 'Một bao bì bằng giấy hoặc bìa cứng dùng để đựng các vật phẳng nhỏ, đặc biệt là thư, để gửi thư.', NULL),
    ('f67683b1-13a3-5d07-9ae5-2e295d8deaa8', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'inhabitant', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ɪnˈhæ.bɪ.tənt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/inhabitant-us.mp3', 'Someone or thing who lives in a place.', NULL, 'Home & Living', 'cư dân', 'Ai đó hoặc thứ gì sống ở một nơi.', NULL),
    ('b0f0d505-d956-51fc-8f17-df39d70acece', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'rebuild', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/ˈɹiːbɪld/', 'audio/rebuild.mp3', 'A process or result of rebuilding.', NULL, 'Home & Living', 'xây dựng lại', 'Một quá trình hoặc kết quả của việc xây dựng lại.', NULL),
    ('865fcbc9-f99c-5e65-a073-4c08a12d1348', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'suburb', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈsʌbɜːb/', 'audio/suburb.mp3', 'A residential area located on the outskirts of a city or large town that usually includes businesses that cater to its residents; such as schools, grocery stores, shopping centers, restaurants, convenience stores, etc.', NULL, 'Home & Living', 'ngoại ô', 'Khu vực dân cư nằm ở ngoại ô thành phố hoặc thị trấn lớn, thường bao gồm các doanh nghiệp phục vụ cư dân; chẳng hạn như trường học, cửa hàng tạp hóa, trung tâm mua sắm, nhà hàng, tiện ích', NULL),
    ('8ecaa29d-87ae-52cd-8a04-99d28e73a2fd', 'a725c9f8-6f07-5e17-b4f5-93b9e3a3b230', 'tear1', 'B2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B2"}, {"pos": "n", "level": "B2"}]'::jsonb, NULL, 'audio/tear1.mp3', NULL, NULL, 'Home & Living', 'xé', NULL, NULL)
ON CONFLICT (desk_id, word) DO NOTHING;

