INSERT INTO flashcard
    (id, desk_id, word, cefr, pos_json, all_levels_json, ipa, audio_url,
     definition, example, topic, vietnamese, vi_definition, vi_example)
VALUES
    ('1ab8e4ac-e0a2-5c63-84c9-ab861a3e4694', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'bunch', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈbʌntʃ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/bunch-us.mp3', 'A group of similar things, either growing together, or in a cluster or clump, usually fastened together.', 'a bunch of grapes; a bunch of bananas; a bunch of keys; a bunch of yobs on a street corner', 'Nature & Environment', 'chùm', 'Một nhóm những thứ tương tự, hoặc mọc cùng nhau, hoặc trong một cụm hoặc chùm, thường được buộc lại với nhau.', 'một chùm nho; một nải chuối; một chùm chìa khóa; một đám thanh niên hư hỏng ở góc phố'),
    ('d1e949a3-2619-56f8-9eb2-567e9d1f5427', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'bush', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/bʊʃ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/bush-au.mp3', 'A woody plant distinguished from a tree by its multiple stems and lower height, being usually less than six metres tall; a horticultural rather than strictly botanical category.', 'bushes to support pea vines', 'Nature & Environment', 'bụi cây', 'Một loại cây thân gỗ phân biệt với cây thân gỗ bằng nhiều thân và chiều cao thấp hơn, thường thấp hơn sáu mét; một danh mục thuộc về làm vườn hơn là thực vật học nghiêm ngặt.', 'các bụi cây để đỡ dây đậu Hà Lan'),
    ('71fff4e0-6804-5e94-ac6d-415be765bf8a', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'creature', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈkɹiːt͡ʃə/', 'audio/creature.mp3', 'A living being; an animal or (sometimes derogatory) a human.', 'He''s a creature of habit. insects and other creatures', 'Nature & Environment', 'sinh vật', 'Một sinh vật sống; một động vật hoặc (đôi khi mang tính miệt thị) một con người.', 'Anh ấy là một sinh vật của thói quen. Côn trùng và các sinh vật khác'),
    ('f79688d1-3154-56b3-97b1-f4edb4fda999', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'crop', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/kɹɒp/', 'audio/crop.mp3', 'A plant, especially a cereal, grown to be harvested as food, livestock fodder or fuel or for any other economic purpose.', 'the farmer had lots of crops to sell at the market', 'Nature & Environment', 'vụ mùa', 'Một loại cây, đặc biệt là ngũ cốc, được trồng để thu hoạch làm thực phẩm, thức ăn gia súc hoặc nhiên liệu hoặc cho bất kỳ mục đích kinh tế nào khác.', 'người nông dân có nhiều vụ mùa để bán ở chợ'),
    ('4cdc0848-c2d2-5c8d-a789-7b0a82c69a8e', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'feather', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈfɛð.ə(ɹ)/', 'audio/feather.mp3', 'A branching, hair-like structure that grows on the bodies of birds, used for flight, swimming, protection and display.', 'The stylist feathered my hair.', 'Nature & Environment', 'lông vũ', 'Một cấu trúc phân nhánh, giống như tóc, mọc trên cơ thể chim, được sử dụng để bay, bơi, bảo vệ và phô trương.', 'Nhà tạo mẫu đã tỉa lọn tóc cho tôi.'),
    ('c3835013-de13-579d-9b09-19277c4881e6', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'flame', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/fleɪm/', 'https://api.dictionaryapi.dev/media/pronunciations/en/flame-us.mp3', 'The visible part of fire; a stream of burning vapour or gas, emitting light and heat.', 'The cello has a two-piece back with a beautiful narrow flame.', 'Nature & Environment', 'ngọn lửa', 'Phần có thể nhìn thấy của lửa; một dòng hơi hoặc khí đang cháy, tỏa ra ánh sáng và nhiệt.', 'Cây cello có mặt sau hai mảnh với vân gỗ đẹp hẹp.'),
    ('b9662004-2278-586f-bcbf-3b7c5998630d', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'hollow', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈhɒl.əʊ/', 'audio/hollow.mp3', 'A small valley between mountains.', 'He built himself a cabin in a hollow high up in the Rockies.', 'Nature & Environment', 'thung lũng nhỏ', 'Một thung lũng nhỏ giữa các ngọn núi.', 'Anh ấy đã xây cho mình một cabin trong một thung lũng nhỏ trên cao ở dãy Rockies.'),
    ('bfd676d8-24d9-5602-952b-3d46cf303483', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'landscape', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈlandskeɪp/', 'audio/landscape.mp3', 'A portion of land or territory which the eye can comprehend in a single view, including all the objects it contains.', 'The software patent landscape has changed considerably in the last years', 'Nature & Environment', 'phong cảnh', 'Một phần đất đai hoặc lãnh thổ mà mắt có thể bao quát trong một lần nhìn, bao gồm tất cả các đối tượng mà nó chứa đựng.', 'Bối cảnh bằng sáng chế phần mềm đã thay đổi đáng kể trong những năm gần đây.'),
    ('21fe1a81-e2ed-5892-b582-7f9cb12d64b9', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'massive', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈmæs.ɪv/', 'audio/massive.mp3', 'A homogeneous mass of rock, not layered and without an obvious crystal structure.', 'karst massives in western Georgia', 'Nature & Environment', 'đồ sộ, khổng lồ', 'Một khối đá đồng nhất, không phân lớp và không có cấu trúc tinh thể rõ ràng.', 'các khối đá karst ở phía tây Georgia'),
    ('077940a9-7791-50d5-b4f1-4f17bc44f3aa', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'mount', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/maʊnt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/mount-us.mp3', 'A hill or mountain.', 'the mount of Jupiter', 'Nature & Environment', 'leo lên, gắn', 'Một ngọn đồi hoặc núi.', 'gò của sao Mộc'),
    ('8157afe1-f276-57e7-9eea-722c609c20b8', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'pitch', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/pɪtʃ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/pitch-au.mp3', 'A sticky, gummy substance secreted by trees; sap.', 'It is hard to get this pitch off my hand.', 'Nature & Environment', 'nhựa cây', 'Một chất dính, dẻo tiết ra từ cây; nhựa cây.', 'Thật khó để làm sạch nhựa cây này khỏi tay tôi.'),
    ('a3bfd5b4-5424-5449-aa89-c78935c51b2b', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'root', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ɹuːt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/root-au.mp3', 'The part of a plant, generally underground, that anchors and supports the plant body, absorbs and stores water and nutrients, and in some plants is able to perform vegetative reproduction.', 'This tree''s roots can go as deep as twenty metres underground.', 'Nature & Environment', 'rễ cây', 'Phần của cây, thường ở dưới đất, có chức năng neo giữ và hỗ trợ thân cây, hấp thụ và dự trữ nước cùng chất dinh dưỡng, và ở một số loài cây có khả năng sinh sản vô tính.', 'Rễ của cây này có thể sâu tới hai mươi mét dưới lòng đất.'),
    ('cd019e38-e75c-5de6-93ee-11d4785297c4', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'shade', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ʃeɪd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/shade-us.mp3', 'Darkness where light, particularly sunlight, is blocked.', 'The old oak tree gave shade in the heat of the day.', 'Nature & Environment', 'bóng râm', 'Bóng tối nơi ánh sáng, đặc biệt là ánh sáng mặt trời, bị chặn lại.', 'Cây sồi già tỏa bóng râm trong cái nóng ban ngày.'),
    ('5ec3bef2-bf01-5511-9345-8c2774af171c', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'shadow', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈʃædəʊ/', 'audio/shadow.mp3', 'A dark image projected onto a surface where light (or other radiation) is blocked by the shade of an object.', 'My shadow lengthened as the sun began to set.', 'Nature & Environment', 'cái bóng', 'Một hình ảnh tối được chiếu lên bề mặt nơi ánh sáng (hoặc bức xạ khác) bị chặn bởi bóng của một vật thể.', 'Cái bóng của tôi kéo dài ra khi mặt trời bắt đầu lặn.'),
    ('9d7edcab-8dcd-5128-8c0a-b0ff923cd27c', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'shallow', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈʃaləʊ/', 'audio/shallow.mp3', 'A shallow portion of an otherwise deep body of water.', 'The ship ran aground in an unexpected shallow.', 'Nature & Environment', 'nông', 'Một phần nông của một vùng nước sâu.', 'Con tàu mắc cạn ở một vùng nước nông bất ngờ.'),
    ('23fdc661-d97c-5382-b7e2-c063ead20b81', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'slope', 'B2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "v", "level": "B2"}]'::jsonb, '/sləʊp/', 'audio/slope.mp3', 'An area of ground that tends evenly upward or downward.', 'I had to climb a small slope to get to the site.', 'Nature & Environment', 'dốc', 'Một khu vực mặt đất có xu hướng nghiêng lên hoặc xuống đều đặn.', 'Tôi phải leo một con dốc nhỏ để đến được địa điểm.'),
    ('465f6053-f54d-538a-a98a-a7ea6fc79ec8', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'solar', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈsəʊlə/', 'audio/solar.mp3', 'Of or pertaining to the sun; proceeding from the sun', 'solar influence', 'Nature & Environment', 'mặt trời', 'Thuộc hoặc liên quan đến mặt trời; xuất phát từ mặt trời', 'ảnh hưởng của mặt trời'),
    ('ce6442b9-d897-5f1d-9eab-cb0f087809e2', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'steep', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/stiːp/', 'https://api.dictionaryapi.dev/media/pronunciations/en/steep-us.mp3', 'The steep side of a mountain etc.; a slope or acclivity.', 'a steep hill or mountain; a steep roof; a steep ascent; a steep barometric gradient', 'Nature & Environment', 'dốc', 'Sườn dốc của một ngọn núi, v.v.; một độ dốc hoặc chỗ dốc lên.', 'một ngọn đồi hoặc núi dốc; một mái nhà dốc; một đường lên dốc; một gradient khí áp dốc'),
    ('be220f42-0bed-5476-8501-b5239a1e1a39', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'stream', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/stɹiːm/', 'https://api.dictionaryapi.dev/media/pronunciations/en/stream-us.mp3', 'A small river; a large creek; a body of moving water confined by banks.', 'He poured the milk in a thin stream from the jug to the glass.', 'Nature & Environment', 'dòng suối', 'Một con sông nhỏ; một con lạch lớn; một dòng nước chảy được giới hạn bởi các bờ.', 'Anh ấy rót sữa thành một dòng mỏng từ bình vào ly.'),
    ('82b9cbc0-32cb-540a-a7d7-a1afac8c81a5', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'zone', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/zəʊn/', 'audio/zone.mp3', 'Each of the five regions of the earth''s surface into which it was divided by climatic differences, namely the torrid zone (between the tropics), two temperate zones (between the tropics and the polar circles), and two frigid zones (within the polar circles).', 'Files in the Internet zone are blocked by default, as a security measure.', 'Nature & Environment', 'vùng, khu vực', 'Mỗi trong năm khu vực trên bề mặt trái đất được phân chia bởi sự khác biệt về khí hậu, cụ thể là vùng nhiệt đới (giữa các chí tuyến), hai vùng ôn đới (giữa chí tuyến và vùng cực).', 'Các tệp trong vùng Internet bị chặn theo mặc định, như một biện pháp bảo mật.'),
    ('92698e73-e20c-538a-bf3d-f1bae93b1bbd', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'bug', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/bʌɡ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/bug-us.mp3', 'An insect of the order Hemiptera (the “true bugs”).', 'These flies are a bother. I’ll get some bug spray and kill them.', 'Nature & Environment', 'con bọ', 'Một loài côn trùng thuộc bộ Cánh nửa (Hemiptera) (các ''con bọ thực sự'').', 'Những con ruồi này thật phiền phức. Tôi sẽ lấy bình xịt côn trùng và diệt chúng.'),
    ('1b413498-afb1-57bc-a9d9-e4ad1e82c5b3', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'cave', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/keɪv/', 'https://api.dictionaryapi.dev/media/pronunciations/en/cave-1-us.mp3', 'A large, naturally-occurring cavity formed underground or in the face of a cliff or a hillside.', 'We found a cave on the mountainside where we could take shelter.', 'Nature & Environment', 'hang động', 'Một khoang lớn hình thành tự nhiên dưới lòng đất hoặc trên mặt vách đá hoặc sườn đồi.', 'Chúng tôi tìm thấy một hang động trên sườn núi nơi chúng tôi có thể trú ẩn.'),
    ('a0c1d97e-df60-5a20-9772-1510379404f7', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'darkness', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈdɑːknəs/', 'audio/darkness.mp3', 'The state of being dark; lack of light.', 'The darkness of the room made it difficult to see.', 'Nature & Environment', 'bóng tối', 'Trạng thái tối tăm; thiếu ánh sáng.', 'Bóng tối của căn phòng khiến việc nhìn thấy trở nên khó khăn.'),
