    ('a9403c73-57c4-5bbe-bf6c-38ae85efe7e0', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'leaflet', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈliːflɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/leaflet-us.mp3', 'One of the components of a compound leaf.', 'The new leaflets at the end of the branch were a lighter shade of green than the mature leaves.', 'Nature & Environment', 'lá chét', 'Một trong những thành phần của một lá kép.', 'Những lá chét mới ở đầu cành có màu xanh nhạt hơn những lá trưởng thành.'),
    ('dfe2254b-f208-588f-9201-60f1efbe281a', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'rat', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ɹæt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/rat-uk.mp3', 'A medium-sized rodent belonging to the genus Rattus.', 'What a rat, leaving us stranded here!', 'Nature & Environment', 'con chuột', 'Một loài gặm nhấm cỡ trung bình thuộc chi Rattus.', 'Đồ đểu, bỏ mặc chúng tôi mắc kẹt ở đây!'),
    ('be4196bb-d2a6-584e-9d00-52607e6579b8', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'shore', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ʃɔː/', 'audio/shore.mp3', 'Land adjoining a non-flowing body of water, such as an ocean, lake or pond.', 'lake shore; bay shore; gulf shore; island shore; mainland shore; river shore; estuary shore; pond shore; sandy shore; rocky shore', 'Nature & Environment', 'bờ biển, bờ hồ', 'Vùng đất tiếp giáp với một vùng nước không chảy, chẳng hạn như đại dương, hồ hoặc ao.', 'bờ hồ; bờ vịnh; bờ vịnh; bờ đảo; bờ đất liền; bờ sông; bờ cửa sông; bờ ao; bờ cát; bờ đá'),
    ('d55b6255-a08a-5554-af6b-f6d7f14a838a', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'worm', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/wɜːm/', 'audio/worm.mp3', 'A generally tubular invertebrate of the annelid phylum; an earthworm.', 'Don''t try to run away, you little worm!', 'Nature & Environment', 'con giun', 'Một loài động vật không xương sống hình ống nói chung thuộc ngành Giun đốt; một con giun đất.', 'Đừng cố chạy trốn, đồ giun nhỏ bé!'),
    ('e7dde6c1-dd11-5063-9ea0-0f1d677d017b', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'forecast', 'B2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "v", "level": "B2"}]'::jsonb, '/ˈfɔːkɑːst/', 'audio/forecast.mp3', 'An estimation of a future condition.', 'to forecast a rise in prices', 'Weather & Climate', 'dự báo', 'Một ước tính về tình trạng trong tương lai.', 'dự báo giá cả tăng'),
    ('b006ac49-f02e-5bd3-a463-f064178a4f96', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'tropical', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, NULL, 'audio/tropical.mp3', 'A tropical plant.', 'tropical fruit', 'Nature & Environment', 'nhiệt đới', 'Một loài cây nhiệt đới.', 'trái cây nhiệt đới'),
    ('ec870e58-5bb9-5489-acc4-b22bc38e7218', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'warming', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, NULL, 'audio/warming.mp3', 'To make or keep warm.', 'My socks are warming by the fire.', 'Weather & Climate', 'sự ấm lên', 'Làm cho hoặc giữ ấm.', 'Tất của tôi đang được sưởi ấm bên lửa.'),
    ('78d43266-74ec-5837-ac62-190492e49463', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'prospect', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈpɹɒspɛkt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/prospect-uk-noun.mp3', 'The region which the eye overlooks at one time; view; scene; outlook.', NULL, 'Nature & Environment', 'viễn cảnh', 'Khu vực mà mắt có thể nhìn thấy trong một lần; tầm nhìn; cảnh quan; viễn cảnh.', NULL),
    ('46a04e0a-d266-5252-a723-11298dbf34e2', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'regional', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈɹiːdʒnəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/regional-au.mp3', 'An entity or event with scope limited to a single region.', NULL, 'Nature & Environment', 'thuộc khu vực', 'Một thực thể hoặc sự kiện với phạm vi giới hạn trong một khu vực duy nhất.', NULL),
    ('9b121489-7412-53e9-9bcb-c43ab4bc7ddc', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'wildlife', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈwaɪldlaɪf/', 'https://api.dictionaryapi.dev/media/pronunciations/en/wildlife-au.mp3', 'Animals, plants, and fungi, not normally domesticated, often to the exclusion of plants, fungi, fish, insects and other invertebrates, and microscopic plants and animals; hence:', NULL, 'Nature & Environment', 'động vật hoang dã', 'Động vật, thực vật và nấm, thường không được thuần hóa, thường loại trừ thực vật, nấm, cá, côn trùng và các động vật không xương sống khác, và thực vật và động vật vi mô; do đó:', NULL),
    ('c668b0da-bb3b-520e-9336-0d3777386001', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'agriculture', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈæɡɹɪˌkʌltʃə/', 'https://api.dictionaryapi.dev/media/pronunciations/en/agriculture-uk.mp3', 'The art or science of cultivating the ground, including the harvesting of crops, and the rearing and management of livestock', NULL, 'Nature & Environment', 'nông nghiệp', 'Nghệ thuật hoặc khoa học trồng trọt đất đai, bao gồm thu hoạch cây trồng, và chăn nuôi, quản lý gia súc', NULL),
    ('cfc98d11-fbc1-528a-810f-8dae312794d4', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'bat', 'B2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "v", "level": "C1"}]'::jsonb, '/bæt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/bat-au.mp3', 'Any of the flying mammals of the order Chiroptera, usually small and nocturnal, insectivorous or frugivorous.', NULL, 'Nature & Environment', 'con dơi', 'Bất kỳ loài động vật có vú biết bay nào thuộc bộ Dơi, thường nhỏ và sống về đêm, ăn côn trùng hoặc ăn quả.', NULL),
    ('b8549360-b436-5e5d-a43d-46412457b46d', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'cliff', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/klɪf/', 'https://api.dictionaryapi.dev/media/pronunciations/en/cliff-us.mp3', 'A vertical (or nearly vertical) rock face.', NULL, 'Nature & Environment', 'vách đá', 'Một mặt đá thẳng đứng (hoặc gần như thẳng đứng).', NULL),
    ('01c2eba0-11c8-59c3-a79a-ef6b47db5dc4', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'conservation', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˌkɑnsə(ɹ)ˈveɪʃən/', 'audio/conservation.mp3', 'The act of preserving, guarding, or protecting; the keeping (of a thing) in a safe or entire state; preservation.', NULL, 'Nature & Environment', 'bảo tồn', 'Hành động bảo vệ, gìn giữ hoặc bảo vệ; việc giữ (một thứ) trong trạng thái an toàn hoặc nguyên vẹn; sự bảo tồn.', NULL),
    ('7d8f95e0-0ac5-5de7-b167-66a4f9e6ea78', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'fossil', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈfɒsəl/', 'audio/fossil.mp3', 'The mineralized remains of an animal or plant.', NULL, 'Nature & Environment', 'hóa thạch', 'Phần còn lại đã hóa thạch của động vật hoặc thực vật.', NULL),
    ('943c1110-5723-5e8b-a9fa-bb5dec01f6e7', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'greenhouse', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈɡɹiːnˌhaʊs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/greenhouse-au.mp3', 'A building used to grow plants, particularly one with large glass windows or plastic sheeting to trap heat from sunlight even in intemperate seasons or climates.', NULL, 'Nature & Environment', 'nhà kính', 'Một tòa nhà dùng để trồng cây, đặc biệt là loại có cửa sổ kính lớn hoặc tấm phủ nhựa để giữ nhiệt từ ánh sáng mặt trời ngay cả trong những mùa hoặc khí hậu khắc nghiệt.', NULL),
    ('a7b90dd9-8a25-53bc-a90b-1c73487a407c', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'palm', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈpæm/', 'audio/palm.mp3', 'Any of various evergreen trees from the family Palmae or Arecaceae, which are mainly found in the tropics.', NULL, 'Nature & Environment', 'cây cọ', 'Bất kỳ loại cây thường xanh nào thuộc họ Palmae hoặc Arecaceae, chủ yếu được tìm thấy ở vùng nhiệt đới.', NULL),
    ('1f0e3152-7dc6-5218-9ba0-4a700fb9aeeb', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'rose', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ɹəʊz/', 'https://api.dictionaryapi.dev/media/pronunciations/en/rose-1-uk.mp3', 'A shrub of the genus Rosa, with red, pink, white or yellow flowers.', NULL, 'Nature & Environment', 'hoa hồng', 'Một loại cây bụi thuộc chi Rosa, với hoa màu đỏ, hồng, trắng hoặc vàng.', NULL),
    ('863578bd-fcbe-50fd-b43f-dd32ddc60886', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'sustainable', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/səˈsteɪnəbəl/', 'audio/sustainable.mp3', 'Able to be sustained.', NULL, 'Nature & Environment', 'bền vững', 'Có thể được duy trì.', NULL),
    ('71115503-34d4-5612-8dc4-260565e547f9', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'tsunami', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/suˈnæmi/', 'audio/tsunami.mp3', 'A very large and destructive wave, generally caused by a tremendous disturbance in the ocean, such as an undersea earthquake or volcanic eruption. Tsunami are usually a series of waves, or wave train.', NULL, 'Nature & Environment', 'sóng thần', 'Một cơn sóng rất lớn và tàn phá, thường do một sự xáo trộn khủng khiếp ở đại dương, như động đất dưới biển hoặc núi lửa phun trào. Sóng thần thường là một chuỗi các đợt sóng.', NULL),
    ('76ef7426-6d52-5f77-aa82-065f0d7a0460', 'bdf16d4b-702f-5b0d-82ed-e9ba47eb7fab', 'drought', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '[dɹʌʊt]', 'audio/drought.mp3', 'A period of unusually low rainfall, longer and more severe than a dry spell.', NULL, 'Weather & Climate', 'hạn hán', 'Một khoảng thời gian có lượng mưa thấp bất thường, kéo dài và nghiêm trọng hơn một đợt khô hạn.', NULL)
ON CONFLICT (desk_id, word) DO NOTHING;

