INSERT INTO flashcard
    (id, desk_id, word, cefr, pos_json, all_levels_json, ipa, audio_url,
     definition, example, topic, vietnamese, vi_definition, vi_example)
VALUES
    ('c472e7ab-73d8-564c-b133-5915abd4b30a', '2d043061-f0a8-5472-8e09-358e64b45037', 'broadcast', 'B2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B2"}, {"pos": "n", "level": "B2"}]'::jsonb, '/ˈbɹɑdkæst/', 'audio/broadcast.mp3', 'A transmission of a radio or television programme intended to be received by anyone with a receiver.', 'The DJ was feeling nervous before his first national broadcast.', 'Technology & Media', 'phát sóng', 'Một buổi phát sóng chương trình radio hoặc truyền hình nhằm mục đích được tiếp nhận bởi bất kỳ ai có máy thu.', 'DJ cảm thấy lo lắng trước buổi phát sóng toàn quốc đầu tiên của anh ấy.'),
    ('d391d319-d710-5cfc-894d-c7191d317310', '2d043061-f0a8-5472-8e09-358e64b45037', 'cable', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/keɪ.bl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/cable-us.mp3', '(material) A long object used to make a physical connection.', 'I tried to watch the movie last night but my cable was out.', 'Technology & Media', 'cáp', '(vật liệu) Một vật thể dài được sử dụng để tạo kết nối vật lý.', 'Tôi đã cố xem bộ phim tối qua nhưng cáp của tôi bị hỏng.'),
    ('4aa12847-5b7e-5eb7-8d24-6099bcf47d4d', '2d043061-f0a8-5472-8e09-358e64b45037', 'component', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/kʌmˈpoʊnənt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/component-us.mp3', 'A smaller, self-contained part of a larger entity. Often refers to a manufactured object that is part of a larger device.', 'A CPU is a component of a computer.', 'Technology & Media', 'thành phần', 'Một phần nhỏ hơn, độc lập của một thực thể lớn hơn. Thường đề cập đến một vật thể được sản xuất là một phần của một thiết bị lớn hơn.', 'CPU là một thành phần của máy tính.'),
    ('823600e4-beae-5c32-b09a-1f2ae15c723f', '2d043061-f0a8-5472-8e09-358e64b45037', 'disc', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/dɪsk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/disc-us.mp3', 'A thin, flat, circular plate or similar object.', 'A coin is a disc of metal.', 'Technology & Media', 'đĩa', 'Một tấm tròn, phẳng, mỏng hoặc vật thể tương tự.', 'Một đồng xu là một đĩa kim loại.'),
    ('0aedf86e-a6d4-5138-b334-695d7c8f7c23', '2d043061-f0a8-5472-8e09-358e64b45037', 'edit', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/ˈɛdɪt/', 'audio/edit.mp3', 'A change to the text of a document.', 'He edits the Chronicle.', 'Technology & Media', 'chỉnh sửa', 'Một thay đổi đối với văn bản của một tài liệu.', 'Anh ấy biên tập cho tờ Chronicle.'),
    ('abc32d05-f1b1-582a-b5fc-920fd8ee91e7', '2d043061-f0a8-5472-8e09-358e64b45037', 'flash', 'B2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "v", "level": "B2"}]'::jsonb, '/flæʃ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/flash-au.mp3', 'A device that produces a short flash of light to help illuminate a scene, mostly for night-time or indoors photography.', 'I just got my first commando flash.', 'Technology & Media', 'đèn flash', 'Một thiết bị tạo ra một tia sáng ngắn để giúp chiếu sáng cảnh, chủ yếu cho chụp ảnh ban đêm hoặc trong nhà.', 'Tôi vừa có chiếc đèn flash đầu tiên của mình.'),
    ('b77c6377-f4fc-5bcd-aee4-10eb7f2ed541', '2d043061-f0a8-5472-8e09-358e64b45037', 'generate', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/ˈdʒɛn.əɹ.eɪt/', 'audio/generate.mp3', 'To bring into being; give rise to.', 'The discussion generated an uproar.', 'Technology & Media', 'tạo ra', 'Mang vào sự tồn tại; tạo ra.', 'Cuộc thảo luận đã tạo ra một sự hỗn loạn.'),
    ('56722774-fdf1-5b9a-bdc6-7ff0f37c2dbb', '2d043061-f0a8-5472-8e09-358e64b45037', 'install', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/ɪnˈstɔːl/', 'audio/install.mp3', 'Installer. A software utility that installs an application.', 'After inserting the disk, you need to run the install.', 'Technology & Media', 'cài đặt', 'Trình cài đặt. Một tiện ích phần mềm cài đặt một ứng dụng.', 'Sau khi chèn đĩa, bạn cần chạy trình cài đặt.'),
    ('0175f9cc-0abe-52cc-ac3b-b010e7a33fd7', '2d043061-f0a8-5472-8e09-358e64b45037', 'interrupt', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/ˌɪntəˈɹʌpt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/interrupt-us-verb.mp3', 'An event that causes a computer or other device to temporarily cease what it was doing and attend to a condition.', 'The interrupt caused the packet handler routine to run.', 'Technology & Media', 'làm gián đoạn', 'Một sự kiện khiến máy tính hoặc thiết bị khác tạm thời ngừng những gì nó đang làm và xử lý một điều kiện.', 'Ngắt làm cho thủ tục xử lý gói tin chạy.'),
    ('83c334fb-f5b2-5222-b4a3-8a97a26c1f78', '2d043061-f0a8-5472-8e09-358e64b45037', 'monitor', 'B2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "v", "level": "B2"}]'::jsonb, '/ˈmɒnɨtə/', 'https://api.dictionaryapi.dev/media/pronunciations/en/monitor-uk.mp3', 'Someone who watches over something; a person in charge of something or someone.', 'The camp monitors look after the children during the night, when the teachers are asleep.', 'Technology & Media', 'màn hình, giám sát', 'Người giám sát điều gì đó; một người phụ trách điều gì đó hoặc ai đó.', 'Các giám thị trại chăm sóc bọn trẻ vào ban đêm, khi các giáo viên đang ngủ.'),
    ('9b0f6846-0b67-5961-afeb-6c926c8890e1', '2d043061-f0a8-5472-8e09-358e64b45037', 'motor', 'B2', '["n", "adj"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "adj", "level": "B2"}]'::jsonb, '/ˈməʊtə/', 'audio/motor.mp3', 'A machine or device that converts other energy forms into mechanical energy, or imparts motion.', 'Nice motor!', 'Technology & Media', 'động cơ', 'Một máy móc hoặc thiết bị chuyển đổi các dạng năng lượng khác thành năng lượng cơ học, hoặc truyền chuyển động.', 'Động cơ đẹp đấy!'),
    ('0bbb6a1e-49bd-53e8-8d67-0ea3d25b0717', '2d043061-f0a8-5472-8e09-358e64b45037', 'operate', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/ˈɒpəɹeɪt/', 'audio/operate.mp3', 'To perform a work or labour; to exert power or strength, physical or mechanical; to act.', 'to operate a machine', 'Technology & Media', 'vận hành', 'Để thực hiện một công việc hoặc lao động; để vận dụng sức mạnh hoặc sức lực, thể chất hoặc cơ khí; để hành động.', 'vận hành một máy móc'),
    ('1866c137-432a-593d-b023-6915e5433748', '2d043061-f0a8-5472-8e09-358e64b45037', 'rubber', 'B2', '["n", "adj"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "adj", "level": "B2"}]'::jsonb, '/ˈɹʌbə(ɹ)/', 'audio/rubber.mp3', 'Pliable material derived from the sap of the rubber tree; a hydrocarbon polymer of isoprene.', 'Jones toes the rubber and then fires to the plate.', 'Technology & Media', 'cao su', 'Vật liệu dẻo có nguồn gốc từ nhựa cây cao su; một polymer hydrocarbon của isoprene.', 'Jones chạm ngón chân vào vạch cao su và sau đó ném mạnh về phía home plate.'),
    ('ecd48b41-1ef7-546b-baca-c42e218e4984', '2d043061-f0a8-5472-8e09-358e64b45037', 'satellite', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈsætəlaɪt/', 'audio/satellite.mp3', 'A moon or other smaller body orbiting a larger one.', 'A spent upper stage is a derelict satellite.', 'Technology & Media', 'vệ tinh', 'Một mặt trăng hoặc thiên thể nhỏ hơn khác quay quanh một thiên thể lớn hơn.', 'Một tầng trên đã qua sử dụng là một vệ tinh bị bỏ hoang.'),
    ('2068cec1-c900-521d-8921-8c10c7f099c0', '2d043061-f0a8-5472-8e09-358e64b45037', 'sticky', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈstɪki/', 'https://api.dictionaryapi.dev/media/pronunciations/en/sticky-au.mp3', 'A sticky note, such as a post-it note.', 'Her desk is covered with yellow stickies.', 'Technology & Media', 'giấy ghi chú', 'Một mẩu giấy ghi chú dính, chẳng hạn như giấy ghi chú Post-it.', 'Bàn làm việc của cô ấy phủ đầy những mẩu giấy ghi chú màu vàng.'),
    ('1a37622f-3dcc-52b8-8747-794db77b932a', '2d043061-f0a8-5472-8e09-358e64b45037', 'tank', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/tæŋk/', 'https://api.dictionaryapi.dev/media/pronunciations/en/tank-au.mp3', 'A closed container for liquids or gases.', 'I burned three tanks of gas on the drive to New York.', 'Technology & Media', 'bể chứa, xe tăng', 'Một thùng chứa kín dành cho chất lỏng hoặc khí.', 'Tôi đã đốt hết ba bình xăng trong chuyến lái xe đến New York.'),
    ('0efcb9da-0970-54e0-b39f-33e69e9a5b6d', '2d043061-f0a8-5472-8e09-358e64b45037', 'virtual', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈvɵːtʃuəl/', 'audio/virtual.mp3', 'A virtual member function of a class.', 'In fact a defeat on the battlefield, Tet was a virtual victory for the North, owing to its effect on public opinion.', 'Technology & Media', 'ảo', 'Một hàm thành viên ảo của một lớp.', 'Trên thực tế là một thất bại trên chiến trường, Tết Mậu Thân lại là một chiến thắng ảo đối với miền Bắc, nhờ vào tác động của nó đối với dư luận.'),
    ('acfe6630-46ff-5a00-9bcf-a37861baa7f2', '2d043061-f0a8-5472-8e09-358e64b45037', 'wire', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/waɪə(ɹ)/', 'audio/wire.mp3', 'Metal formed into a thin, even thread, now usually by being drawn through a hole in a steel die.', 'This election is going to go right to the wire', 'Technology & Media', 'dây kim loại', 'Kim loại được tạo thành sợi mỏng, đều, thường bằng cách kéo qua một lỗ trong khuôn thép.', 'Cuộc bầu cử này sẽ đi đến phút chót.'),
    ('cf081b89-c65b-5080-8a9a-7155ff126c7b', '2d043061-f0a8-5472-8e09-358e64b45037', 'automatic', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˌɔːtəˈmætɪk/', 'audio/automatic.mp3', 'A car with automatic transmission.', 'I never learned to drive a stick. I can only drive an automatic.', 'Technology & Media', 'tự động', 'Một chiếc xe có hộp số tự động.', 'Tôi chưa bao giờ học lái xe số sàn. Tôi chỉ lái được xe số tự động.'),
    ('8f57310c-d9f0-5217-871d-1217828f2be2', '2d043061-f0a8-5472-8e09-358e64b45037', 'database', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈdeɪtəˌbeɪs/', 'audio/database.mp3', '(general) A collection of (usually) organized information in a regular structure, usually but not necessarily in a machine-readable format accessible by a computer.', 'I have a database of all my contacts in my personal organizer.', 'Technology & Media', 'cơ sở dữ liệu', '(Chung) Một bộ sưu tập thông tin (thường) được tổ chức trong một cấu trúc thông thường, thường nhưng không nhất thiết ở định dạng máy đọc được mà máy tính có thể truy cập.', 'Tôi có một cơ sở dữ liệu về tất cả các liên lạc của mình trong máy tổ chức cá nhân.'),
    ('6c99d5ce-49e1-5d31-b000-8cd0a68cea17', '2d043061-f0a8-5472-8e09-358e64b45037', 'delete', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/diˈliːt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/delete-us.mp3', 'A key that may be pressed to delete something (such as text or files) from a computer.', 'I lost the file when I accidentally hit delete.', 'Technology & Media', 'xóa', 'Một phím có thể được nhấn để xóa thứ gì đó (chẳng hạn như văn bản hoặc tệp) khỏi máy tính.', 'Tôi đã mất tệp khi vô tình nhấn xóa.'),
    ('6e55d4d1-9fbd-5797-83ca-dfd666844f88', '2d043061-f0a8-5472-8e09-358e64b45037', 'extension', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ɪkˈstɛnʃən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/extension-us.mp3', 'The act of extending; a stretching out; enlargement in length or breadth; an increase', 'Files with the .txt extension usually contain text.', 'Technology & Media', 'phần mở rộng, sự gia hạn', 'Hành động mở rộng; sự kéo dài ra; mở rộng về chiều dài hoặc chiều rộng; sự gia tăng', 'Các tệp có phần mở rộng .txt thường chứa văn bản.'),
    ('6d21daa9-c368-57a5-970a-c4d49fbc23b8', '2d043061-f0a8-5472-8e09-358e64b45037', 'format', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈfɔː(ɹ).mæt/', 'audio/format.mp3', 'The layout of a publication or document.', 'The radio station changed the format of its evening program.', 'Technology & Media', 'định dạng', 'Bố cục của một ấn phẩm hoặc tài liệu.', 'Đài phát thanh đã thay đổi định dạng chương trình buổi tối của họ.'),
    ('a12bcfd5-3668-53ec-a08a-5998f2acb3e4', '2d043061-f0a8-5472-8e09-358e64b45037', 'forum', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈfɔːɹəm/', 'audio/forum.mp3', 'A place for discussion.', 'Trish was an admin on three forums, and had no trouble at all when it came to moderating them.', 'Technology & Media', 'diễn đàn', 'Một nơi để thảo luận.', 'Trish là quản trị viên của ba diễn đàn, và không gặp chút khó khăn nào khi điều hành chúng.'),
    ('5e41aa05-f9fa-5dd1-ab04-a40a05817dc2', '2d043061-f0a8-5472-8e09-358e64b45037', 'graphic', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈɡɹæfɪk/', 'audio/graphic.mp3', 'A drawing or picture.', 'I''ve just played this new computer game: the graphics are amazing.', 'Technology & Media', 'đồ họa', 'Một bản vẽ hoặc hình ảnh.', 'Tôi vừa chơi trò chơi máy tính mới này: đồ họa thật tuyệt vời.'),
    ('a04e9f10-6097-56a4-a9da-aa31527c5f08', '2d043061-f0a8-5472-8e09-358e64b45037', 'graphics', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈɡɹæfɪks/', 'audio/graphics.mp3', 'The making of architectural or design drawings.', 'This game is really fun, but the graphics aren''t very good.', 'Technology & Media', 'đồ họa', 'Việc tạo ra các bản vẽ kiến trúc hoặc thiết kế.', 'Trò chơi này thực sự thú vị, nhưng đồ họa không tốt lắm.'),
    ('9eaadc5e-884c-50e5-8e6e-a34848db191c', '2d043061-f0a8-5472-8e09-358e64b45037', 'input', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈɪnpʊt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/input-uk.mp3', 'The act or process of putting in; infusion.', 'The user inputs his date of birth and the computer displays his age.', 'Technology & Media', 'đầu vào', 'Hành động hoặc quá trình đưa vào; sự truyền vào.', 'Người dùng nhập ngày sinh của anh ấy và máy tính hiển thị tuổi của anh ấy.'),
    ('8863f375-488d-520e-8aca-4b408b6b7371', '2d043061-f0a8-5472-8e09-358e64b45037', 'insert', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/ɪnˈsɜːt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/insert-uk.mp3', 'An image inserted into text.', 'This software can print compact disc inserts if you have the right size of paper.', 'Technology & Media', 'chèn', 'Một hình ảnh được chèn vào văn bản.', 'Phần mềm này có thể in các tờ chèn đĩa CD nếu bạn có đúng cỡ giấy.'),
    ('55c7fa6e-02d5-5987-9a0a-da8ea74ffbc9', '2d043061-f0a8-5472-8e09-358e64b45037', 'programming', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈpɹəʊɡɹəmɪŋ/', 'audio/programming.mp3', 'To enter a program or other instructions into (a computer or other electronic device) to instruct it to do a particular task.', 'He programmed the DVR to record his favorite show.', 'Technology & Media', 'lập trình', 'Nhập một chương trình hoặc các hướng dẫn khác vào (máy tính hoặc thiết bị điện tử khác) để hướng dẫn nó thực hiện một nhiệm vụ cụ thể.', 'Anh ấy lập trình DVR để ghi lại chương trình yêu thích của mình.'),
    ('24204722-139b-5b6d-88e1-140f5ccb8b07', '2d043061-f0a8-5472-8e09-358e64b45037', 'restore', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/ɹɪˈstɔː/', 'audio/restore.mp3', 'The act of recovering data or a system from a backup.', 'We backed up the data successfully, but the restore failed.', 'Technology & Media', 'khôi phục', 'Hành động khôi phục dữ liệu hoặc hệ thống từ bản sao lưu.', 'Chúng tôi đã sao lưu dữ liệu thành công, nhưng việc khôi phục thất bại.'),
    ('f359f6ea-4332-563f-a4a0-7c2a84a899ca', '2d043061-f0a8-5472-8e09-358e64b45037', 'accompany', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/ə.ˈkʌm.pə.ni/', 'https://api.dictionaryapi.dev/media/pronunciations/en/accompany-us.mp3', 'To go with or attend as a companion or associate; to keep company with; to go along with.', 'Geoffrey accompanied the group on their pilgrimage.', 'Travel & Transport', 'đi cùng', 'Đi cùng hoặc tham dự với tư cách bạn đồng hành hoặc liên kết; đi cùng; đi theo.', 'Geoffrey đã đi cùng nhóm trong chuyến hành hương của họ.'),
    ('8dd1767b-8fce-515f-a9d2-07a96d5fa23c', '2d043061-f0a8-5472-8e09-358e64b45037', 'crash', 'B2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "v", "level": "B2"}]'::jsonb, '/kɹæʃ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/crash-us.mp3', 'A sudden, intense, loud sound, as made for example by cymbals.', 'After the lightning came the crash of thunder.', 'Travel & Transport', 'va chạm', 'Một âm thanh lớn, đột ngột, dữ dội, như được tạo ra chẳng hạn bởi chũm chọe.', 'Sau tia chớp là tiếng sấm vang rền.'),
    ('457866bc-8ea8-5b66-8cbe-cbcb84ef8333', '2d043061-f0a8-5472-8e09-358e64b45037', 'reserve', 'B2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "v", "level": "B2"}]'::jsonb, '/ɹɪˈzɜːv/', 'audio/reserve.mp3', '(behaviour) Restriction.', 'We reserve the right to make modifications.', 'Travel & Transport', 'dự trữ', '(hành vi) Sự hạn chế.', 'Chúng tôi bảo lưu quyền thực hiện các sửa đổi.'),
    ('6f628a18-3662-538d-a82d-e5e5bda8c54c', '2d043061-f0a8-5472-8e09-358e64b45037', 'resort', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ɹɨˈzɔ(ɹ)t/', 'https://api.dictionaryapi.dev/media/pronunciations/en/resort-1-us.mp3', 'A place where people go for recreation, especially one with facilities such as lodgings, entertainment, and a relaxing environment.', 'to have resort to violence', 'Travel & Transport', 'khu nghỉ dưỡng', 'Một nơi mọi người đến để giải trí, đặc biệt là nơi có các tiện nghi như chỗ ở, giải trí và môi trường thư giãn.', 'phải dùng đến bạo lực'),
    ('39a86729-973c-5c7e-af5b-25f6a75ccf7a', '2d043061-f0a8-5472-8e09-358e64b45037', 'booking', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈbʊkɪŋ/', 'audio/booking.mp3', 'To reserve (something) for future use.', 'I can book tickets for the concert next week.', 'Travel & Transport', 'đặt chỗ', 'Để giữ chỗ (một thứ gì đó) cho việc sử dụng trong tương lai.', 'Tôi có thể đặt vé cho buổi hòa nhạc tuần tới.'),
    ('450df1b1-9da8-5909-9382-6784802a3672', '2d043061-f0a8-5472-8e09-358e64b45037', 'cruise', 'B2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "v", "level": "B2"}]'::jsonb, '/kɹuːz/', 'https://api.dictionaryapi.dev/media/pronunciations/en/cruise-uk.mp3', 'A sea or lake voyage, especially one taken for pleasure.', 'Germany cruised to a World Cup victory over the short-handed Australians.', 'Travel & Transport', 'chuyến du thuyền / đi du thuyền', 'Một chuyến đi biển hoặc hồ, đặc biệt là chuyến đi để giải trí.', 'Đức đã dễ dàng giành chiến thắng tại World Cup trước đội Úc thiếu người.'),
    ('37a55aca-a70d-5178-b802-2cf44edfe6ae', '2d043061-f0a8-5472-8e09-358e64b45037', 'depart', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/dɪˈpɑːt/', 'audio/depart.mp3', 'Division; separation, as of compound substances.', 'His latest statements seemed to depart from party policy somewhat.', 'Travel & Transport', 'khởi hành, rời đi', 'Sự phân chia; tách biệt, như của các chất hợp chất.', 'Những tuyên bố mới nhất của ông dường như hơi đi chệch khỏi chính sách của đảng.'),
    ('fe1e6559-07ca-50b6-b332-a50a4e7cc57a', '2d043061-f0a8-5472-8e09-358e64b45037', 'exit', 'B2', '["n", "v"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "v", "level": "C1"}]'::jsonb, '/ˈɛksɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/exit-uk.mp3', 'An act of going out or going away, or leaving; a departure.', 'He made his exit at the opportune time.', 'Travel & Transport', 'lối ra', 'Hành động đi ra hoặc đi khỏi, hoặc rời đi; một sự khởi hành.', 'Anh ấy đã rời đi vào thời điểm thích hợp.'),
    ('d814132d-fd72-598b-9453-ca3ef263ec5b', '2d043061-f0a8-5472-8e09-358e64b45037', 'harbour', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈhɑɹbəɹ/', 'audio/harbour.mp3', 'Any place of shelter.', 'The neighborhood is a well-known harbor for petty thieves.', 'Travel & Transport', 'bến cảng', 'Bất kỳ nơi trú ẩn nào.', 'Khu phố này là một nơi trú ẩn nổi tiếng của bọn trộm vặt.'),
    ('8d937b48-893c-52b9-b40a-102f0bc20da8', '2d043061-f0a8-5472-8e09-358e64b45037', 'jet', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/dʒɛt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/jet-au.mp3', 'A collimated stream, spurt or flow of liquid or gas from a pressurized container, an engine, etc.', 'Farmers may either dip or jet sheep with chemicals.', 'Travel & Transport', 'máy bay phản lực', 'Một dòng chất lỏng hoặc khí được định hướng, phun ra hoặc chảy từ bình chứa có áp suất, động cơ, v.v.', 'Nông dân có thể nhúng hoặc phun hóa chất lên cừu.'),
    ('5edd8bbd-2a98-5095-9010-962053c5ca4b', '2d043061-f0a8-5472-8e09-358e64b45037', 'landing', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈlændɪŋ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/landing-us.mp3', 'To descend to a surface, especially from the air.', 'The plane is about to land.', 'Travel & Transport', 'hạ cánh', 'Hạ xuống một bề mặt, đặc biệt là từ trên không.', 'Máy bay sắp hạ cánh.'),
    ('d3c841df-a2ff-5856-ba6c-be67b1e95e3d', '2d043061-f0a8-5472-8e09-358e64b45037', 'lane', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/leɪn/', 'audio/lane.mp3', '(used in street names) A road, street, or similar thoroughfare.', 'And it''s Uncle Mo in front by two as they come to the top of the lane.', 'Travel & Transport', 'làn đường', '(dùng trong tên đường) Một con đường, phố hoặc lối đi tương tự.', 'Và chú Mo đang dẫn trước hai thân người khi họ đến đầu làn đường.'),
    ('f673c420-7a08-525f-9bf5-2c2dd8a8af5b', '2d043061-f0a8-5472-8e09-358e64b45037', 'litter', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈlɪtə(ɹ)/', 'audio/litter.mp3', 'A platform mounted on two shafts, or a more elaborate construction, designed to be carried by two (or more) people to transport one (in luxury models sometimes more) third person(s) or (occasionally in the elaborate version) a cargo, such as a religious idol.', 'sleep in the litter', 'Travel & Transport', 'kiệu', 'Một bệ được gắn trên hai cây đòn, hoặc một cấu trúc phức tạp hơn, được thiết kế để được khiêng bởi hai (hoặc nhiều) người để chuyên chở một (trong các mẫu sang trọng đôi khi nhiều hơn) người thứ ba hoặc (đôi khi) vật.', 'ngủ trên kiệu'),
    ('fb99d8f5-6471-5466-83fb-2c733c44992a', '2d043061-f0a8-5472-8e09-358e64b45037', 'overseas', 'B2', '["adv", "adj"]'::jsonb, '[{"pos": "adv", "level": "B2"}, {"pos": "adj", "level": "B2"}]'::jsonb, '/ˌəʊvəˈsiːz/', 'audio/overseas.mp3', 'Abroad.', 'Overseas branches of the company are doing well.', 'Travel & Transport', 'hải ngoại', 'Ở nước ngoài.', 'Các chi nhánh ở nước ngoài của công ty đang hoạt động tốt.'),
    ('9093b142-78f0-57f7-a446-7f9a7482e134', '2d043061-f0a8-5472-8e09-358e64b45037', 'rail', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ɹeɪl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/rail-us.mp3', 'A horizontal bar extending between supports and used for support or as a barrier; a railing.', 'We travelled to the seaside by rail.', 'Travel & Transport', 'đường sắt', 'Một thanh ngang kéo dài giữa các giá đỡ và được sử dụng để hỗ trợ hoặc làm rào chắn; một lan can.', 'Chúng tôi đi đến bờ biển bằng đường sắt.'),
    ('dd3d69cc-4d63-5747-b3a1-75f6b0fc1e7f', '2d043061-f0a8-5472-8e09-358e64b45037', 'transportation', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/tɹænspɔːˈteɪʃən/', 'audio/transportation.mp3', 'The act of transporting, or the state of being transported; conveyance, often of people, goods etc.', 'We have to get people out of their cars and encourage them to use alternative forms of transportation.', 'Travel & Transport', 'vận tải', 'Hành động vận chuyển, hoặc trạng thái được vận chuyển; sự chuyên chở, thường là người, hàng hóa, v.v.', 'Chúng ta phải đưa mọi người ra khỏi xe hơi và khuyến khích họ sử dụng các hình thức vận tải thay thế.'),
    ('bae27a38-aee6-5c4f-8b85-5dd42435a59a', '2d043061-f0a8-5472-8e09-358e64b45037', 'wander', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/ˈwɒndə/', 'audio/wander.mp3', 'The act or instance of wandering.', 'to go for a wander in the park', 'Travel & Transport', 'lang thang', 'Hành động hoặc trường hợp lang thang.', 'đi lang thang trong công viên'),
    ('1f59cd90-7819-5089-a5d5-f0175d56305e', '2d043061-f0a8-5472-8e09-358e64b45037', 'debt', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/dɛt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/debt-us.mp3', 'An action, state of mind, or object one has an obligation to perform for another, adopt toward another, or give to another.', 'I am in your debt.', 'Shopping & Money', 'nợ', 'Một hành động, trạng thái tâm trí, hoặc đối tượng mà một người có nghĩa vụ phải thực hiện cho người khác, áp dụng đối với người khác, hoặc trao cho người khác.', 'Tôi mắc nợ anh.'),
    ('7b060306-f057-527e-87f8-7436457409f7', '2d043061-f0a8-5472-8e09-358e64b45037', 'delivery', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/dɪˈlɪv(ə)ɹi/', 'https://api.dictionaryapi.dev/media/pronunciations/en/delivery-au.mp3', 'The act of conveying something.', 'The delivery was completed by four.', 'Shopping & Money', 'sự giao hàng', 'Hành động chuyển giao một cái gì đó.', 'Việc giao hàng đã hoàn thành lúc bốn giờ.'),
    ('b30146aa-7fc0-5afe-8767-c3e1894a8e57', '2d043061-f0a8-5472-8e09-358e64b45037', 'expense', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ɪkˈspɛns/', 'https://api.dictionaryapi.dev/media/pronunciations/en/expense-us.mp3', 'A spending or consuming, often a disbursement of funds.', 'Buying the car was a big expense, but will be worth it in the long run.', 'Shopping & Money', 'chi phí', 'Việc chi tiêu hoặc tiêu dùng, thường là một khoản chi tiêu tiền bạc.', 'Mua chiếc xe là một khoản chi phí lớn, nhưng sẽ đáng giá về lâu dài.')
