INSERT INTO flashcard
    (id, desk_id, word, cefr, pos_json, all_levels_json, ipa, audio_url,
     definition, example, topic, vietnamese, vi_definition, vi_example)
VALUES
    ('ac7d2960-dba5-5bef-9074-67f38546024e', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'annual', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈæn.ju.əl/', 'audio/annual.mp3', 'An annual publication; a book, periodical, journal, report, comic book, yearbook, etc., which is published serially once a year, which may or may not be in addition to regular weekly or monthly publication.', 'I read the magazine, but I usually don''t purchase the annuals.', 'Time & Daily Routine', 'hàng năm', 'Một ấn phẩm hàng năm; một cuốn sách, tạp chí định kỳ, báo, báo cáo, truyện tranh, niên giám, v.v., được xuất bản hàng loạt mỗi năm một lần, có thể hoặc không ngoài các ấn phẩm hàng tuần hoặc hàng tháng thông thường.', 'Tôi đọc tạp chí, nhưng tôi thường không mua các ấn phẩm hàng năm.'),
    ('ca5dbde1-0818-5ad7-acca-a855ee94759c', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'constantly', 'B2', '["adv"]'::jsonb, '[{"pos": "adv", "level": "B2"}]'::jsonb, '/ˈkɒnstəntli/', 'audio/constantly.mp3', 'With steadfastness; with resolve; in loyalty, faithfully.', 'I find that I am constantly reminding you to feed your pets.', 'Time & Daily Routine', 'liên tục', 'Một cách kiên định; với sự quyết tâm; trong lòng trung thành, một cách trung thành.', 'Tôi thấy rằng mình liên tục nhắc nhở bạn cho thú cưng ăn.'),
    ('6a3d3cda-0e65-5374-b155-90b39dd58884', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'delay', 'B2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B2"}, {"pos": "n", "level": "B2"}]'::jsonb, '/dɪˈleɪ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/delay-1-us.mp3', 'A period of time before an event occurs; the act of delaying; procrastination; lingering inactivity.', 'the delay before the echo of a sound', 'Time & Daily Routine', 'trì hoãn', 'Một khoảng thời gian trước khi một sự kiện xảy ra; hành động trì hoãn; sự trì hoãn; hoạt động kéo dài.', 'độ trễ trước tiếng vang của âm thanh'),
    ('2ca8e1de-d896-52da-9bb5-351dbbaec983', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'rapidly', 'B2', '["adv"]'::jsonb, '[{"pos": "adv", "level": "B2"}]'::jsonb, '/ˈɹæpɪdli/', 'https://api.dictionaryapi.dev/media/pronunciations/en/rapidly-us.mp3', 'With speed; in a rapid manner.', 'She packed her case rapidly and hurried out.', 'Time & Daily Routine', 'một cách nhanh chóng', 'Với tốc độ; một cách nhanh chóng.', 'Cô ấy nhanh chóng thu dọn vali và vội vã ra ngoài.'),
    ('7dcf6e57-6522-5def-bcbf-daf840e86df7', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'duration', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/djʊˈɹeɪʃn̩/', 'audio/duration.mp3', 'An amount of time or a particular time interval.', 'Rationing will last at least for the duration.', 'Time & Daily Routine', 'thời lượng', 'Một khoảng thời gian hoặc một khoảng thời gian cụ thể.', 'Việc phân phối định lượng sẽ kéo dài ít nhất trong suốt thời gian đó.'),
    ('084ffddf-1f4c-53fe-950b-fe2042c387c4', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'frequent', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈfɹiː.kwənt/', 'audio/frequent.mp3', 'Done or occurring often; common.', 'I am a frequent visitor to that city.', 'Time & Daily Routine', 'thường xuyên', 'Được thực hiện hoặc xảy ra thường xuyên; phổ biến.', 'Tôi là một khách thường xuyên đến thành phố đó.'),
    ('279bcf89-37a7-50da-bb59-ada156a72d89', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'instant', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈɪnstənt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/instant-us.mp3', 'A very short period of time; a moment.', 'She paused for only an instant, which was just enough time for John to change the subject.', 'Time & Daily Routine', 'khoảnh khắc', 'Một khoảng thời gian rất ngắn; một chốc lát.', 'Cô ấy chỉ dừng lại một khoảnh khắc, vừa đủ thời gian để John chuyển chủ đề.'),
    ('539d99ee-ec6a-5041-ba67-c1066f33d8f9', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'instantly', 'B2', '["adv"]'::jsonb, '[{"pos": "adv", "level": "B2"}]'::jsonb, '/ˈɪnstəntli/', 'audio/instantly.mp3', 'At once; without delay.', 'When the neighbours'' dog barked, ours instantly replied with a howl.', 'Time & Daily Routine', 'ngay lập tức', 'Ngay lập tức; không chậm trễ.', 'Khi con chó của hàng xóm sủa, con chó của chúng tôi ngay lập tức đáp lại bằng một tiếng hú.'),
    ('894770e2-ab03-5fe7-a63c-3e439cd1e449', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'interval', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈɪntəvəl/', 'audio/interval.mp3', 'A distance in space.', 'the interval between contractions during childbirth', 'Time & Daily Routine', 'khoảng thời gian', 'Một khoảng cách trong không gian.', 'khoảng thời gian giữa các cơn co thắt trong khi sinh con'),
    ('212989eb-c0fa-503c-9735-7903858cb294', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'lifetime', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈlaɪftaɪm/', 'https://api.dictionaryapi.dev/media/pronunciations/en/lifetime-us.mp3', 'The duration of the life of someone or something.', 'I''ve been waiting a lifetime for a train.', 'Time & Daily Routine', 'cả đời', 'Khoảng thời gian tồn tại của ai đó hoặc cái gì đó.', 'Tôi đã chờ cả đời cho một chuyến tàu.'),
    ('c7c31188-c9ed-5cc8-87cf-5772c9306af3', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'newly', 'B2', '["adv"]'::jsonb, '[{"pos": "adv", "level": "B2"}]'::jsonb, '/ˈnjuːli/', 'audio/newly.mp3', 'Very recently; in the immediate past.', 'She smelled the newly budding flowers.', 'Time & Daily Routine', 'mới đây, vừa mới', 'Rất gần đây; trong quá khứ gần.', 'Cô ấy ngửi thấy mùi những bông hoa mới chớm nở.'),
    ('e5aa42ef-6704-5364-a1b6-d3b3f98c5d96', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'shortly', 'B2', '["adv"]'::jsonb, '[{"pos": "adv", "level": "B2"}]'::jsonb, '/ʃɔːɹtli/', 'https://api.dictionaryapi.dev/media/pronunciations/en/shortly-us.mp3', 'In a short or brief time or manner; quickly.', 'Ideas are generally expressed more shortly in verse than in prose', 'Time & Daily Routine', 'ngay sau đó, sớm', 'Trong một thời gian hoặc cách thức ngắn hoặc ngắn gọn; một cách nhanh chóng.', 'Ý tưởng thường được diễn đạt ngắn gọn hơn trong thơ so với văn xuôi'),
    ('93863d58-f2b8-58bc-8962-80825d521367', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'sometime', 'B2', '["adv"]'::jsonb, '[{"pos": "adv", "level": "B2"}]'::jsonb, '/ˈsʌmˌtaɪm/', 'audio/sometime.mp3', 'Former, erstwhile; at some previous time.', 'my sometime friend and mentor', 'Time & Daily Routine', 'trước đây, đôi khi', 'Trước đây, trước kia; tại một thời điểm nào đó trước đây.', 'người bạn và người cố vấn trước đây của tôi'),
    ('9b90e512-e624-5c2d-ba6d-d8b4b3a07e44', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'subsequent', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈsʌbsəkwənt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/subsequent-us.mp3', 'Following in time; coming or being after something else at any time, indefinitely.', 'Growth was dampened by a softening of the global economy in 2001, but picked up in the subsequent years due to strong growth in China.', 'Time & Daily Routine', 'tiếp theo', 'Theo sau về thời gian; đến hoặc xảy ra sau một thứ khác bất cứ lúc nào, không xác định.', 'Tăng trưởng bị hạn chế bởi sự suy yếu của nền kinh tế toàn cầu vào năm 2001, nhưng đã tăng trở lại trong những năm tiếp theo nhờ tăng trưởng mạnh ở Trung Quốc.'),
    ('de343484-f2d3-5495-a1a1-c5ad02a68313', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'timing', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈtaɪmɪŋ/', 'audio/timing.mp3', 'To measure or record the time, duration, or rate of.', 'I used a stopwatch to time myself running around the block.', 'Time & Daily Routine', 'thời điểm', 'Để đo lường hoặc ghi lại thời gian, thời lượng hoặc tốc độ của.', 'Tôi đã dùng đồng hồ bấm giờ để tính thời gian mình chạy quanh khu nhà.'),
    ('147ac88d-546f-5a5c-8a5c-2953364b4791', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'urgent', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/ˈɜːdʒənt/', 'audio/urgent.mp3', 'Requiring immediate attention.', 'An urgent appeal was sent out for assistance.', 'Time & Daily Routine', 'khẩn cấp', 'Đòi hỏi sự chú ý ngay lập tức.', 'Một lời kêu gọi khẩn cấp đã được gửi đi để xin hỗ trợ.'),
    ('f90ca5b3-c2e3-534c-9cf0-d338560e3aba', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'weekly', 'B2', '["adj"]'::jsonb, '[{"pos": "adj", "level": "B2"}]'::jsonb, '/wiːk.li/', 'https://api.dictionaryapi.dev/media/pronunciations/en/weekly-us.mp3', 'A publication that is published once a week.', 'He''s going for his weekly check-up at the hospital.', 'Time & Daily Routine', 'hàng tuần', 'Một ấn phẩm được xuất bản mỗi tuần một lần.', 'Anh ấy đang đi kiểm tra sức khỏe hàng tuần tại bệnh viện.'),
    ('30e357b1-58ca-50c0-be27-0c5d9c9827a1', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'bet', 'B2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B2"}, {"pos": "n", "level": "B2"}]'::jsonb, '/ˈbɛt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/bet-us.mp3', 'A wager, an agreement between two parties that a stake (usually money) will be paid by the loser to the winner (the winner being the one who correctly forecast the outcome of an event).', 'Dylan owes Fletcher $30 from an unsuccessful bet.', 'Sports & Hobbies', 'cá cược', 'Một vụ cá cược, một thỏa thuận giữa hai bên rằng một khoản tiền (thường là tiền) sẽ được người thua trả cho người thắng (người thắng là người dự đoán đúng kết quả của một sự kiện).', 'Dylan nợ Fletcher 30 đô la từ một vụ cá cược thất bại.'),
    ('956d5845-6cde-532d-a64a-848fb2a6b8a0', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'defeat', 'B2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B2"}, {"pos": "n", "level": "B2"}]'::jsonb, '/dɪˈfiːt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/defeat-us.mp3', 'To overcome in battle or contest.', 'Wellington defeated Napoleon at Waterloo.', 'Sports & Hobbies', 'đánh bại', 'Chiến thắng trong trận chiến hoặc cuộc thi.', 'Wellington đánh bại Napoleon tại Waterloo.'),
    ('dc3cfe8f-450c-51fc-bda2-1ed20e918838', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'float', 'B2', '["v"]'::jsonb, '[{"pos": "v", "level": "B2"}]'::jsonb, '/fləʊt/', 'audio/float.mp3', 'A buoyant device used to support something in water or another liquid.', 'Attach the float and the weight to the fishing line, above the hook.', 'Sports & Hobbies', 'phao', 'Một thiết bị nổi được sử dụng để hỗ trợ thứ gì đó trong nước hoặc chất lỏng khác.', 'Gắn phao và quả nặng vào dây câu, phía trên lưỡi câu.'),
    ('7eb7c565-b679-5087-897a-9e3d8614a82f', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'league', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/liːɡ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/league-us.mp3', 'A group or association of cooperating members.', 'the League of Nations', 'Sports & Hobbies', 'liên đoàn, giải đấu', 'Một nhóm hoặc hiệp hội của các thành viên hợp tác.', 'Hội Quốc Liên'),
    ('5c7f6a9e-566e-5c39-8876-ee8e0b78c7f7', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'opponent', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ɒpəʊnənt/', 'audio/opponent.mp3', 'One who opposes another; one who works or takes a position against someone or something; one who attempts to stop the progress of someone or something.', 'During the crackdown, many opponents of the regime were arrested.', 'Sports & Hobbies', 'đối thủ', 'Người chống lại người khác; người làm việc hoặc đứng về phía chống lại ai đó hoặc điều gì đó; người cố gắng ngăn chặn sự tiến bộ của ai đó hoặc điều gì đó.', 'Trong cuộc đàn áp, nhiều đối thủ của chế độ đã bị bắt.'),
    ('7a600a3c-d5b3-569a-9364-9d5eaae21ec2', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'shooting', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈʃuːtɪŋ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/shooting-uk.mp3', 'To launch a projectile.', 'The land shoots into a promontory.', 'Sports & Hobbies', 'bắn súng', 'Phóng một vật thể.', 'Vùng đất nhô ra thành một mũi đất.'),
    ('29a4575c-582f-585c-a1c9-114894726d92', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'shot', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ʃɒt/', 'audio/shot.mp3', 'To launch a projectile.', 'The land shoots into a promontory.', 'Sports & Hobbies', 'phát bắn', 'Phóng một vật thể.', 'Vùng đất nhô ra thành một mũi đất.'),
    ('4c544be0-481f-50c7-b48e-eb6c77f05c1a', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'slide', 'B2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B2"}, {"pos": "n", "level": "B2"}]'::jsonb, '/slaɪd/', 'https://api.dictionaryapi.dev/media/pronunciations/en/slide-us.mp3', 'An item of play equipment that children can climb up and then slide down again.', 'The long, red slide was great fun for the kids.', 'Sports & Hobbies', 'cầu trượt/trượt', 'Một món đồ chơi mà trẻ em có thể trèo lên và sau đó trượt xuống.', 'Cầu trượt dài màu đỏ rất vui đối với lũ trẻ.'),
    ('b93bd714-a2bd-5fe0-a6f9-93a35eee9027', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'stretch', 'B2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B2"}, {"pos": "n", "level": "B2"}]'::jsonb, '/stɹɛtʃ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/stretch-us.mp3', 'An act of stretching.', 'I was right in the middle of a stretch when the phone rang.', 'Sports & Hobbies', 'kéo giãn, duỗi', 'Một hành động kéo giãn.', 'Tôi đang ở ngay giữa một động tác duỗi người thì điện thoại reo.'),
    ('94f15178-e0d7-5196-af4a-1fdf7300f40c', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'strike', 'B2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B2"}, {"pos": "n", "level": "B2"}]'::jsonb, '/stɹaɪk/', 'audio/strike.mp3', 'A status resulting from a batter swinging and missing a pitch, or not swinging at a pitch when the ball goes in the strike zone, or hitting a foul ball that is not caught.', 'Thus hand strikes now include single knuckle strikes, knife hand strikes, finger strikes, ridge hand strikes etc., and leg strikes include front kicks, knee strikes, axe kicks, ...', 'Sports & Hobbies', 'cú đánh, đình công', 'Một tình trạng xảy ra khi người đánh bóng vung gậy và trượt một quả ném, hoặc không vung gậy khi bóng đi vào khu vực strike, hoặc đánh một quả phạm lỗi không bắt được.', 'Do đó, các cú đánh tay bây giờ bao gồm các cú đánh bằng đốt ngón tay, cú đánh bằng cạnh tay, cú đánh bằng ngón tay, cú đánh bằng sống tay, v.v., và các cú đánh chân bao gồm đá trước, đánh bằng đầu gối, đá rìu, ...'),
    ('3f6c6233-5d9e-5be4-b185-5e46a4bb5fb0', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'victory', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈvɪkt(ə)ɹi/', 'https://api.dictionaryapi.dev/media/pronunciations/en/victory-us.mp3', 'An instance of having won a competition or battle or succeeded in an effort.', 'It was a great victory on the battlefield.', 'Sports & Hobbies', 'chiến thắng', 'Một trường hợp đã giành chiến thắng trong một cuộc thi hoặc trận chiến hoặc thành công trong một nỗ lực.', 'Đó là một chiến thắng vĩ đại trên chiến trường.'),
    ('5da11517-362f-5fd6-b5d4-a1bbf88f2d8b', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'arrow', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈæɹ.əʊ/', 'audio/arrow.mp3', 'A projectile consisting of a shaft, a point and a tail with stabilizing fins that is shot from a bow.', 'Arrow left until you reach the start of the text you want to delete.', 'Sports & Hobbies', 'mũi tên', 'Một vật thể được bắn ra gồm thân, đầu nhọn và đuôi có cánh ổn định được bắn từ cung.', 'Nhấn mũi tên trái cho đến khi bạn đến đầu đoạn văn bản muốn xóa.'),
    ('fc61a1b9-cdac-5de7-9805-a8210a61fc91', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'championship', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈtʃæmpi.ənʃɪp/', 'audio/championship.mp3', 'A competition to determine a champion, especially the final of a series of competitions.', 'His championship of civil rights eventually bore fruit.', 'Sports & Hobbies', 'chức vô địch', 'Một cuộc thi để xác định nhà vô địch, đặc biệt là vòng chung kết của một loạt các cuộc thi.', 'Sự ủng hộ của ông cho quyền công dân cuối cùng đã đơm hoa kết trái.'),
    ('4b0f8017-cf32-5133-8dc9-7cffb6260edd', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'chase', 'B2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B2"}, {"pos": "n", "level": "B2"}]'::jsonb, '/tʃeɪs/', 'https://api.dictionaryapi.dev/media/pronunciations/en/chase-au.mp3', 'The act of one who chases another; a pursuit.', 'I need something to chase this shot with.', 'Sports & Hobbies', 'đuổi theo, săn đuổi', 'Hành động của một người đuổi theo người khác; một cuộc truy đuổi.', 'Tôi cần thứ gì đó để uống chung với ly rượu này.'),
    ('ec7c7f7b-4bf3-5189-8af3-e96db1584198', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'dive', 'B2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B2"}, {"pos": "n", "level": "B2"}]'::jsonb, '/ˈdaɪv/', 'https://api.dictionaryapi.dev/media/pronunciations/en/dive-1-us.mp3', 'A jump or plunge into water.', 'the dive of a hawk after prey', 'Sports & Hobbies', 'lặn, lao xuống', 'Một cú nhảy hoặc lao xuống nước.', 'cú lao xuống của một con diều hâu sau con mồi'),
    ('b8bef2ea-74dd-582a-9a3a-d096c5bbf2e3', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'gaming', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈɡeɪmɪŋ/', 'audio/gaming.mp3', 'To gamble.', 'We''ll bury them in paperwork, and game the system.', 'Sports & Hobbies', 'chơi game', 'Để đánh bạc.', 'Chúng tôi sẽ chôn vùi họ trong giấy tờ, và lách luật.'),
    ('900e3e59-00d1-5dd2-a6a5-5f987428b0b4', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'kit', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/kɪt/', 'https://api.dictionaryapi.dev/media/pronunciations/en/kit-us.mp3', 'A circular wooden vessel, made of hooped staves.', '1961 18 Jan, Guardian (cited after OED):', 'Sports & Hobbies', 'bộ dụng cụ', 'Một vật đựng bằng gỗ hình tròn, được làm từ các thanh gỗ có đai.', '1961 18 tháng 1, Guardian (trích dẫn sau OED):'),
    ('5c8be425-93ce-50e0-99c6-f3e25c39359f', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'marathon', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈmæɹəθən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/marathon-uk.mp3', 'A 42.195 kilometre (26 mile 385 yard) road race.', 'He had a cleaning marathon the night before his girlfriend came over.', 'Sports & Hobbies', 'cuộc đua marathon', 'Một cuộc đua đường trường dài 42,195 km (26 dặm 385 yard).', 'Anh ấy đã có một buổi dọn dẹp marathon vào đêm trước khi bạn gái đến chơi.'),
    ('4f7714c3-25e5-5929-a4a2-349a84cee8df', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'medal', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '[ˈmeɾ.ɫ̩]', 'audio/medal.mp3', 'A stamped metal disc used as a personal ornament, a charm, or a religious object.', 'He medalled twice at the Olympics.', 'Sports & Hobbies', 'huy chương', 'Một đĩa kim loại được đóng dấu dùng làm đồ trang sức cá nhân, bùa hộ mệnh hoặc vật thể tôn giáo.', 'Anh ấy giành được hai huy chương tại Thế vận hội.'),
    ('e688bb45-acef-5603-a376-78397e32d571', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'pursuit', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/pəˈsʉːt/', 'audio/pursuit.mp3', 'The act of pursuing.', 'Unremitting pursuit of wealth doesn''t bring happiness, particularly if successful.', 'Sports & Hobbies', 'theo đuổi', 'Hành động theo đuổi.', 'Việc theo đuổi của cải không ngừng không mang lại hạnh phúc, đặc biệt nếu thành công.'),
    ('03ee5825-fe58-5ee9-99e3-2ebcfac9f7af', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'puzzle', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˈpʌzəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/puzzle-ca.mp3', 'Anything that is difficult to understand or make sense of.', 'Where he went after he left the house is a puzzle.', 'Sports & Hobbies', 'câu đố', 'Bất cứ điều gì khó hiểu hoặc khó giải thích.', 'Anh ấy đã đi đâu sau khi rời khỏi nhà là một câu đố.'),
    ('f61db656-6d00-54f5-858c-a7b4193e48a5', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'referee', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/ˌɹɛf.əˈɹiː/', 'audio/referee.mp3', 'An umpire or judge; an official who makes sure the rules are followed during a game.', 'The referee kicked Jim out of the game for fighting.', 'Sports & Hobbies', 'trọng tài', 'Một trọng tài hoặc giám khảo; một quan chức đảm bảo các quy tắc được tuân thủ trong một trận đấu.', 'Trọng tài đuổi Jim ra khỏi trận đấu vì đánh nhau.'),
    ('0f5b9daa-0bd4-566f-88c6-80ec174bff32', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'rival', 'B2', '["n", "adj"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "adj", "level": "B2"}]'::jsonb, '/ˈɹaɪvəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/rival-us.mp3', 'A competitor (person, team, company, etc.) with the same goal as another, or striving to attain the same thing. Defeating a rival may be a primary or necessary goal of a competitor.', 'Chris is my biggest rival in the 400-metre race.', 'Sports & Hobbies', 'đối thủ', 'Một đối thủ cạnh tranh (người, đội, công ty, v.v.) có cùng mục tiêu với người khác, hoặc đang phấn đấu để đạt được điều tương tự. Đánh bại một đối thủ có thể là mục tiêu chính hoặc cần thiết của một đối thủ cạnh tranh.', 'Chris là đối thủ lớn nhất của tôi trong cuộc đua 400 mét.'),
    ('0e682a16-31e1-551b-9f3b-1d39f71d5675', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'spectator', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/spɛkˈteɪtə/', 'audio/spectator.mp3', 'One who watches an event; especially, one held outdoors.', 'The cheering spectators watched the fireworks.', 'Sports & Hobbies', 'khán giả', 'Người xem một sự kiện; đặc biệt, một sự kiện được tổ chức ngoài trời.', 'Những khán giả reo hò đã xem pháo hoa.'),
    ('51b4692d-712b-520e-8f84-8fe026c14591', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'stance', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/stæns/', 'audio/stance.mp3', 'The manner, pose, or posture in which one stands.', 'The fencer’s stance showed he was ready to begin.', 'Sports & Hobbies', 'tư thế đứng', 'Cách thức, dáng điệu, hoặc tư thế mà một người đứng.', 'Tư thế của võ sĩ kiếm cho thấy anh ta đã sẵn sàng bắt đầu.'),
    ('bfc7248b-75b3-51c5-a00b-8d7ec62a62f2', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'tackle', 'B2', '["v", "n"]'::jsonb, '[{"pos": "v", "level": "B2"}, {"pos": "n", "level": "C1"}]'::jsonb, '/ˈtækəl/', 'https://api.dictionaryapi.dev/media/pronunciations/en/tackle-us.mp3', 'A device for grasping an object and an attached means of moving it, as a rope and hook.', 'The government''s measures to tackle crime were insufficient.', 'Sports & Hobbies', 'tắc bóng, giải quyết', 'Một thiết bị để nắm bắt một vật thể và phương tiện gắn liền để di chuyển nó, như dây thừng và móc.', 'Các biện pháp của chính phủ để giải quyết tội phạm là không đủ.'),
    ('e9c38214-9f26-59e2-b971-58abbc56cfcf', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'capacity', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/kəˈpæsɪti/', 'https://api.dictionaryapi.dev/media/pronunciations/en/capacity-us.mp3', 'The ability to hold, receive or absorb', 'It was hauling a capacity load.', 'Numbers & Measurement', 'sức chứa, dung tích', 'Khả năng chứa, tiếp nhận hoặc hấp thụ', 'Nó đang chở một tải trọng tối đa.'),
    ('b15ea26e-7438-509d-9707-069d4b9f320f', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'depth', 'B2', '["n"]'::jsonb, '[{"pos": "n", "level": "B2"}]'::jsonb, '/dɛpθ/', 'https://api.dictionaryapi.dev/media/pronunciations/en/depth-us.mp3', 'The vertical distance below a surface; the degree to which something is deep', 'Measure the depth of the water in this part of the bay.', 'Numbers & Measurement', 'độ sâu', 'Khoảng cách thẳng đứng bên dưới một bề mặt; mức độ sâu của một cái gì đó', 'Đo độ sâu của nước ở phần này của vịnh.'),
    ('6f9c46f8-3db9-52fc-bb11-95172146a59b', 'd14dfe13-dc41-540b-936e-a43aeafb4591', 'dozen', 'B2', '["n", "det"]'::jsonb, '[{"pos": "n", "level": "B2"}, {"pos": "det", "level": "B2"}]'::jsonb, '/ˈdʌzən/', 'https://api.dictionaryapi.dev/media/pronunciations/en/dozen-us.mp3', 'A set of twelve.', 'Can I have a dozen eggs, please?', 'Numbers & Measurement', 'tá', 'Một bộ mười hai.', 'Cho tôi một tá trứng, được không?'),
